// Redefinir window.alert globalmente con SweetAlert2 para estética premium y generar mayor confianza
const nativeAlert = window.alert;
window.alert = function(message) {
  if (window.Swal) {
    let icon = 'info';
    let title = 'Notificación';
    const lowerMessage = String(message).toLowerCase();

    if (
      lowerMessage.includes('exitosamente') || 
      lowerMessage.includes('éxito') || 
      lowerMessage.includes('correctamente') || 
      lowerMessage.includes('sincronizado') || 
      lowerMessage.includes('guardada') || 
      lowerMessage.includes('conexión establecida') || 
      lowerMessage.includes('conectada') ||
      lowerMessage.includes('exitoso')
    ) {
      icon = 'success';
      title = '¡Éxito!';
    } else if (
      lowerMessage.includes('error') || 
      lowerMessage.includes('falla') || 
      lowerMessage.includes('denegado') || 
      lowerMessage.includes('no se pudo') || 
      lowerMessage.includes('inválido') || 
      lowerMessage.includes('incorrecto') || 
      lowerMessage.includes('inactiva') || 
      lowerMessage.includes('falló') || 
      lowerMessage.includes('no autorizado') || 
      lowerMessage.includes('unauthorized') ||
      lowerMessage.includes('error al')
    ) {
      icon = 'error';
      title = 'Error';
    } else if (
      lowerMessage.includes('seguro') || 
      lowerMessage.includes('desea') || 
      lowerMessage.includes('advertencia') || 
      lowerMessage.includes('atención') || 
      lowerMessage.includes('cuidado')
    ) {
      icon = 'warning';
      title = 'Atención';
    }

    window.Swal.fire({
      title: title,
      text: message,
      icon: icon,
      confirmButtonText: 'Aceptar',
      customClass: {
        popup: 'swal2-popup',
        title: 'swal2-title',
        confirmButton: 'swal2-confirm swal2-styled'
      },
      buttonsStyling: true
    });
  } else {
    nativeAlert(message);
  }
};

window.roundUpVolume = function(val) {
  if (val === null || val === undefined || isNaN(val) || val === '') return null;
  return Math.ceil(Math.round(val * 10000000) / 100) / 100000;
};

// Variable global para almacenar el valor de la UF del día con soporte de caché y respaldo offline
const cachedBackupUf = localStorage.getItem('stocka-last-uf-backup');
window.currentUfValue = cachedBackupUf ? parseFloat(cachedBackupUf) : 38200; // Fallback predeterminado actualizado a 2026

const todayStr = new Date().toISOString().slice(0, 10);
const cachedTodayUf = JSON.parse(localStorage.getItem('stocka-uf') || 'null');

if (cachedTodayUf && cachedTodayUf.date === todayStr && cachedTodayUf.numericValue) {
  window.currentUfValue = cachedTodayUf.numericValue;
  console.log('Valor UF de hoy cargado desde caché local:', window.currentUfValue);
} else {
  fetch('https://mindicador.cl/api/uf')
    .then(res => res.json())
    .then(data => {
      if (data && data.serie && data.serie[0]) {
        const val = parseFloat(data.serie[0].valor);
        window.currentUfValue = val;
        console.log('Valor UF de hoy cargado desde API:', window.currentUfValue);
        
        // Guardar para hoy
        const formatted = val.toLocaleString('es-CL', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
        localStorage.setItem('stocka-uf', JSON.stringify({ 
          date: todayStr, 
          value: `$${formatted}`,
          numericValue: val 
        }));
        
        // Guardar como respaldo de última UF conocida
        localStorage.setItem('stocka-last-uf-backup', val.toString());
      }
    })
    .catch(err => {
      console.error('Error cargando valor UF desde API, usando respaldo:', err);
    });
}

// Función global para descargar archivos en PDF codificados en Base64
window.downloadBase64Pdf = function(base64, filename) {
  try {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    const blob = new Blob([bytes], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  } catch (err) {
    console.error('Error al descargar el PDF en Base64:', err);
    alert('No se pudo descargar la etiqueta de despacho: el archivo está dañado o no está disponible.');
  }
};

// Global function to toggle table action menus
window.toggleTableActionMenu = function(event, btn) {
  event.stopPropagation();
  // Close any other open menus first
  document.querySelectorAll('.table-action-menu-content.show').forEach(menu => {
    if (menu !== btn.nextElementSibling) {
      menu.classList.remove('show');
    }
  });
  // Toggle the clicked menu
  btn.nextElementSibling.classList.toggle('show');
};

// Close all table action menus when clicking anywhere else
document.addEventListener('click', function() {
  document.querySelectorAll('.table-action-menu-content.show').forEach(menu => {
    menu.classList.remove('show');
  });
});

// Formateador de moneda en pesos chilenos (CLP)
window.formatCLP = function(value) {
  if (value === null || value === undefined || isNaN(value) || value === '') {
    return '-';
  }
  return new Intl.NumberFormat('es-CL', { style: 'currency', currency: 'CLP' }).format(value);
};

window.shouldProcessOrderStockLocal = function(order, config, allOrdersList) {
  // Si no hay configuración para este comercio, por defecto no hacemos seguimiento
  if (!config) return false;

  // A. Check if tracking is active
  if (!config.inventario_seguimiento) return false;

  // B. Check if order state is terminal (despachado, retirado, entregado, cancelado)
  const orderStatus = (order.status || '').toLowerCase().trim();
  const orderWmsStatus = (order.estado_wms || '').toLowerCase().trim();
  const terminalStatuses = ['despachado', 'retirado', 'entregado', 'cancelado'];
  if (terminalStatuses.includes(orderStatus) || terminalStatuses.includes(orderWmsStatus)) {
    return false;
  }

  // C. Check start conditions
  const startConfig = config.inventario_inicio_pedidos;
  if (!startConfig || typeof startConfig !== 'object') {
    return true;
  }

  const platform = order.external_platform || order.origen || 'Manual';
  const platformStart = startConfig[platform];
  if (!platformStart) {
    return true;
  }

  const startOrderNum = String(platformStart.external_order_number || '').trim();
  if (!startOrderNum) {
    return true;
  }

  const include = platformStart.incluir !== false;

  // Try to find the start order in the loaded orders list to get its created_at
  const startOrder = (allOrdersList || []).find(o => 
    o.comercio === order.comercio && 
    (o.external_platform || o.origen || 'Manual') === platform && 
    String(o.external_order_number || '').trim() === startOrderNum
  );

  if (startOrder && startOrder.created_at) {
    const orderTime = new Date(order.created_at).getTime();
    const startTime = new Date(startOrder.created_at).getTime();
    if (include) {
      return orderTime >= startTime;
    } else {
      if (order.id === startOrder.id || String(order.external_order_number || '').trim() === startOrderNum) {
        return false;
      }
      return orderTime > startTime;
    }
  }

  // Numeric fallback if start order is not in memory
  const startVal = parseInt(startOrderNum.replace(/[^0-9]/g, ''), 10);
  const orderVal = parseInt(String(order.external_order_number || '').replace(/[^0-9]/g, ''), 10);

  if (isNaN(startVal) || isNaN(orderVal)) {
    // Lexicographical fallback
    const startStr = startOrderNum;
    const orderStr = String(order.external_order_number || '');
    if (include) {
      return orderStr >= startStr;
    } else {
      if (orderStr === startStr) return false;
      return orderStr > startStr;
    }
  } else {
    if (include) {
      return orderVal >= startVal;
    } else {
      if (orderVal === startVal) return false;
      return orderVal > startVal;
    }
  }
};

