async function cleanOldReceiptsJS() {
  try {
    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
    
    const { data: oldReports, error } = await supabase
      .from('payment_reports')
      .select('id, comprobante_url')
      .neq('status', 'pendiente')
      .not('comprobante_url', 'is', null)
      .lt('created_at', sevenDaysAgo.toISOString());
      
    if (error) throw error;
    
    if (oldReports && oldReports.length > 0) {
      console.log(`Eliminando ${oldReports.length} comprobantes antiguos...`);
      
      const filePaths = oldReports.map(rep => {
        const parts = rep.comprobante_url.split('/payment_receipts/');
        return parts.length > 1 ? parts[1] : null;
      }).filter(Boolean);
      
      if (filePaths.length > 0) {
        await supabase.storage
          .from('payment_receipts')
          .remove(filePaths);
      }
      
      const ids = oldReports.map(rep => rep.id);
      await supabase
        .from('payment_reports')
        .update({ comprobante_url: null })
        .in('id', ids);
    }
  } catch (err) {
    console.error('Error in cleanOldReceiptsJS:', err);
  }
}

async function checkBillingSuspension(companyStr) {
  if (!companyStr) return;
  try {
    const list = companyStr.split(',').map(c => c.trim()).filter(Boolean);
    if (list.length === 0) return;
    
    const { data: mappings } = await supabase
      .from('billing_mappings')
      .select('comercio_nombre, billing_name');
    
    const billingComercios = new Set();
    list.forEach(c => {
      const match = mappings?.find(m => m.comercio_nombre.toLowerCase() === c.toLowerCase());
      billingComercios.add(match ? match.billing_name : c);
    });
    
    const resolvedList = Array.from(billingComercios);
    
    const { data: statuses, error } = await supabase
      .from('commerce_billing_status')
      .select('comercio, al_dia')
      .in('comercio', resolvedList);
      
    if (error) throw error;
    
    const pausedComercios = statuses?.filter(s => !s.al_dia).map(s => s.comercio) || [];
    if (pausedComercios.length > 0) {
      showSuspensionBanner(pausedComercios);
    }
  } catch (err) {
    console.error('Error checking billing suspension:', err);
  }
}

window.checkBillingSuspension = checkBillingSuspension;

function showSuspensionBanner(pausedComercios) {
  if (document.getElementById('billing-suspension-banner')) return;
  const mainContent = document.querySelector('.main-content');
  if (!mainContent) return;
  
  const banner = document.createElement('div');
  banner.id = 'billing-suspension-banner';
  banner.style.cssText = `
    background-color: #ef4444; 
    color: white; 
    padding: 0.75rem 1.5rem; 
    text-align: center; 
    font-weight: 500; 
    font-size: 0.9rem;
    display: flex; 
    align-items: center; 
    justify-content: center; 
    gap: 0.5rem;
    border-bottom: 2px solid #b91c1c;
  `;
  banner.innerHTML = `
    <i class="ri-error-warning-fill" style="font-size: 1.25rem;"></i>
    <span><strong>Servicio Pausado:</strong> El comercio <strong>${pausedComercios.join(', ')}</strong> se encuentra con servicio pausado. Por favor regularizar a la brevedad con nuestra área de finanzas a <a href="mailto:finanzas@stocka.cl" style="color: white; text-decoration: underline; font-weight: 700;">finanzas@stocka.cl</a>.</span>
  `;
  mainContent.insertBefore(banner, mainContent.firstChild);
}

window.showSuspensionBanner = showSuspensionBanner;

async function renderInboxPage() {
  const appContent = document.getElementById('app-content');
  if (!appContent) return;
  
  appContent.innerHTML = `
    <div style="max-width: 900px; margin: 0 auto;">
      <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 1.5rem;">
        <h2 style="font-size: 1.5rem; color: var(--color-text-main); font-weight: 600;">Mi Inbox de Notificaciones</h2>
        <button id="inbox-mark-all-read-btn" class="btn btn-outline" style="border-color: var(--color-primary); color: var(--color-primary); display: none;">
          <i class="ri-check-double-line" style="margin-right: 0.25rem;"></i> Marcar todas leídas
        </button>
      </div>
      <div class="card">
        <div class="card-body" style="padding: 0;">
          <div id="inbox-list" style="min-height: 200px; position: relative;">
            <div style="padding: 3rem; text-align: center; color: var(--color-text-muted);">
              <i class="ri-loader-4-line spin" style="font-size: 2rem;"></i><br>Cargando...
            </div>
          </div>
        </div>
      </div>
    </div>
  `;

  await loadInboxData();
}

async function loadInboxData() {
  const list = document.getElementById('inbox-list');
  const markAllBtn = document.getElementById('inbox-mark-all-read-btn');
  if (!list) return;

  try {
    if (!currentMerchantId) return;
    
    // Fetch user's read records
    const { data: readRecords } = await supabase
      .from('user_notification_reads')
      .select('entity_id')
      .eq('user_id', currentMerchantId)
      .eq('entity_type', 'notification');
      
    const readIds = readRecords ? readRecords.map(r => r.entity_id) : [];

    const rolesToMatch = ['all', userRole];
    // Traer un historial más largo (100)
    const { data, error } = await supabase
      .from('dashboard_notifications')
      .select('*')
      .order('created_at', { ascending: false })
      .limit(100);
      
    if (error) throw error;

    const filteredData = data ? data.filter(n => {
      return (rolesToMatch.includes(n.target_role) && !n.user_id) || n.user_id === currentMerchantId;
    }) : [];

    if (!filteredData || filteredData.length === 0) {
      list.innerHTML = `
        <div style="padding: 4rem 2rem; text-align: center; color: var(--color-text-muted);">
          <div style="background: var(--color-surface-hover); width: 64px; height: 64px; border-radius: 50%; display: flex; align-items: center; justify-content: center; margin: 0 auto 1rem;">
            <i class="ri-inbox-archive-line" style="font-size: 2rem; color: var(--color-border);"></i>
          </div>
          <h3 style="font-size: 1.1rem; color: var(--color-text-main); margin-bottom: 0.25rem;">Bandeja vacía</h3>
          <p style="font-size: 0.9rem;">No tienes notificaciones en tu historial.</p>
        </div>`;
      if (markAllBtn) markAllBtn.style.display = 'none';
      return;
    }

    const unreadCount = filteredData.filter(n => !readIds.includes(n.id)).length;
    if (markAllBtn) {
      markAllBtn.style.display = unreadCount > 0 ? 'inline-flex' : 'none';
      
      // Remove old listener by replacing button
      const newBtn = markAllBtn.cloneNode(true);
      markAllBtn.parentNode.replaceChild(newBtn, markAllBtn);
      
      newBtn.addEventListener('click', async () => {
        try {
          const unreadItems = filteredData.filter(n => !readIds.includes(n.id));
          const inserts = unreadItems.map(item => ({
            user_id: currentMerchantId,
            entity_type: 'notification',
            entity_id: item.id
          }));
          
          if (inserts.length > 0) {
            newBtn.innerHTML = '<i class="ri-loader-4-line spin"></i> Marcando...';
            await supabase.from('user_notification_reads').insert(inserts);
            await loadInboxData();
          }
        } catch(err) {
          console.error(err);
        }
      });
    }

    list.innerHTML = filteredData.map(n => {
      const isReadLocally = readIds.includes(n.id);
      return `
      <div class="inbox-item ${isReadLocally ? 'read' : 'unread'}" style="padding: 1.25rem 1.5rem; border-bottom: 1px solid var(--color-border); display: flex; gap: 1rem; align-items: flex-start; transition: background-color 0.2s; background: ${isReadLocally ? 'transparent' : 'rgba(59, 130, 246, 0.05)'};">
        <div style="flex-shrink: 0; width: 40px; height: 40px; border-radius: 50%; background: ${isReadLocally ? 'var(--color-surface-hover)' : 'rgba(59, 130, 246, 0.15)'}; color: ${isReadLocally ? 'var(--color-text-muted)' : 'var(--color-primary)'}; display: flex; align-items: center; justify-content: center;">
          <i class="${isReadLocally ? 'ri-notification-badge-line' : 'ri-notification-3-fill'}" style="font-size: 1.25rem;"></i>
        </div>
        <div style="flex: 1;">
          <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 0.25rem;">
            <h4 style="margin: 0; font-size: 1rem; color: var(--color-text-main); font-weight: ${isReadLocally ? '500' : '600'};">${n.title}</h4>
            <span style="font-size: 0.75rem; color: var(--color-text-muted); white-space: nowrap; margin-left: 1rem;">${new Date(n.created_at).toLocaleString()}</span>
          </div>
          <p style="margin: 0; font-size: 0.9rem; color: ${isReadLocally ? 'var(--color-text-muted)' : 'var(--color-text-main)'}; line-height: 1.5;">${n.message}</p>
        </div>
        ${!isReadLocally ? `
          <button class="btn btn-outline mark-inbox-read-btn" data-id="${n.id}" title="Marcar como leída" style="padding: 0.25rem 0.5rem; font-size: 1.1rem; border: none; color: var(--color-primary); background: transparent;">
            <i class="ri-check-line"></i>
          </button>
        ` : `
          <div style="padding: 0.25rem 0.5rem; color: var(--color-text-muted); font-size: 1.1rem;"><i class="ri-check-double-line"></i></div>
        `}
      </div>
    `}).join('');

    document.querySelectorAll('.mark-inbox-read-btn').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        const id = btn.getAttribute('data-id');
        btn.innerHTML = '<i class="ri-loader-4-line spin"></i>';
        await supabase.from('user_notification_reads').insert([{ user_id: currentMerchantId, entity_type: 'notification', entity_id: id }]);
        await loadInboxData();
      });
    });

  } catch (err) {
    console.error('Error fetching inbox:', err);
    list.innerHTML = `<div style="padding: 2rem; color: var(--color-danger); text-align: center;">Error al cargar: ${err.message}</div>`;
  }
}

// Ocultar cabeceras de categorías vacías en el menú
function updateCategoryHeadersVisibility() {
  const listItems = Array.from(document.querySelectorAll('.sidebar-nav > ul > li'));
  let currentHeader = null;
  let hasVisibleItems = false;
  
  listItems.forEach(li => {
    if (li.classList.contains('sidebar-category-header')) {
      if (currentHeader && !hasVisibleItems) {
        currentHeader.style.display = 'none';
      }
      currentHeader = li;
      hasVisibleItems = false;
    } else {
      if (li.style.display !== 'none') {
        hasVisibleItems = true;
      }
    }
  });
  
  if (currentHeader && !hasVisibleItems) {
    currentHeader.style.display = 'none';
  }
}

// ==========================================
// Módulo de Documentación de Servicio (Cliente)
// ==========================================

function injectDocsStyles() {
  if (document.getElementById('docs-client-styles')) return;
  const style = document.createElement('style');
  style.id = 'docs-client-styles';
  style.innerHTML = `
    .docs-container {
      display: flex;
      flex-direction: column;
      gap: 1.5rem;
    }
    .docs-grid {
      display: grid;
      grid-template-columns: 240px 1fr;
      gap: 1.5rem;
    }
    @media (max-width: 768px) {
      .docs-grid {
        grid-template-columns: 1fr;
      }
    }
    .folder-sidebar {
      background: var(--color-surface);
      border: 1px solid var(--color-border);
      border-radius: var(--radius-lg);
      padding: 1rem;
      align-self: start;
    }
    .folder-list {
      list-style: none;
      padding: 0;
      margin: 0;
      display: flex;
      flex-direction: column;
      gap: 0.25rem;
    }
    .folder-item {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0.6rem 0.75rem;
      border-radius: var(--radius-md);
      cursor: pointer;
      color: var(--color-text-muted);
      font-size: 0.9rem;
      font-weight: 500;
      transition: all 0.2s;
    }
    .folder-item:hover {
      background: var(--color-bg);
      color: var(--color-text-main);
    }
    .folder-item.active {
      background: rgba(59, 130, 246, 0.1);
      color: var(--color-primary);
    }
    .folder-icon {
      font-size: 1.1rem;
      margin-right: 0.5rem;
    }
    .docs-main-content {
      display: flex;
      flex-direction: column;
      gap: 1.5rem;
    }
    .pinned-section {
      background: linear-gradient(135deg, rgba(59, 130, 246, 0.05) 0%, rgba(147, 51, 234, 0.05) 100%);
      border: 1px dashed var(--color-primary);
      border-radius: var(--radius-lg);
      padding: 1.25rem;
    }
    .pinned-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
      gap: 1rem;
      margin-top: 0.75rem;
    }
    .doc-card-pinned {
      background: var(--color-surface);
      border: 1px solid var(--color-border);
      border-radius: var(--radius-md);
      padding: 1rem;
      position: relative;
      overflow: hidden;
      box-shadow: var(--shadow-sm);
      transition: transform 0.2s, box-shadow 0.2s;
    }
    .doc-card-pinned:hover {
      transform: translateY(-2px);
      box-shadow: var(--shadow-md);
      border-color: var(--color-primary);
    }
    .doc-card-pinned::before {
      content: '';
      position: absolute;
      top: 0;
      left: 0;
      width: 4px;
      height: 100%;
      background: linear-gradient(to bottom, #f59e0b, #d97706);
    }
    .doc-file-icon {
      font-size: 2.25rem;
      color: var(--color-primary);
    }
    .doc-star-badge {
      position: absolute;
      top: 0.75rem;
      right: 0.75rem;
      color: #f59e0b;
      font-size: 1.1rem;
    }
    .files-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
      gap: 1rem;
    }
    .doc-card-standard {
      background: var(--color-surface);
      border: 1px solid var(--color-border);
      border-radius: var(--radius-md);
      padding: 1.25rem;
      display: flex;
      flex-direction: column;
      justify-content: space-between;
      gap: 1rem;
      box-shadow: var(--shadow-sm);
      transition: border-color 0.2s, box-shadow 0.2s;
    }
    .doc-card-standard:hover {
      border-color: var(--color-primary);
      box-shadow: var(--shadow-md);
    }
    .doc-info {
      display: flex;
      gap: 0.75rem;
      align-items: flex-start;
    }
    .doc-badge-folder {
      background: rgba(59, 130, 246, 0.08);
      color: var(--color-primary);
      padding: 0.15rem 0.4rem;
      border-radius: var(--radius-sm);
      font-size: 0.7rem;
      font-weight: 600;
      text-transform: uppercase;
      align-self: flex-start;
    }
  `;
  document.head.appendChild(style);
}

// Variables globales cliente
let clientDocsList = [];
let clientSelectedFolder = 'all';
let clientSearchQuery = '';

window.renderDocsClient = async function() {
  const appContent = document.getElementById('app-content');
  if (!appContent) return;

  injectDocsStyles();

  // Inyectar banner de observador si procede
  const observerBanner = typeof getObserverBanner === 'function' ? getObserverBanner() : '';

  appContent.innerHTML = observerBanner + `
    <div class="docs-container">
      <div class="card" style="padding: 1.25rem;">
        <div style="display: flex; gap: 0.75rem; align-items: center; flex-wrap: wrap;">
          <div style="position: relative; flex: 1; min-width: 250px;">
            <i class="ri-search-line" style="position: absolute; left: 0.75rem; top: 50%; transform: translateY(-50%); color: var(--color-text-muted);"></i>
            <input type="text" id="client-doc-search" class="form-input" style="padding-left: 2.25rem;" placeholder="Buscar documentos por nombre o descripción..." value="${clientSearchQuery}">
          </div>
        </div>
      </div>

      <div class="docs-grid">
        <aside class="folder-sidebar">
          <h4 style="font-size: 0.85rem; text-transform: uppercase; color: var(--color-text-muted); margin-bottom: 0.75rem; letter-spacing: 0.05em;">Carpetas</h4>
          <ul id="client-folder-list" class="folder-list">
            <li class="folder-item active" data-folder="all">
              <span><i class="ri-folder-open-line folder-icon"></i> Todas</span>
              <span id="client-folder-count-all" class="badge" style="font-size: 0.75rem; padding: 0.1rem 0.4rem;">0</span>
            </li>
          </ul>
        </aside>

        <div class="docs-main-content">
          <!-- Sección de Destacados -->
          <div id="client-pinned-section" class="pinned-section" style="display: none;">
            <h4 style="margin: 0; color: #b45309; display: flex; align-items: center; gap: 0.4rem; font-size: 0.9rem; text-transform: uppercase; letter-spacing: 0.05em;">
              <i class="ri-star-fill" style="color: #f59e0b;"></i> Documentos Destacados
            </h4>
            <div id="client-pinned-grid" class="pinned-grid"></div>
          </div>

          <!-- Listado de Archivos -->
          <div class="card" style="padding: 1.5rem;">
            <h3 style="margin-top: 0; margin-bottom: 1.25rem; font-size: 1.1rem; display: flex; justify-content: space-between;" id="client-current-folder-title">
              <span>Todos los Archivos</span>
              <span id="client-files-count" style="font-size: 0.85rem; color: var(--color-text-muted); font-weight: normal;">0 archivos</span>
            </h3>
            <div id="client-files-grid" class="files-grid">
              <div style="grid-column: 1 / -1; text-align: center; padding: 2rem; color: var(--color-text-muted);">
                <i class="ri-loader-4-line spin" style="font-size: 1.5rem; display: block; margin-bottom: 0.5rem;"></i>
                Cargando archivos...
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  `;

  // Search filter trigger
  const searchInput = document.getElementById('client-doc-search');
  searchInput.addEventListener('input', (e) => {
    clientSearchQuery = e.target.value.trim().toLowerCase();
    filterAndRenderDocsClient();
  });

  await loadDocsClientData();
};

async function loadDocsClientData() {
  try {
    const { data, error } = await supabase
      .from('service_docs')
      .select('*')
      .order('is_pinned', { ascending: false })
      .order('updated_at', { ascending: false });

    if (error) throw error;

    clientDocsList = data || [];
    renderClientFoldersSidebar();
    filterAndRenderDocsClient();
  } catch (err) {
    console.error('Error loading client documents:', err);
    const grid = document.getElementById('client-files-grid');
    if (grid) {
      grid.innerHTML = `
        <div style="grid-column: 1 / -1; text-align: center; padding: 2rem; color: var(--color-danger);">
          <i class="ri-error-warning-line" style="font-size: 1.5rem; display: block; margin-bottom: 0.5rem;"></i>
          Error al cargar los documentos de servicio: ${err.message}
        </div>
      `;
    }
  }
}

function renderClientFoldersSidebar() {
  const sidebar = document.getElementById('client-folder-list');
  if (!sidebar) return;

  const folders = {};
  clientDocsList.forEach(doc => {
    const f = doc.folder || 'General';
    folders[f] = (folders[f] || 0) + 1;
  });

  let html = `
    <li class="folder-item ${clientSelectedFolder === 'all' ? 'active' : ''}" data-folder="all">
      <span><i class="ri-folder-open-line folder-icon"></i> Todas</span>
      <span class="badge" style="font-size: 0.75rem; padding: 0.1rem 0.4rem; background: var(--color-border); color: var(--color-text-main); font-weight: 600;">${clientDocsList.length}</span>
    </li>
  `;

  Object.keys(folders).sort().forEach(folder => {
    html += `
      <li class="folder-item ${clientSelectedFolder === folder ? 'active' : ''}" data-folder="${folder}">
        <span><i class="ri-folder-line folder-icon"></i> ${folder}</span>
        <span class="badge" style="font-size: 0.75rem; padding: 0.1rem 0.4rem; background: var(--color-border); color: var(--color-text-main); font-weight: 600;">${folders[folder]}</span>
      </li>
    `;
  });

  sidebar.innerHTML = html;

  sidebar.querySelectorAll('.folder-item').forEach(item => {
    item.addEventListener('click', () => {
      sidebar.querySelectorAll('.folder-item').forEach(li => li.classList.remove('active'));
      item.classList.add('active');
      clientSelectedFolder = item.getAttribute('data-folder');
      filterAndRenderDocsClient();
    });
  });
}

function getFileIconClass(filename) {
  if (!filename) return 'ri-file-text-line';
  const cleanFilename = filename.split('?')[0];
  const ext = cleanFilename.split('.').pop().toLowerCase();
  switch (ext) {
    case 'pdf': return 'ri-file-pdf-line';
    case 'xls':
    case 'xlsx':
    case 'csv': return 'ri-file-excel-line';
    case 'doc':
    case 'docx': return 'ri-file-word-line';
    case 'png':
    case 'jpg':
    case 'jpeg':
    case 'gif':
    case 'svg':
    case 'webp': return 'ri-file-image-line';
    case 'zip':
    case 'rar':
    case '7z': return 'ri-file-zip-line';
    default: return 'ri-file-text-line';
  }
}

function filterAndRenderDocsClient() {
  const grid = document.getElementById('client-files-grid');
  const pinnedSection = document.getElementById('client-pinned-section');
  const pinnedGrid = document.getElementById('client-pinned-grid');
  const folderTitle = document.getElementById('client-current-folder-title');
  const countSpan = document.getElementById('client-files-count');
  
  if (!grid) return;

  // Filtrar lista
  let filtered = clientDocsList;

  if (clientSelectedFolder !== 'all') {
    filtered = filtered.filter(doc => doc.folder === clientSelectedFolder);
    if (folderTitle) folderTitle.innerHTML = `<span>Carpeta: ${clientSelectedFolder}</span>`;
  } else {
    if (folderTitle) folderTitle.innerHTML = `<span>Todos los Archivos</span>`;
  }

  if (clientSearchQuery) {
    filtered = filtered.filter(doc => 
      doc.name.toLowerCase().includes(clientSearchQuery) || 
      (doc.description && doc.description.toLowerCase().includes(clientSearchQuery))
    );
  }

  if (countSpan) countSpan.textContent = `${filtered.length} archivos`;

  // Renderizar destacados (solo si no hay filtro de búsqueda activo, o si los destacados coinciden con la búsqueda)
  const pinnedFiles = filtered.filter(doc => doc.is_pinned);
  if (pinnedFiles.length > 0) {
    if (pinnedSection) pinnedSection.style.display = 'block';
    if (pinnedGrid) {
      pinnedGrid.innerHTML = pinnedFiles.map(doc => {
        const iconClass = getFileIconClass(doc.file_url);
        const formattedDate = new Date(doc.updated_at).toLocaleDateString('es-CL', {
          day: '2-digit',
          month: 'short',
          year: 'numeric'
        });

        return `
          <div class="doc-card-pinned">
            <div class="doc-star-badge"><i class="ri-star-fill"></i></div>
            <div class="doc-info" style="margin-bottom: 0.5rem;">
              <i class="${iconClass} doc-file-icon" style="color: #d97706;"></i>
              <div style="flex: 1; padding-right: 1.25rem;">
                <h4 style="margin: 0; font-size: 0.95rem; font-weight: 700; color: var(--color-text-main); line-height: 1.3;">${doc.name}</h4>
                <span class="doc-badge-folder" style="margin-top: 0.25rem; display: inline-block;">${doc.folder || 'General'}</span>
              </div>
            </div>
            <p style="font-size: 0.8rem; color: var(--color-text-muted); margin: 0 0 1rem 0; min-height: 2.4rem; line-height: 1.4;">${doc.description || 'Sin descripción'}</p>
            <div style="display: flex; align-items: center; justify-content: space-between; border-top: 1px solid var(--color-border); padding-top: 0.75rem; margin-top: auto;">
              <span style="font-size: 0.75rem; color: var(--color-text-muted);">Act: ${formattedDate}</span>
              <div style="display: flex; gap: 0.25rem;">
                <button class="btn btn-outline btn-client-preview-doc" data-name="${doc.name}" data-url="${doc.file_url}" style="padding: 0.35rem 0.6rem; font-size: 0.8rem; height: auto;">
                  <i class="ri-eye-line"></i> Ver
                </button>
                <a href="${doc.file_url}" target="_blank" class="btn btn-primary" style="padding: 0.35rem 0.6rem; font-size: 0.8rem; height: auto;" title="Descargar">
                  <i class="ri-download-2-line"></i>
                </a>
              </div>
            </div>
          </div>
        `;
      }).join('');
    }
  } else {
    if (pinnedSection) pinnedSection.style.display = 'none';
  }

  // Renderizar estándar
  if (filtered.length === 0) {
    grid.innerHTML = `
      <div style="grid-column: 1 / -1; text-align: center; padding: 3rem; color: var(--color-text-muted);">
        <i class="ri-file-search-line" style="font-size: 2.5rem; display: block; margin-bottom: 0.5rem; opacity: 0.5;"></i>
        No se encontraron archivos en esta carpeta.
      </div>
    `;
    return;
  }

  grid.innerHTML = filtered.map(doc => {
    const iconClass = getFileIconClass(doc.file_url);
    const formattedDate = new Date(doc.updated_at).toLocaleDateString('es-CL', {
      day: '2-digit',
      month: 'short',
      year: 'numeric'
    });

    const isPinnedHeaderBadge = doc.is_pinned ? `<i class="ri-star-fill" style="color: #f59e0b;" title="Destacado"></i> ` : '';

    return `
      <div class="doc-card-standard">
        <div>
          <div class="doc-info" style="margin-bottom: 0.5rem;">
            <i class="${iconClass}" style="font-size: 2rem; color: var(--color-primary);"></i>
            <div style="flex: 1;">
              <h4 style="margin: 0; font-size: 0.9rem; font-weight: 600; color: var(--color-text-main); line-height: 1.3;">
                ${isPinnedHeaderBadge}${doc.name}
              </h4>
              <div style="display: flex; gap: 0.35rem; align-items: center; margin-top: 0.25rem;">
                <span class="doc-badge-folder">${doc.folder || 'General'}</span>
              </div>
            </div>
          </div>
          <p style="font-size: 0.8rem; color: var(--color-text-muted); margin: 0.5rem 0 0 0; line-height: 1.4;">${doc.description || 'Sin descripción'}</p>
        </div>
        <div style="display: flex; align-items: center; justify-content: space-between; border-top: 1px solid var(--color-border); padding-top: 0.75rem; margin-top: 0.5rem;">
          <span style="font-size: 0.75rem; color: var(--color-text-muted);">Actualizado: ${formattedDate}</span>
          <div style="display: flex; gap: 0.25rem;">
            <button class="btn btn-outline btn-client-preview-doc" data-name="${doc.name}" data-url="${doc.file_url}" style="padding: 0.35rem 0.6rem; font-size: 0.8rem; height: auto;">
              <i class="ri-eye-line"></i> Ver
            </button>
            <a href="${doc.file_url}" target="_blank" class="btn btn-outline" style="padding: 0.35rem 0.6rem; font-size: 0.8rem; height: auto;" title="Descargar archivo">
              <i class="ri-download-2-line"></i>
            </a>
          </div>
        </div>
      </div>
    `;
  }).join('');

  // Bind previews
  document.querySelectorAll('.btn-client-preview-doc').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.preventDefault();
      const name = btn.getAttribute('data-name');
      const url = btn.getAttribute('data-url');
      window.openDocPreviewModal(name, url);
    });
  });
}

window.openDocPreviewModal = function(name, url) {
  const modal = document.getElementById('modal-doc-preview');
  const title = document.getElementById('doc-preview-title');
  const body = document.getElementById('doc-preview-body');
  const info = document.getElementById('doc-preview-info');
  const downloadBtn = document.getElementById('doc-preview-download-btn');
  
  if (!modal || !body) return;
  
  title.textContent = name;
  body.innerHTML = '';
  
  const knownExtensions = ['pdf', 'png', 'jpg', 'jpeg', 'gif', 'svg', 'webp', 'txt', 'html', 'htm', 'xlsx', 'xls', 'csv', 'docx', 'doc', 'zip', 'rar', '7z'];
  let ext = '';
  let isExternalLink = false;
  
  try {
    const parsedUrl = new URL(url);
    const pathname = parsedUrl.pathname;
    const lastSegment = pathname.substring(pathname.lastIndexOf('/') + 1);
    if (lastSegment.includes('.')) {
      ext = lastSegment.split('.').pop().toLowerCase();
      if (!knownExtensions.includes(ext)) {
        isExternalLink = true;
      }
    } else {
      isExternalLink = true; // No hay extensión de archivo en el path, asumimos que es link
    }
  } catch (e) {
    // Si no es URL válida, intentar split simple
    const cleanUrl = url.split('?')[0];
    ext = cleanUrl.split('.').pop().toLowerCase();
    if (!knownExtensions.includes(ext)) {
      isExternalLink = true;
    }
  }
  
  let html = '';
  let infoText = 'Vista previa del archivo';
  
  if (isExternalLink) {
    html = `
      <div style="padding:3rem; text-align:center; color:var(--color-text-muted); display:flex; flex-direction:column; align-items:center; justify-content:center; height:100%; box-sizing:border-box;">
        <div style="width:70px; height:70px; border-radius:50%; background:rgba(59, 130, 246, 0.1); color:var(--color-primary); display:flex; align-items:center; justify-content:center; margin-bottom:1.5rem;">
          <i class="ri-external-link-line" style="font-size:2.5rem;"></i>
        </div>
        <h3 style="color:var(--color-text-main); margin-bottom:0.75rem; font-size:1.4rem; font-weight:700;">Documento Online Externo</h3>
        <p style="font-size:0.9rem; max-width:480px; margin:0 auto 1.5rem auto; line-height:1.6; color:var(--color-text-muted);">
          Este documento está enlazado a un servicio externo (como Google Sheets, Notion, OneDrive o YouTube) y no se puede visualizar directamente dentro de esta ventana debido a restricciones de seguridad del sitio de origen.
        </p>
        <a href="${url}" target="_blank" class="btn btn-primary" style="display:inline-flex; align-items:center; gap:0.5rem; padding:0.6rem 1.25rem; font-size:0.95rem; font-weight:600; text-decoration:none;">
          <i class="ri-external-link-line"></i> Abrir en pestaña nueva
        </a>
        <div style="margin-top:2rem; padding:0.75rem 1rem; background:var(--color-bg); border:1px solid var(--color-border); border-radius:var(--radius-md); font-family:monospace; font-size:0.75rem; color:var(--color-text-muted); word-break:break-all; max-width:90%;">
          Enlace: ${url}
        </div>
      </div>
    `;
    infoText = 'Enlace externo';
    if (downloadBtn) {
      downloadBtn.innerHTML = '<i class="ri-external-link-line"></i> Abrir Enlace';
    }
  } else if (['pdf', 'txt', 'html', 'htm'].includes(ext)) {
    html = `<iframe src="${url}" style="width:100%; height:100%; border:none; background:white;"></iframe>`;
    if (downloadBtn) {
      downloadBtn.innerHTML = '<i class="ri-download-2-line"></i> Descargar Archivo';
    }
  } else if (['png', 'jpg', 'jpeg', 'gif', 'svg', 'webp'].includes(ext)) {
    html = `<div style="padding:1rem; width:100%; height:100%; overflow:auto; display:flex; align-items:center; justify-content:center;"><img src="${url}" style="max-width:100%; max-height:100%; object-fit:contain; border-radius:4px; box-shadow:var(--shadow-md);"></div>`;
    if (downloadBtn) {
      downloadBtn.innerHTML = '<i class="ri-download-2-line"></i> Descargar Archivo';
    }
  } else {
    html = `
      <div style="padding:2.5rem; text-align:center; color:var(--color-text-muted);">
        <i class="ri-file-warning-line" style="font-size:3rem; color:var(--color-primary); display:block; margin-bottom:1rem;"></i>
        <h4 style="color:var(--color-text-main); margin-bottom:0.5rem;">Vista previa no disponible</h4>
        <p style="font-size:0.875rem; max-width:400px; margin:0 auto 1.5rem auto;">Los archivos de tipo <strong>.${ext}</strong> no se pueden visualizar directamente en el navegador.</p>
        <a href="${url}" target="_blank" class="btn btn-primary" style="display:inline-flex; align-items:center; gap:0.5rem;">
          <i class="ri-download-2-line"></i> Descargar para Visualizar
        </a>
      </div>
    `;
    infoText = 'Descarga requerida para este tipo de archivo';
    if (downloadBtn) {
      downloadBtn.innerHTML = '<i class="ri-download-2-line"></i> Descargar Archivo';
    }
  }
  
  body.innerHTML = html;
  if (info) info.textContent = infoText;
  if (downloadBtn) {
    downloadBtn.href = url;
    downloadBtn.setAttribute('download', name);
  }
  
  modal.classList.add('active');
};

window.closeDocPreviewModal = function() {
  const modal = document.getElementById('modal-doc-preview');
  const body = document.getElementById('doc-preview-body');
  if (body) body.innerHTML = '';
  if (modal) modal.classList.remove('active');
};

// Global function to switch tabs in Integrations view
window.switchIntegrationTab = function(tabId) {
  const container = document.querySelector('.integrations-tabs-container');
  if (!container) return;
  
  const buttons = container.querySelectorAll('.integration-tab-btn');
  buttons.forEach(btn => {
    if (btn.getAttribute('data-tab') === tabId) {
      btn.classList.add('active');
      btn.style.borderBottomColor = 'var(--color-primary)';
      btn.style.color = 'var(--color-text-main)';
      btn.style.fontWeight = '600';
    } else {
      btn.classList.remove('active');
      btn.style.borderBottomColor = 'transparent';
      btn.style.color = 'var(--color-text-muted)';
      btn.style.fontWeight = '500';
    }
  });

  const panes = document.querySelectorAll('.integration-tab-pane');
  panes.forEach(pane => {
    if (pane.id === 'tab-' + tabId) {
      pane.style.display = 'block';
    } else {
      pane.style.display = 'none';
    }
  });
};

function initProductPackDomElements(isAdmin = false) {
  const checkbox = document.getElementById('prod-is-pack');
  const stockInput = document.getElementById('prod-stock');
  if (checkbox && stockInput && !checkbox.dataset.hasListener) {
    checkbox.dataset.hasListener = 'true';
    checkbox.addEventListener('change', () => {
      if (checkbox.checked) {
        stockInput.value = '0';
        stockInput.disabled = true;
        stockInput.style.backgroundColor = 'var(--color-gray-dark)';
        stockInput.style.color = 'var(--color-text-muted)';
      } else {
        stockInput.disabled = false;
        stockInput.style.backgroundColor = '';
        stockInput.style.color = '';
      }
    });
  }

  const editCheckbox = document.getElementById('edit-prod-is-pack');
  const packSection = document.getElementById('edit-prod-pack-section');
  if (editCheckbox && packSection && !editCheckbox.dataset.hasListener) {
    editCheckbox.dataset.hasListener = 'true';
    editCheckbox.addEventListener('change', () => {
      packSection.style.display = editCheckbox.checked ? 'block' : 'none';
    });
  }

  const btnAddComp = document.getElementById('btn-add-pack-component');
  if (btnAddComp && !btnAddComp.dataset.hasListener) {
    btnAddComp.dataset.hasListener = 'true';
    btnAddComp.addEventListener('click', () => {
      const hiddenSelect = document.getElementById('edit-pack-component-select');
      const selectedId = hiddenSelect ? hiddenSelect.value : '';
      if (!selectedId) return;

      const prod = (window._packSelectProducts || []).find(p => p.id === selectedId);
      if (!prod) return;
      const sku = prod.sku;
      const name = prod.name;
      const qtyInput = document.getElementById('edit-pack-component-qty');
      const qty = parseInt(qtyInput.value, 10) || 1;

      const existing = window.currentPackItems.find(item => item.id === selectedId);
      if (existing) {
        existing.quantity += qty;
      } else {
        window.currentPackItems.push({
          id: selectedId,
          sku,
          name,
          quantity: qty
        });
      }

      renderPackComponentsTable();
      qtyInput.value = '1';
      // Clear searchable select
      const searchInput = document.getElementById('edit-pack-component-search');
      if (searchInput) searchInput.value = '';
      if (hiddenSelect) hiddenSelect.value = '';
    });
  }
}

function initSearchableComponentSelect(products) {
  const searchInput = document.getElementById('edit-pack-component-search');
  const dropdown = document.getElementById('edit-pack-component-dropdown');
  const hiddenInput = document.getElementById('edit-pack-component-select');
  if (!searchInput || !dropdown || !hiddenInput) return;

  searchInput.value = '';
  hiddenInput.value = '';
  dropdown.innerHTML = '';
  dropdown.classList.remove('open');

  const renderOptions = (filter) => {
    const q = (filter || '').toLowerCase();
    const filtered = products.filter(p => {
      const text = `${p.name} ${p.sku}`.toLowerCase();
      return text.includes(q);
    }).slice(0, 50);

    if (filtered.length === 0) {
      dropdown.innerHTML = '<div style="padding: 0.75rem; text-align: center; color: var(--color-text-muted); font-size: 0.85rem;">Sin resultados</div>';
    } else {
      dropdown.innerHTML = filtered.map(p =>
        `<div class="searchable-select-option" data-id="${p.id}" data-sku="${p.sku}" data-name="${p.name}">
          ${p.name} <span class="sku-hint">(${p.sku})</span>
        </div>`
      ).join('');
    }
    dropdown.classList.add('open');

    dropdown.querySelectorAll('.searchable-select-option').forEach(opt => {
      opt.addEventListener('mousedown', (e) => {
        e.preventDefault();
        hiddenInput.value = opt.getAttribute('data-id');
        newSearch.value = `${opt.getAttribute('data-name')} (${opt.getAttribute('data-sku')})`;
        dropdown.classList.remove('open');
      });
    });
  };

  const newSearch = searchInput.cloneNode(true);
  searchInput.parentNode.replaceChild(newSearch, searchInput);

  newSearch.addEventListener('input', () => {
    renderOptions(newSearch.value);
    hiddenInput.value = '';
  });

  newSearch.addEventListener('focus', () => {
    renderOptions(newSearch.value);
  });

  newSearch.addEventListener('blur', () => {
    setTimeout(() => dropdown.classList.remove('open'), 150);
  });
}

function renderPackComponentsTable() {
  const tbody = document.getElementById('edit-pack-components-tbody');
  if (!tbody) return;

  const items = window.currentPackItems || [];
  if (items.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="4" style="text-align: center; padding: 1.5rem; color: var(--color-text-muted);">
          No hay componentes definidos aún.
        </td>
      </tr>
    `;
    return;
  }

  tbody.innerHTML = items.map(item => `
    <tr style="border-bottom: 1px solid var(--color-border);">
      <td style="padding: 0.5rem; color: var(--color-text-main); font-weight: 500;">${item.name}</td>
      <td style="padding: 0.5rem; font-family: monospace;">${item.sku}</td>
      <td style="padding: 0.5rem; text-align: center; font-weight: bold;">${item.quantity}</td>
      <td style="padding: 0.5rem; text-align: center;">
        <button type="button" class="btn-remove-pack-component" data-id="${item.id}" style="background: transparent; border: none; color: var(--color-danger); cursor: pointer; font-size: 1.1rem; display: inline-flex; align-items: center; justify-content: center; padding: 0.25rem;">
          <i class="ri-delete-bin-line"></i>
        </button>
      </td>
    </tr>
  `).join('');

  tbody.querySelectorAll('.btn-remove-pack-component').forEach(btn => {
    btn.addEventListener('click', (e) => {
      const id = e.currentTarget.getAttribute('data-id');
      window.currentPackItems = window.currentPackItems.filter(item => item.id !== id);
      renderPackComponentsTable();
    });
  });
}

async function renderPacksTab() {
  const tbody = document.getElementById('catalog-packs-tbody');
  if (!tbody) return;

  const packs = (window.currentMasterProducts || []).filter(p => p.is_pack);

  if (packs.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="6" class="text-center" style="padding: 2rem; color: var(--color-text-muted);">
          No tienes ningún pack o combo configurado.
        </td>
      </tr>
    `;
    return;
  }

  tbody.innerHTML = `
    <tr>
      <td colspan="6" class="text-center" style="padding: 2rem; color: var(--color-text-muted);">
        <i class="ri-loader-4-line ri-spin" style="font-size: 1.5rem; display: block; margin: 0 auto 0.5rem;"></i>
        Cargando composición de los packs...
      </td>
    </tr>
  `;

  try {
    const packIds = packs.map(p => p.id);
    const { data: relations, error } = await supabase
      .from('product_pack_items')
      .select('pack_product_id, quantity, products:member_product_id(sku, name)')
      .in('pack_product_id', packIds);

    if (error) throw error;

    const relationsMap = {};
    if (relations) {
      relations.forEach(rel => {
        if (!relationsMap[rel.pack_product_id]) {
          relationsMap[rel.pack_product_id] = [];
        }
        relationsMap[rel.pack_product_id].push(rel);
      });
    }

    tbody.innerHTML = packs.map(item => {
      const imgHtml = item.image_url 
        ? `<img src="${item.image_url}" alt="${item.name}" style="width: 40px; height: 40px; object-fit: cover; border-radius: 4px; border: 1px solid var(--color-border);">` 
        : `<div style="width: 40px; height: 40px; background-color: var(--color-gray-dark); border-radius: 4px; display: flex; align-items: center; justify-content: center; color: var(--color-text-muted); border: 1px solid var(--color-border);"><i class="ri-image-line" style="font-size: 1.2rem;"></i></div>`;

      const comps = relationsMap[item.id] || [];
      const compsHtml = comps.length > 0
        ? comps.map(c => `<div style="margin-bottom: 0.25rem;"><strong>${c.products?.sku || 'Sin SKU'}</strong>: ${c.products?.name || 'Desconocido'} <span style="color: var(--color-primary); font-weight: bold;">x${c.quantity}</span></div>`).join('')
        : '<span style="color: var(--color-danger); font-style: italic;">Sin componentes configurados</span>';

      const isObserver = userRole === 'observer';
      const deleteBtn = isObserver 
        ? '' 
        : `<button class="btn btn-outline btn-delete-product" data-id="${item.id}" style="padding: 0.35rem 0.75rem; font-size: 0.85rem; border-color: var(--color-danger); color: var(--color-danger); margin-left: 0.5rem;"><i class="ri-delete-bin-line" style="margin-right: 0.25rem;"></i>Borrar</button>`;
      
      const actionBtn = isObserver 
        ? '' 
        : `<button class="btn btn-outline btn-edit-product" data-id="${item.id}" style="padding: 0.35rem 0.75rem; font-size: 0.85rem; border-color: var(--color-border); color: var(--color-text);"><i class="ri-edit-line" style="margin-right: 0.25rem;"></i>Editar</button>` + deleteBtn;

      return `
        <tr data-product-row-id="${item.id}">
          <td style="padding: 0.75rem 2rem;">${imgHtml}</td>
          <td style="padding: 0.75rem 2rem;"><strong>${item.sku}</strong></td>
          <td style="padding: 0.75rem 2rem;">${item.name}</td>
          <td style="padding: 0.75rem 2rem;">$${item.price ? item.price.toLocaleString('es-CL') : '0'}</td>
          <td style="padding: 0.75rem 2rem; line-height: 1.4;">${compsHtml}</td>
          <td style="padding: 0.75rem 2rem;">${actionBtn}</td>
        </tr>
      `;
    }).join('');

    // Re-bind listeners
    tbody.querySelectorAll('.btn-edit-product').forEach(btn => {
      btn.addEventListener('click', (e) => {
        const prodId = e.currentTarget.getAttribute('data-id');
        openEditProductModal(prodId);
        showWmsWarningInModal('form-edit-product');
      });
    });

    tbody.querySelectorAll('.btn-delete-product').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        const prodId = e.currentTarget.getAttribute('data-id');
        if (confirm('¿Estás seguro de que deseas eliminar este combo/pack?')) {
          try {
            const { error } = await supabase.from('products').delete().eq('id', prodId);
            if (error) throw error;
            alert('Pack eliminado correctamente.');
            renderCatalog();
          } catch (err) {
            alert('Error al eliminar pack: ' + err.message);
          }
        }
      });
    });

  } catch (err) {
    console.error("Error loading packs:", err);
    tbody.innerHTML = `
      <tr>
        <td colspan="6" class="text-center" style="padding: 2rem; color: var(--color-danger);">
          Error al cargar composición de packs: ${err.message}
        </td>
      </tr>
    `;
  }
}

// ==========================================
// REDISEÑO: Catálogo Master y Equivalencias SKU
// ==========================================

function showWmsWarningInModal(formId) {
  const form = document.getElementById(formId);
  if (!form) return;
  if (form.querySelector('.wms-sync-warning')) return;
  
  const warningDiv = document.createElement('div');
  warningDiv.className = 'wms-sync-warning';
  warningDiv.style.margin = '0 1rem 1rem 1rem';
  warningDiv.style.padding = '0.75rem 1rem';
  warningDiv.style.background = 'rgba(245, 158, 11, 0.1)';
  warningDiv.style.border = '1px solid rgba(245, 158, 11, 0.2)';
  warningDiv.style.borderRadius = '0.375rem';
  warningDiv.style.color = '#d97706';
  warningDiv.style.fontSize = '0.85rem';
  warningDiv.style.lineHeight = '1.4';
  warningDiv.style.display = 'flex';
  warningDiv.style.alignItems = 'center';
  warningDiv.style.gap = '0.5rem';
  warningDiv.innerHTML = `
    <i class="ri-alert-line" style="font-size: 1.2rem; flex-shrink: 0;"></i>
    <div>
      <strong>Recordatorio:</strong> De momento tus cambios solo se aplican al WMS. Debes ajustar en tu plataforma de ventas los cambios también.
    </div>
  `;
  
  const modalBody = form.querySelector('.modal-body');
  if (modalBody) {
    form.insertBefore(warningDiv, modalBody);
  }
}

function renderMasterCatalogRows(products) {
  const tbody = document.getElementById('catalog-master-tbody');
  if (!tbody) return;

  if (products.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="12" class="text-center" style="padding: 2rem; color: var(--color-text-muted);">
          No hay productos en el catálogo master.
        </td>
      </tr>
    `;
    return;
  }

  const sortCol = window.catalogSortCol || 'sku';
  const sortAsc = window.catalogSortAsc !== false;

  const sortedProducts = [...products].sort((a, b) => {
    let valA, valB;
    if (sortCol === 'sku') {
      valA = (a.sku || '').toString().toLowerCase();
      valB = (b.sku || '').toString().toLowerCase();
    } else if (sortCol === 'name') {
      valA = (a.name || '').toString().toLowerCase();
      valB = (b.name || '').toString().toLowerCase();
    } else if (sortCol === 'barcode') {
      valA = (a.barcode || '').toString().toLowerCase();
      valB = (b.barcode || '').toString().toLowerCase();
    } else if (sortCol === 'stock') {
      valA = parseInt(window.catalogInitialStockMap?.[a.id] || 0, 10);
      valB = parseInt(window.catalogInitialStockMap?.[b.id] || 0, 10);
    } else if (sortCol === 'price') {
      valA = parseFloat(a.price || 0);
      valB = parseFloat(b.price || 0);
    } else if (sortCol === 'origin') {
      let origA = a.shopify_product_id ? 'shopify' : (a.raw_meli_data ? 'meli' : (a.raw_falabella_data ? 'falabella' : 'manual'));
      let origB = b.shopify_product_id ? 'shopify' : (b.raw_meli_data ? 'meli' : (b.raw_falabella_data ? 'falabella' : 'manual'));
      valA = origA;
      valB = origB;
    } else if (sortCol === 'medidas') {
      valA = (parseFloat(a.length) || 0) * (parseFloat(a.width) || 0) * (parseFloat(a.height) || 0);
      valB = (parseFloat(b.length) || 0) * (parseFloat(b.width) || 0) * (parseFloat(b.height) || 0);
    } else if (sortCol === 'volumen') {
      valA = parseFloat(a.volumen || 0);
      valB = parseFloat(b.volumen || 0);
    } else if (sortCol === 'weight') {
      valA = parseFloat(a.weight || 0);
      valB = parseFloat(b.weight || 0);
    } else if (sortCol === 'venc') {
      valA = (a.expiration_date || '').toString().toLowerCase();
      valB = (b.expiration_date || '').toString().toLowerCase();
    } else {
      return 0;
    }

    if (valA < valB) return sortAsc ? -1 : 1;
    if (valA > valB) return sortAsc ? 1 : -1;
    return 0;
  });

  // Actualizar indicadores visuales de ordenación en las cabeceras
  document.querySelectorAll('.sortable-header').forEach(header => {
    const col = header.getAttribute('data-sort');
    const icon = header.querySelector('.sort-icon');
    if (icon) {
      if (col === sortCol) {
        icon.className = sortAsc ? 'sort-icon ri-arrow-up-line' : 'sort-icon ri-arrow-down-line';
        icon.style.color = 'var(--color-primary)';
      } else {
        icon.className = 'sort-icon ri-arrow-up-down-line';
        icon.style.color = 'var(--color-text-muted)';
      }
    }
  });

  tbody.innerHTML = sortedProducts.map(item => {
    const imgHtml = item.image_url 
      ? `<img src="${item.image_url}" alt="${item.name}" style="width: 40px; height: 40px; object-fit: cover; border-radius: 4px; border: 1px solid var(--color-border);">` 
      : `<div style="width: 40px; height: 40px; background-color: var(--color-gray-dark); border-radius: 4px; display: flex; align-items: center; justify-content: center; color: var(--color-text-muted); border: 1px solid var(--color-border);"><i class="ri-image-line" style="font-size: 1.2rem;"></i></div>`;

    const dimensions = (item.length || item.width || item.height)
      ? `${item.length || 0} x ${item.width || 0} x ${item.height || 0} cm`
      : '<span style="color: var(--color-text-muted); font-size: 0.85rem;">No def.</span>';

    const weight = item.weight 
      ? `${item.weight} kg` 
      : '<span style="color: var(--color-text-muted); font-size: 0.85rem;">No def.</span>';

    let platformName = 'Manual';
    let platformColor = '#64748b';
    if (item.shopify_product_id) {
      platformName = 'Shopify'; platformColor = '#96bf48';
    } else if (item.raw_meli_data) {
      platformName = 'MercadoLibre'; platformColor = '#f59e0b';
    } else if (item.raw_falabella_data) {
      platformName = 'Falabella'; platformColor = '#84cc16';
    } else if (item.raw_paris_data) {
      platformName = 'Paris'; platformColor = '#e11d48';
    } else if (item.raw_woocommerce_data) {
      platformName = 'WooCommerce'; platformColor = '#96588a';
    } else if (item.raw_jumpseller_data) {
      platformName = 'Jumpseller'; platformColor = '#0284c7';
    }
    const platformLower = platformName.toLowerCase();
    const originBadge = `<img src="./img/${platformLower}.png" alt="${platformName}" title="${platformName}" style="height: 32px; max-width: 100px; object-fit: contain; vertical-align: middle;" onerror="this.onerror=null; this.outerHTML='<span class=\\'badge\\' style=\\'background-color: ${platformColor}15; color: ${platformColor}; padding: 0.25rem 0.5rem; border-radius: 0.25rem; font-size: 0.75rem; font-weight: 600;\\'>${platformName}</span>';" />`;

    const expAndLot = (item.expiration_date || item.lot_number)
      ? `<div style="font-size: 0.8rem; line-height: 1.2;">
           ${item.expiration_date ? `Vence: ${item.expiration_date}<br>` : ''}
           ${item.lot_number ? `Lote: ${item.lot_number}` : ''}
         </div>`
      : '<span style="color: var(--color-text-muted); font-size: 0.85rem;">-</span>';

    const isObserver = userRole === 'observer';
    const deleteBtn = isObserver 
      ? '' 
      : `<button class="btn btn-outline btn-delete-product" data-id="${item.id}" style="padding: 0.25rem 0.5rem; font-size: 0.8rem; border-color: var(--color-danger); color: var(--color-danger); margin-left: 0.5rem;"><i class="ri-delete-bin-line" style="margin-right: 0.25rem;"></i>Borrar</button>`;
    
    const actionBtn = isObserver 
      ? '' 
      : `<button class="btn btn-outline btn-edit-product" data-id="${item.id}" style="padding: 0.25rem 0.5rem; font-size: 0.8rem; border-color: var(--color-border); color: var(--color-text);"><i class="ri-edit-line" style="margin-right: 0.25rem;"></i>Editar</button>` + deleteBtn;

    let packBadge = '';
    if (item.is_pack) {
      packBadge = ` <span class="badge" style="background-color: #8b5cf6; color: white; padding: 0.25rem 0.5rem; border-radius: 0.25rem; font-size: 0.75rem; font-weight: 600; margin-left: 0.25rem;"><i class="ri-stack-line"></i> Pack</span>`;
    }

    const initialStock = window.catalogInitialStockMap?.[item.id] || 0;

    const initialStockCell = window.catalogQuickEditMode
      ? `<td style="padding: 0.45rem 0.75rem; text-align: center;">
           <input type="number" class="quick-edit-stock form-input" data-id="${item.id}" data-old="${initialStock}" value="${initialStock}" style="width: 75px; text-align: center; padding: 0.25rem 0.5rem; height: 32px; font-size: 0.85rem; margin: 0 auto; background: var(--color-bg); color: var(--color-text-main); border: 1px solid var(--color-border); border-radius: var(--radius-md);">
         </td>`
      : `<td style="padding: 0.45rem 0.75rem; text-align: center;"><strong>${initialStock}</strong></td>`;

    const dimensionsCell = window.catalogQuickEditMode
      ? `<td style="padding: 0.45rem 0.75rem;">
           <div style="display: flex; gap: 0.25rem; align-items: center; font-size: 0.8rem;">
             <span style="color: var(--color-text-muted);">L:</span>
             <input type="number" step="any" class="quick-edit-length form-input" data-id="${item.id}" data-old="${item.length || ''}" value="${item.length || ''}" style="width: 45px; padding: 0.25rem; height: 32px; font-size: 0.85rem; background: var(--color-bg); color: var(--color-text-main); border: 1px solid var(--color-border); border-radius: var(--radius-md);">
             <span style="color: var(--color-text-muted);">An:</span>
             <input type="number" step="any" class="quick-edit-width form-input" data-id="${item.id}" data-old="${item.width || ''}" value="${item.width || ''}" style="width: 45px; padding: 0.25rem; height: 32px; font-size: 0.85rem; background: var(--color-bg); color: var(--color-text-main); border: 1px solid var(--color-border); border-radius: var(--radius-md);">
             <span style="color: var(--color-text-muted);">Al:</span>
             <input type="number" step="any" class="quick-edit-height form-input" data-id="${item.id}" data-old="${item.height || ''}" value="${item.height || ''}" style="width: 45px; padding: 0.25rem; height: 32px; font-size: 0.85rem; background: var(--color-bg); color: var(--color-text-main); border: 1px solid var(--color-border); border-radius: var(--radius-md);">
           </div>
         </td>`
      : `<td style="padding: 0.45rem 0.75rem;">${dimensions}</td>`;

    const unitVol = parseFloat(item.volumen || 0);
    const totalVol = unitVol * initialStock;
    const volumenHtml = (item.volumen !== null && item.volumen !== undefined)
      ? `<div style="font-size: 0.8rem; line-height: 1.2;">
           Unit: ${unitVol.toFixed(5)} m³<br>
           Total: ${totalVol.toFixed(5)} m³
         </div>`
      : '<span style="color: var(--color-text-muted); font-size: 0.85rem;">No def.</span>';

    const volumenCell = window.catalogQuickEditMode
      ? `<td style="padding: 0.45rem 0.75rem;">
           <div style="display: flex; flex-direction: column; gap: 0.25rem; font-size: 0.85rem;">
             <div style="display: flex; gap: 0.25rem; align-items: center;">
               <span style="color: var(--color-text-muted);">Vol (m³):</span>
               <input type="number" step="any" class="quick-edit-volumen form-input" data-id="${item.id}" data-old="${item.volumen !== null && item.volumen !== undefined ? item.volumen : ''}" value="${item.volumen !== null && item.volumen !== undefined ? item.volumen : ''}" style="width: 75px; padding: 0.25rem; height: 32px; font-size: 0.85rem; background: var(--color-bg); color: var(--color-text-main); border: 1px solid var(--color-border); border-radius: var(--radius-md);">
             </div>
             <div class="quick-edit-total-vol-display" data-id="${item.id}" style="font-size: 0.75rem; color: var(--color-text-muted); padding-left: 0.25rem;">
               Total: ${totalVol.toFixed(5)} m³
             </div>
           </div>
         </td>`
      : `<td style="padding: 0.45rem 0.75rem;">${volumenHtml}</td>`;

    return `
      <tr data-product-row-id="${item.id}">
        <td style="padding: 0.45rem 0.75rem;">${imgHtml}</td>
        <td style="padding: 0.45rem 0.75rem;"><strong>${item.sku}</strong></td>
        <td style="padding: 0.45rem 0.75rem;">${item.name}</td>
        <td style="padding: 0.45rem 0.75rem;">${item.barcode || '<span style="color: var(--color-text-muted); font-size: 0.85rem;">-</span>'}</td>
        ${initialStockCell}
        <td style="padding: 0.45rem 0.75rem;">$${item.price ? item.price.toLocaleString('es-CL') : '0'}</td>
        <td style="padding: 0.45rem 0.75rem;">${originBadge}${packBadge}</td>
        ${dimensionsCell}
        ${volumenCell}
        <td style="padding: 0.45rem 0.75rem;">${weight}</td>
        <td style="padding: 0.45rem 0.75rem;">${expAndLot}</td>
        <td style="padding: 0.45rem 0.75rem;">${actionBtn}</td>
      </tr>
    `;
  }).join('');

  // Preservar filtro de búsqueda si existe un término ingresado
  const masterSearch = document.getElementById('catalog-master-search');
  if (masterSearch && masterSearch.value.trim()) {
    const q = masterSearch.value.toLowerCase().trim();
    const rows = tbody.querySelectorAll('tr');
    rows.forEach(row => {
      const text = row.textContent.toLowerCase();
      row.style.display = text.includes(q) ? '' : 'none';
    });
  }
}

function renderEquivalencesRows(unmappedProducts, mappingsMap) {
  const tbody = document.getElementById('eq-matrix-tbody');
  if (!tbody) return;

  if (unmappedProducts.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="4" style="text-align: center; padding: 2rem; color: var(--color-text-muted);">
          No hay productos no mapeados en tus canales sincronizados.
        </td>
      </tr>
    `;
    return;
  }

  const isObserver = userRole === 'observer';

  tbody.innerHTML = unmappedProducts.map(sp => {
    const currentMapping = (mappingsMap[sp.platform] && mappingsMap[sp.platform][sp.sku]) || '';
    
    let statusBadge = '';
    if (sp.status) {
      const s = sp.status.toLowerCase().trim();
      let bgColor = 'rgba(107, 114, 128, 0.1)';
      let textColor = '#6b7280';
      let borderClr = 'rgba(107, 114, 128, 0.2)';
      let label = sp.status;

      if (s === 'active' || s === 'publish') {
        bgColor = 'rgba(16, 185, 129, 0.1)';
        textColor = '#10b981';
        borderClr = 'rgba(16, 185, 129, 0.2)';
        label = 'Activo';
      } else if (s === 'draft' || s === 'borrador') {
        bgColor = 'rgba(245, 158, 11, 0.1)';
        textColor = '#f59e0b';
        borderClr = 'rgba(245, 158, 11, 0.2)';
        label = 'Borrador';
      } else if (s === 'archived' || s === 'archivado' || s === 'inactive') {
        bgColor = 'rgba(239, 68, 68, 0.1)';
        textColor = '#ef4444';
        borderClr = 'rgba(239, 68, 68, 0.2)';
        label = 'Archivado';
      }

      statusBadge = ` <span class="badge" style="background-color: ${bgColor}; color: ${textColor}; border: 1px solid ${borderClr}; padding: 0.15rem 0.35rem; border-radius: 4px; font-size: 0.7rem; font-weight: 600; margin-left: 0.5rem; text-transform: uppercase;">${label}</span>`;
    }

    return `
      <tr class="eq-row" style="border-bottom: 1px solid var(--color-border); transition: background-color 0.15s;" onmouseover="this.style.backgroundColor='var(--color-bg)'" onmouseout="this.style.backgroundColor='transparent'">
        <td style="padding: 0.75rem 2rem; font-size: 0.9rem; color: var(--color-text-main); font-weight: 500;">${sp.name}${statusBadge}</td>
        <td style="padding: 0.75rem 2rem;">
          <span class="badge" style="background: var(--color-bg); color: var(--color-text-main); border: 1px solid var(--color-border); padding: 0.25rem 0.5rem; border-radius: 4px; font-size: 0.75rem; font-weight: 600;">${sp.platform}</span>
        </td>
        <td style="padding: 0.75rem 2rem; font-size: 0.9rem; font-family: monospace; font-weight: bold; color: var(--color-text-muted);">${sp.sku}</td>
        <td style="padding: 0.5rem 2rem;">
          <input type="text" class="form-input eq-mapping-input" 
                 list="master-skus-list" 
                 data-platform-sku="${sp.sku}" 
                 data-platform="${sp.platform}" 
                 value="${currentMapping}" 
                 placeholder="Escribe para buscar o seleccionar..." 
                 ${isObserver ? 'disabled' : ''}
                 style="margin: 0; padding: 0.4rem 0.8rem; font-size: 0.85rem; font-family: monospace; border: 1px solid var(--color-border); background: var(--color-surface); color: var(--color-text-main); border-radius: var(--radius-md); width: 100%; transition: border-color 0.2s;">
        </td>
      </tr>
    `;
  }).join('');
}

function openCatalogHelpDrawer() {
  let drawer = document.getElementById('catalog-help-drawer');
  let overlay = document.getElementById('catalog-help-overlay');

  if (!drawer) {
    overlay = document.createElement('div');
    overlay.id = 'catalog-help-overlay';
    overlay.className = 'catalog-help-overlay';
    overlay.style.cssText = `
      position: fixed;
      top: 0;
      left: 0;
      width: 100vw;
      height: 100vh;
      background-color: rgba(0, 0, 0, 0.4);
      z-index: 9999;
      opacity: 0;
      pointer-events: none;
      transition: opacity 0.3s ease;
    `;
    document.body.appendChild(overlay);

    drawer = document.createElement('div');
    drawer.id = 'catalog-help-drawer';
    drawer.className = 'catalog-help-drawer';
    drawer.style.cssText = `
      position: fixed;
      top: 0;
      right: -450px;
      width: 450px;
      max-width: 90%;
      height: 100vh;
      background-color: var(--color-surface, #1e293b);
      border-left: 1px solid var(--color-border, #334155);
      box-shadow: -4px 0 15px rgba(0, 0, 0, 0.3);
      z-index: 10000;
      transition: right 0.3s cubic-bezier(0.16, 1, 0.3, 1);
      display: flex;
      flex-direction: column;
      color: var(--color-text-main, #f8fafc);
    `;

    drawer.innerHTML = `
      <div style="padding: 1.5rem; border-bottom: 1px solid var(--color-border, #334155); display: flex; justify-content: space-between; align-items: center; background-color: var(--color-bg, #0f172a);">
        <h3 style="margin: 0; font-size: 1.2rem; font-weight: 600; display: flex; align-items: center; gap: 0.5rem; color: var(--color-primary, #3b82f6);">
          <i class="ri-question-line"></i> Ayuda del Módulo
        </h3>
        <button id="close-help-drawer" style="background: transparent; border: none; color: var(--color-text-muted, #94a3b8); cursor: pointer; font-size: 1.25rem; display: flex; align-items: center; justify-content: center; padding: 0.25rem; border-radius: 4px; transition: background 0.2s;">
          <i class="ri-close-line"></i>
        </button>
      </div>
      <div style="padding: 1.5rem; overflow-y: auto; flex: 1; font-size: 0.95rem; line-height: 1.6; display: flex; flex-direction: column; gap: 1.25rem;">
        <p style="margin: 0; font-weight: 500; color: var(--color-text-main, #f8fafc);">
          ¡Bienvenido al módulo de <strong>Catálogo de Productos</strong>! Este espacio es el corazón de tu operación en WMS STOCKA, ya que es donde centralizas, unificas y controlas todo tu inventario físico, conectándolo con tus diferentes canales de venta en línea.
        </p>
        <p style="margin: 0; color: var(--color-text-muted, #94a3b8);">
          Aquí tienes una guía rápida de todo lo que necesitas saber, cómo funciona el módulo y tus primeros pasos:
        </p>

        <div style="border-top: 1px solid var(--color-border, #334155); padding-top: 1rem;">
          <h4 style="margin: 0 0 0.5rem 0; font-size: 1rem; color: var(--color-text-main, #f8fafc); font-weight: 600;">
            1. ¿Cómo funciona este módulo?
          </h4>
          <p style="margin: 0 0 0.75rem 0; color: var(--color-text-muted, #94a3b8); font-size: 0.9rem;">
            Para evitar discrepancias de stock y sincronizar correctamente tus pedidos, el sistema se divide en dos conceptos clave:
          </p>
          <ul style="margin: 0; padding-left: 1.25rem; color: var(--color-text-muted, #94a3b8); font-size: 0.9rem; display: flex; flex-direction: column; gap: 0.5rem;">
            <li>
              <strong>Catálogo Master (Tu Bodega Real):</strong> Representa los productos físicos que realmente existen y se almacenan en el WMS. Cada producto tiene un único SKU Maestro.
            </li>
            <li>
              <strong>Equivalencias SKU (El Puente con tus Tiendas):</strong> Tus plataformas externas (Shopify, MercadoLibre, Falabella, etc.) a veces usan SKUs diferentes para referirse al mismo producto físico. En la pestaña de Equivalencias SKU puedes decirle al sistema: <em>"Cuando se venda el SKU X en Shopify, descuenta el stock del SKU Maestro Y en el WMS"</em>.
            </li>
          </ul>
        </div>

        <div style="border-top: 1px solid var(--color-border, #334155); padding-top: 1rem;">
          <h4 style="margin: 0 0 0.75rem 0; font-size: 1rem; color: var(--color-text-main, #f8fafc); font-weight: 600;">
            2. ¿Qué debes hacer al entrar por primera vez? (Paso a Paso)
          </h4>
          
          <div style="margin-bottom: 0.75rem;">
            <strong style="color: var(--color-text-main, #f8fafc); font-size: 0.9rem; display: block; margin-bottom: 0.25rem;">Paso 1: Seleccionar tu Comercio Activo</strong>
            <p style="margin: 0; color: var(--color-text-muted, #94a3b8); font-size: 0.85rem;">
              Si tu usuario tiene múltiples tiendas o empresas asociadas en STOCKA, verás el desplegable "Seleccionar Comercio Activo" en la parte superior. Asegúrate de elegir el comercio que deseas configurar.
            </p>
          </div>

          <div style="margin-bottom: 0.75rem;">
            <strong style="color: var(--color-text-main, #f8fafc); font-size: 0.9rem; display: block; margin-bottom: 0.25rem;">Paso 2: Definir tu Plataforma Principal (Catálogo Maestro)</strong>
            <p style="margin: 0; color: var(--color-text-muted, #94a3b8); font-size: 0.85rem;">
              En la tarjeta de configuración superior, verás la opción "Plataforma Principal de Ventas":
              <br>• Si ya tienes una tienda con tus productos cargados (ej: Shopify): Selecciónala como plataforma principal y haz clic en Guardar. Esto le dice al WMS que use tu tienda como la fuente de verdad.
              <br>• Si vas a gestionar tus productos directamente en el WMS de forma manual: Selecciona "Ninguna (Usar WMS)".
            </p>
          </div>

          <div style="margin-bottom: 0.75rem;">
            <strong style="color: var(--color-text-main, #f8fafc); font-size: 0.9rem; display: block; margin-bottom: 0.25rem;">Paso 3: Cargar tu Catálogo Master</strong>
            <p style="margin: 0; color: var(--color-text-muted, #94a3b8); font-size: 0.85rem;">
              Ve a la pestaña Catálogo Master:
              <br>• Si configuraste una plataforma principal en el paso anterior, verás el botón "Importar de [Plataforma]". Haz clic en él para traer todos tus productos automáticamente al WMS.
              <br>• Si vas a trabajar de forma manual, utiliza el botón "Nuevo Producto" para crearlos uno a uno.
            </p>
          </div>

          <div>
            <strong style="color: var(--color-text-main, #f8fafc); font-size: 0.9rem; display: block; margin-bottom: 0.25rem;">Paso 4: Mapear Equivalencias de tus Canales Secundarios</strong>
            <p style="margin: 0; color: var(--color-text-muted, #94a3b8); font-size: 0.85rem;">
              Si vendes el mismo producto físico en más de una plataforma (ej. vendes en Shopify y también en MercadoLibre):
              <br>1. Ve a la pestaña de Equivalencias SKU.
              <br>2. El sistema listará automáticamente todos los productos de tus canales integrados que no coinciden exactamente con un SKU de tu Catálogo Master.
              <br>3. Mapeo Individual: En la columna "Equivalencia", escribe o selecciona el SKU maestro del WMS correspondiente a cada producto externo. El guardado es automático.
              <br>4. Auto-mapeo: Si los SKUs externos coinciden con los maestros pero están en minúsculas o tienen espacios, haz clic en "Auto-mapear Coincidencias" para que el sistema los enlace automáticamente.
              <br>5. Importación Masiva: Si tienes cientos de productos, puedes hacer clic en "Importar Planilla" para subir tus equivalencias en un archivo Excel.
            </p>
          </div>
        </div>

        <div style="border-top: 1px solid var(--color-border, #334155); padding-top: 1rem; background: rgba(59, 130, 246, 0.05); padding: 1rem; border-radius: var(--radius-md); border-left: 3px solid var(--color-primary, #3b82f6);">
          <strong style="color: var(--color-text-main, #f8fafc); font-size: 0.9rem; display: flex; align-items: center; gap: 0.25rem; margin-bottom: 0.25rem;">
            💡 Un Consejo Útil
          </strong>
          <p style="margin: 0; color: var(--color-text-muted, #94a3b8); font-size: 0.85rem; line-height: 1.5;">
            Cada vez que realices cambios en tus productos desde el panel administrativo de tus tiendas (como cambiar un SKU en Shopify), el sistema de equivalencias te ayudará a mantener la conexión estable. Puedes hacer clic en "Validar SKUs" en la sección de consistencia al final de la pestaña para verificar que no haya SKUs huérfanos o duplicados.
          </p>
        </div>
      </div>
    `;

    document.body.appendChild(drawer);

    const closeBtn = drawer.querySelector('#close-help-drawer');
    closeBtn.addEventListener('click', closeCatalogHelpDrawer);
    overlay.addEventListener('click', closeCatalogHelpDrawer);
  }

  setTimeout(() => {
    overlay.style.opacity = '1';
    overlay.style.pointerEvents = 'auto';
    drawer.style.right = '0';
  }, 10);
}

function closeCatalogHelpDrawer() {
  const drawer = document.getElementById('catalog-help-drawer');
  const overlay = document.getElementById('catalog-help-overlay');
  if (drawer && overlay) {
    overlay.style.opacity = '0';
    overlay.style.pointerEvents = 'none';
    drawer.style.right = '-450px';
  }
}

window.showStockAndDimensionsPreviewModal = function({ title, headers, rows, onConfirm }) {
  const oldModal = document.getElementById('modal-import-preview');
  if (oldModal) oldModal.remove();

  const modal = document.createElement('div');
  modal.id = 'modal-import-preview';
  modal.className = 'modal-overlay active';
  modal.style.zIndex = '9999';

  const trs = rows.map(r => {
    const badgeColor = r.status === 'ok' ? 'var(--color-success)' : 'var(--color-danger)';
    const badgeText = r.status === 'ok' ? 'Listo' : 'Error';
    const rowStyle = r.status === 'error' ? 'background-color: rgba(239, 68, 68, 0.05);' : '';
    return `
      <tr style="${rowStyle} border-bottom: 1px solid var(--color-border);">
        <td style="padding: 0.75rem; font-weight: 600;">${r.sku}</td>
        <td style="padding: 0.75rem; max-width: 250px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${r.name || '<span style="color:var(--color-text-muted);">No encontrado</span>'}</td>
        <td style="padding: 0.75rem; text-align: center;">${r.oldValue}</td>
        <td style="padding: 0.75rem; text-align: center; font-weight: 600;">${r.newValue}</td>
        <td style="padding: 0.75rem; text-align: center;">
          <span class="badge" style="background-color: ${badgeColor}20; color: ${badgeColor}; padding: 0.25rem 0.5rem; border-radius: var(--radius-sm); font-size: 0.75rem; font-weight: 600;">
            ${badgeText}
          </span>
        </td>
        <td style="padding: 0.75rem; color: ${r.status === 'ok' ? 'var(--color-text-muted)' : 'var(--color-danger)'}; font-size: 0.8rem;">
          ${r.message || ''}
        </td>
      </tr>
    `;
  }).join('');

  const totalRows = rows.length;
  const okRows = rows.filter(r => r.status === 'ok').length;
  const errorRows = rows.filter(r => r.status === 'error').length;

  const alertBanner = errorRows > 0
    ? `<div style="background-color: rgba(239, 68, 68, 0.1); border: 1px solid var(--color-danger); color: var(--color-danger); padding: 0.75rem 1rem; border-radius: var(--radius-md); margin-bottom: 1rem; font-size: 0.85rem; display: flex; align-items: center; gap: 0.5rem;">
         <i class="ri-error-warning-line" style="font-size: 1.1rem;"></i>
         <span>Se detectaron <strong>${errorRows} filas con errores</strong>. Solo se procesarán las <strong>${okRows} filas válidas</strong>.</span>
       </div>`
    : `<div style="background-color: rgba(16, 124, 65, 0.1); border: 1px solid var(--color-success); color: var(--color-success); padding: 0.75rem 1rem; border-radius: var(--radius-md); margin-bottom: 1rem; font-size: 0.85rem; display: flex; align-items: center; gap: 0.5rem;">
         <i class="ri-checkbox-circle-line" style="font-size: 1.1rem;"></i>
         <span>¡Todo correcto! Las <strong>${okRows} filas</strong> son completamente válidas y están listas para importar.</span>
       </div>`;

  modal.innerHTML = `
    <div class="modal-content" style="max-width: 850px; width: 95%; max-height: 90vh; display: flex; flex-direction: column;">
      <div class="modal-header">
        <h3><i class="ri-table-line" style="color: var(--color-primary); margin-right: 0.5rem;"></i> ${title}</h3>
        <button class="modal-close" onclick="this.closest('.modal-overlay').remove()">&times;</button>
      </div>
      <div class="modal-body" style="padding: 1.25rem; overflow-y: auto; flex: 1;">
        ${alertBanner}
        <div style="max-height: 350px; overflow-y: auto; border: 1px solid var(--color-border); border-radius: var(--radius-md); margin-bottom: 1.25rem;">
          <table style="width: 100%; border-collapse: collapse; text-align: left; font-size: 0.85rem;">
            <thead>
              <tr style="background-color: var(--color-bg); border-bottom: 2px solid var(--color-border); color: var(--color-text-muted); text-transform: uppercase; font-size: 0.75rem; letter-spacing: 0.05em; position: sticky; top: 0; z-index: 1;">
                <th style="padding: 0.75rem;">SKU</th>
                <th style="padding: 0.75rem;">Nombre</th>
                <th style="padding: 0.75rem; text-align: center;">V. Actual</th>
                <th style="padding: 0.75rem; text-align: center;">N. Valor</th>
                <th style="padding: 0.75rem; text-align: center;">Estado</th>
                <th style="padding: 0.75rem;">Detalle</th>
              </tr>
            </thead>
            <tbody>
              ${trs}
            </tbody>
          </table>
        </div>
        
        <div style="display: flex; justify-content: space-between; align-items: center; background: var(--color-bg); padding: 0.75rem 1rem; border-radius: var(--radius-md); border: 1px solid var(--color-border);">
          <div style="display: flex; gap: 1.5rem; font-size: 0.85rem; color: var(--color-text-main);">
            <div>Total registros: <strong>${totalRows}</strong></div>
            <div style="color: var(--color-success);">Válidos: <strong>${okRows}</strong></div>
            <div style="color: var(--color-danger);">Errores: <strong>${errorRows}</strong></div>
          </div>
        </div>
      </div>
      <div class="modal-footer" style="border-top: 1px solid var(--color-border); padding: 1rem 1.25rem;">
        <button type="button" class="btn btn-outline" onclick="this.closest('.modal-overlay').remove()">Cancelar</button>
        <button type="button" class="btn btn-primary" id="btn-confirm-import" ${okRows === 0 ? 'disabled' : ''} style="background-color: var(--color-success); border-color: var(--color-success); color: white;">
          <i class="ri-checkbox-circle-line"></i> Confirmar y Cargar
        </button>
      </div>
    </div>
  `;

  document.body.appendChild(modal);

  const confirmBtn = document.getElementById('btn-confirm-import');
  if (confirmBtn) {
    confirmBtn.addEventListener('click', async () => {
      confirmBtn.disabled = true;
      confirmBtn.innerHTML = '<i class="ri-loader-4-line spin"></i> Procesando...';
      try {
        const validRows = rows.filter(r => r.status === 'ok');
        await onConfirm(validRows);
        modal.remove();
      } catch (err) {
        console.error(err);
        alert('Error durante la importación: ' + err.message);
        confirmBtn.disabled = false;
        confirmBtn.innerHTML = '<i class="ri-checkbox-circle-line"></i> Confirmar y Cargar';
      }
    });
  }
};

function setupCatalogListeners(commerce, mainPlatform) {
  // 0. Help button trigger
  const btnHelp = document.getElementById('btn-catalog-help');
  if (btnHelp) {
    btnHelp.addEventListener('click', openCatalogHelpDrawer);
  }

  // 1. Tab switching
  const tabs = document.querySelectorAll('.catalog-tab');
  const panes = document.querySelectorAll('.catalog-tab-pane');
  tabs.forEach(tab => {
    tab.addEventListener('click', () => {
      tabs.forEach(t => {
        t.style.borderBottomColor = 'transparent';
        t.style.color = 'var(--color-text-muted)';
        t.style.fontWeight = '500';
        t.classList.remove('active');
      });
      panes.forEach(p => p.style.display = 'none');

      tab.classList.add('active');
      tab.style.borderBottomColor = 'var(--color-primary)';
      tab.style.color = 'var(--color-text-main)';
      tab.style.fontWeight = '600';

      const tabId = tab.getAttribute('data-tab');
      const targetPane = document.getElementById(tabId);
      if (targetPane) targetPane.style.display = 'block';

      if (tabId === 'tab-catalog-packs') {
        renderPacksTab();
      } else if (tabId === 'tab-catalog-campaigns') {
        renderCampaignsTab(commerce);
      }
    });
  });

  // 1.5. Configuración de Plataforma Principal
  const btnSaveMain = document.getElementById('btn-save-main-platform');
  if (btnSaveMain) {
    btnSaveMain.addEventListener('click', async () => {
      const selected = document.getElementById('eq-main-platform-select').value;
      
      btnSaveMain.disabled = true;
      btnSaveMain.innerHTML = `<i class="ri-loader-4-line ri-spin"></i> Guardando...`;

      try {
        const { error: resetErr } = await supabase
          .from('merchant_integrations')
          .update({ is_main: false })
          .eq('comercio', commerce);

        if (resetErr) throw resetErr;

        if (selected) {
          const { error: setErr } = await supabase
            .from('merchant_integrations')
            .update({ is_main: true })
            .eq('comercio', commerce)
            .eq('platform', selected);

          if (setErr) throw setErr;
        }

        alert('Plataforma principal actualizada correctamente.');
        renderCatalog();
      } catch (err) {
        alert('Error al actualizar plataforma principal: ' + err.message);
      } finally {
        btnSaveMain.disabled = false;
        btnSaveMain.innerHTML = `<i class="ri-save-line"></i> Guardar`;
      }
    });
  }

  // 2. Search box for Master Catalog
  const masterSearch = document.getElementById('catalog-master-search');
  if (masterSearch) {
    masterSearch.addEventListener('input', (e) => {
      const q = e.target.value.toLowerCase().trim();
      const rows = document.querySelectorAll('#catalog-master-tbody tr');
      rows.forEach(row => {
        const text = row.textContent.toLowerCase();
        row.style.display = text.includes(q) ? '' : 'none';
      });
    });
  }

  // 2.5. Search box for Packs Tab
  const packsSearch = document.getElementById('catalog-packs-search');
  if (packsSearch) {
    packsSearch.addEventListener('input', (e) => {
      const q = e.target.value.toLowerCase().trim();
      const rows = document.querySelectorAll('#catalog-packs-tbody tr');
      rows.forEach(row => {
        const text = row.textContent.toLowerCase();
        row.style.display = text.includes(q) ? '' : 'none';
      });
    });
  }

  // 3. Search box for Equivalencias
  const eqSearch = document.getElementById('eq-matrix-search');
  if (eqSearch) {
    eqSearch.addEventListener('input', (e) => {
      const q = e.target.value.toLowerCase().trim();
      const rows = document.querySelectorAll('#eq-matrix-tbody tr.eq-row');
      rows.forEach(row => {
        const text = row.textContent.toLowerCase();
        row.style.display = text.includes(q) ? '' : 'none';
      });
    });
  }

  // 4. Modal Warning Banners (New & Edit product)
  const btnNewProd = document.getElementById('btn-new-product');
  if (btnNewProd) {
    btnNewProd.addEventListener('click', () => {
      showWmsWarningInModal('form-new-product');
    });
  }
  document.querySelectorAll('.btn-edit-product').forEach(btn => {
    btn.addEventListener('click', (e) => {
      const prodId = e.currentTarget.getAttribute('data-id');
      openEditProductModal(prodId);
      showWmsWarningInModal('form-edit-product');
    });
  });

  // 5. Delete Product handler
  document.querySelectorAll('.btn-delete-product').forEach(btn => {
    btn.addEventListener('click', async (e) => {
      const prodId = e.currentTarget.getAttribute('data-id');
      if (confirm('¿Estás seguro de que deseas eliminar este producto? Esto también eliminará su inventario asociado en todas las bodegas.')) {
        try {
          const { error } = await supabase.from('products').delete().eq('id', prodId);
          if (error) throw error;
          alert('Producto eliminado correctamente.');
          renderCatalog();
        } catch (err) {
          alert('Error al eliminar producto: ' + err.message);
        }
      }
    });
  });

  // 6. Import from Main Platform handler
  const btnImport = document.getElementById('btn-import-from-main');
  if (btnImport) {
    btnImport.addEventListener('click', async () => {
      if (confirm(`¿Deseas importar todos los productos desde tu plataforma principal (${mainPlatform}) al catálogo master de WMS?`)) {
        btnImport.disabled = true;
        btnImport.textContent = 'Importando...';
        try {
          const { data: syncedProds, error: syncErr } = await supabase
            .from('synced_products')
            .select('*')
            .eq('comercio', commerce)
            .eq('platform', mainPlatform);
          
          if (syncErr) throw syncErr;
          if (!syncedProds || syncedProds.length === 0) {
            alert(`No se encontraron productos sincronizados de ${mainPlatform}. Por favor realiza una sincronización primero en la pestaña Integraciones.`);
            return;
          }

          const { data: userAuth } = await supabase.auth.getUser();
          const merchantId = userAuth.user.id;

          const productsToInsert = syncedProds.map(sp => {
            const productRow = {
              merchant_id: merchantId,
              comercio: commerce,
              sku: sp.sku,
              name: sp.name,
              price: parseFloat(sp.price) || 0,
              image_url: sp.image_url || null,
              description: `Importado automáticamente de ${mainPlatform}`
            };

            if (mainPlatform === 'Shopify') {
              productRow.shopify_product_id = 'imported';
            } else if (mainPlatform === 'MercadoLibre') {
              productRow.raw_meli_data = {};
            } else if (mainPlatform === 'Falabella') {
              productRow.raw_falabella_data = {};
            } else if (mainPlatform === 'Paris') {
              productRow.raw_paris_data = {};
            } else if (mainPlatform === 'WooCommerce') {
              productRow.raw_woocommerce_data = {};
            } else if (mainPlatform === 'Jumpseller') {
              productRow.raw_jumpseller_data = {};
            } else if (mainPlatform === 'Walmart') {
              productRow.raw_walmart_data = {};
            }

            return productRow;
          });

          const { error: insErr } = await supabase
            .from('products')
            .upsert(productsToInsert, { onConflict: 'comercio,sku' });

          if (insErr) throw insErr;

          alert(`¡Importación completada! Se importaron/actualizaron ${productsToInsert.length} productos en el catálogo master.`);
          renderCatalog();
        } catch (err) {
          alert('Error al importar catálogo: ' + err.message);
        } finally {
          btnImport.disabled = false;
          btnImport.innerHTML = `<i class="ri-download-cloud-2-line" style="margin-right: 0.25rem; color: var(--color-primary);"></i>Importar de ${mainPlatform}`;
        }
      }
    });
  }

  // 7. Auto-map equivalences
  const btnAutoMap = document.getElementById('btn-auto-map-equivalences');
  if (btnAutoMap) {
    btnAutoMap.addEventListener('click', async () => {
      const unmapped = window.currentUnmappedSyncedProducts || [];
      const masterSkusSet = new Set(window.currentMasterProducts.map(p => p.sku.toLowerCase().trim().replace(/\s+/g, '')));
      const masterSkusMap = {};
      window.currentMasterProducts.forEach(p => {
        masterSkusMap[p.sku.toLowerCase().trim().replace(/\s+/g, '')] = p.sku;
      });

      const mappingsToInsert = [];
      unmapped.forEach(sp => {
        const cleanSku = sp.sku.toLowerCase().trim().replace(/\s+/g, '');
        if (masterSkusSet.has(cleanSku)) {
          mappingsToInsert.push({
            comercio: commerce,
            platform: sp.platform,
            platform_sku: sp.sku,
            master_sku: masterSkusMap[cleanSku]
          });
        }
      });

      if (mappingsToInsert.length === 0) {
        alert('No se encontraron coincidencias de SKU exactas no mapeadas entre tus canales y el catálogo master.');
        return;
      }

      if (confirm(`Se encontraron ${mappingsToInsert.length} coincidencias exactas de SKU. ¿Deseas mapearlas automáticamente?`)) {
        btnAutoMap.disabled = true;
        btnAutoMap.innerHTML = `<i class="ri-loader-4-line ri-spin"></i> Procesando...`;
        try {
          const { error } = await supabase
            .from('sku_equivalences')
            .upsert(mappingsToInsert, { onConflict: 'comercio,platform,platform_sku' });
          
          if (error) throw error;
          alert(`¡Éxito! Se mapearon automáticamente ${mappingsToInsert.length} equivalencias.`);
          renderCatalog();
        } catch (err) {
          alert('Error al realizar auto-mapeo: ' + err.message);
        } finally {
          btnAutoMap.disabled = false;
          btnAutoMap.innerHTML = `<i class="ri-magic-line"></i> Auto-mapear Coincidencias`;
        }
      }
    });
  }

  // 8. Auto-save Equivalences on input change
  document.querySelectorAll('.eq-mapping-input').forEach(input => {
    input.addEventListener('change', async (e) => {
      const platformSku = e.target.getAttribute('data-platform-sku');
      const platform = e.target.getAttribute('data-platform');
      const enteredValue = e.target.value.trim();

      e.target.style.borderColor = 'var(--color-primary)';

      try {
        if (!enteredValue) {
          const { error } = await supabase
            .from('sku_equivalences')
            .delete()
            .eq('comercio', commerce)
            .eq('platform', platform)
            .eq('platform_sku', platformSku);

          if (error) throw error;
          e.target.style.borderColor = 'var(--color-success)';
          renderCatalog();
        } else {
          const masterSkus = window.currentMasterProducts.map(p => p.sku);
          if (!masterSkus.includes(enteredValue)) {
            e.target.style.borderColor = 'var(--color-danger)';
            alert(`El SKU "${enteredValue}" no existe en el catálogo master. Crea el producto master primero o selecciona uno válido.`);
            e.target.value = '';
            return;
          }

          const { error } = await supabase
            .from('sku_equivalences')
            .upsert({
              comercio: commerce,
              platform: platform,
              platform_sku: platformSku,
              master_sku: enteredValue
            }, { onConflict: 'comercio,platform,platform_sku' });

          if (error) throw error;
          e.target.style.borderColor = 'var(--color-success)';
          renderCatalog();
        }
      } catch (err) {
        e.target.style.borderColor = 'var(--color-danger)';
        alert('Error al guardar equivalencia: ' + err.message);
      }
    });
  });

  // 2. Buscador en la matriz
  const searchInput = document.getElementById('eq-matrix-search');
  if (searchInput) {
    const newSearchInput = searchInput.cloneNode(true);
    searchInput.parentNode.replaceChild(newSearchInput, searchInput);
    newSearchInput.addEventListener('input', (e) => {
      const term = e.target.value.toLowerCase().trim();
      if (!window.currentProductsForMatrix) return;

      const filteredProducts = window.currentProductsForMatrix.filter(p => 
        (p.name && p.name.toLowerCase().includes(term)) || 
        (p.sku && p.sku.toLowerCase().includes(term))
      );

      renderMatrixRows(filteredProducts, window.currentSecondaryPlatforms, window.currentMappingsMap);
    });
  }

  // 3. Botón de validación de consistencia
  const btnValidate = document.getElementById('btn-run-consistency-check');
  if (btnValidate) {
    const newBtn = btnValidate.cloneNode(true);
    btnValidate.parentNode.replaceChild(newBtn, btnValidate);
    newBtn.addEventListener('click', async () => {
      const resultsDiv = document.getElementById('eq-consistency-results');
      if (!resultsDiv) return;

      resultsDiv.innerHTML = `<span style="color: var(--color-primary);"><i class="ri-loader-4-line ri-spin"></i> Analizando integraciones activas...</span>`;
      
      try {
        const commerce = window.activeIntegrationCommerce || (currentCompany ? currentCompany.split(',')[0].trim() : '');

        // También podemos obtener productos de 'products' que no tienen 'shopify_product_id' o que pertenecen a las secundarias
        const { data: allProducts, error: prodErr } = await supabase
          .from('products')
          .select('sku, name, raw_shopify_data')
          .eq('comercio', commerce);

        if (prodErr) throw prodErr;

        // Comprobemos si hay inconsistencias.
        const { data: integrations } = await supabase
          .from('merchant_integrations')
          .select('platform, is_main')
          .eq('comercio', commerce)
          .eq('is_main', true)
          .maybeSingle();

        const mainPlatform = integrations ? integrations.platform : null;

        if (!mainPlatform) {
          resultsDiv.innerHTML = `<span style="color: var(--color-warning);"><i class="ri-alert-line"></i> Debe definir una plataforma principal para realizar la validación.</span>`;
          return;
        }

        // Agrupar por SKU y ver si hay duplicados o inconsistencias
        const skuGroups = {};
        allProducts.forEach(p => {
          if (p.sku) {
            if (!skuGroups[p.sku]) skuGroups[p.sku] = [];
            skuGroups[p.sku].push(p.name);
          }
        });

        const inconsistencies = [];
        for (const [sku, names] of Object.entries(skuGroups)) {
          if (names.length > 1) {
            inconsistencies.push({
              sku,
              issue: 'Duplicado en catálogo',
              detail: `Existen ${names.length} variantes/productos con este mismo SKU en el systema WMS: "${names.join(', ')}"`
            });
          }
        }

        // Buscar si hay SKUs mapeados que no existen en productos
        const { data: currentMappings } = await supabase
          .from('sku_equivalences')
          .select('platform_sku, master_sku, platform')
          .eq('comercio', commerce);

        if (currentMappings) {
          const wmsSkus = new Set(allProducts.map(p => p.sku));
          currentMappings.forEach(m => {
            if (!wmsSkus.has(m.master_sku)) {
              inconsistencies.push({
                sku: m.master_sku,
                issue: 'SKU Master huérfano',
                detail: `La equivalencia para la plataforma ${m.platform} (SKU: ${m.platform_sku}) apunta a un SKU Master que no existe en el catálogo.`
              });
            }
          });
        }

        if (inconsistencies.length === 0) {
          resultsDiv.innerHTML = `<div style="color: #10b981; display:flex; align-items:center; gap:0.5rem; font-weight:600;"><i class="ri-checkbox-circle-line" style="font-size:1.25rem;"></i> ¡Todos los SKUs analizados están limpios y consistentes!</div>`;
        } else {
          resultsDiv.innerHTML = `
            <div style="color: var(--color-danger); font-weight:600; margin-bottom: 0.5rem;"><i class="ri-close-circle-line"></i> Se encontraron ${inconsistencies.length} inconsistencias:</div>
            <ul style="padding-left: 1.25rem; margin: 0; display:flex; flex-direction:column; gap:0.5rem;">
              ${inconsistencies.map(inc => `
                <li>
                  <strong style="font-family:monospace; color: var(--color-text-main);">${inc.sku}</strong>: 
                  <span style="color: var(--color-danger);">${inc.issue}</span> - <span style="color: var(--color-text-muted); font-size:0.85rem;">${inc.detail}</span>
                </li>
              `).join('')}
            </ul>
          `;
        }

      } catch (err) {
        console.error(err);
        resultsDiv.innerHTML = `<span style="color: var(--color-danger);"><i class="ri-error-warning-line"></i> Error al realizar validación: ${err.message}</span>`;
      }
    });
  }

  // 4. Configurar importación de Excel con Vista Previa
  const importInput = document.getElementById('eq-matrix-import-excel');
  if (importInput) {
    const newImportInput = importInput.cloneNode(true);
    importInput.parentNode.replaceChild(newImportInput, importInput);
    newImportInput.addEventListener('change', (e) => {
      const file = e.target.files[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = async (evt) => {
        try {
          const data = new Uint8Array(evt.target.result);
          const workbook = XLSX.read(data, { type: 'array' });
          const firstSheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[firstSheetName];
          const rows = XLSX.utils.sheet_to_json(worksheet);

          if (rows.length === 0) {
            alert('El archivo Excel está vacío.');
            return;
          }

          // Identificar columnas
          const sample = rows[0];
          let colPlatform = '';
          let colPlatformSku = '';
          let colMasterSku = '';

          for (const key of Object.keys(sample)) {
            const lower = key.toLowerCase().trim();
            if (lower === 'plataforma' || lower === 'platform') colPlatform = key;
            else if (lower === 'sku plataforma' || lower === 'platform_sku' || lower === 'sku_plataforma' || lower === 'sku externo') colPlatformSku = key;
            else if (lower === 'sku master' || lower === 'master_sku' || lower === 'sku_master' || lower === 'sku wms' || lower === 'sku maestro') colMasterSku = key;
          }

          if (!colPlatformSku || !colMasterSku) {
            alert('Error: Columnas no encontradas. Asegúrate de que el archivo tenga "SKU Plataforma" y "SKU Master" como columnas.');
            return;
          }

          const commerce = window.activeIntegrationCommerce || (currentCompany ? currentCompany.split(',')[0].trim() : '');

          // Obtener lista de SKUs válidos del catálogo para validar
          const { data: validProducts } = await supabase
            .from('products')
            .select('sku')
            .eq('comercio', commerce);
          
          const validSkus = new Set((validProducts || []).map(p => p.sku));

          const previewData = [];
          const allowedPlatforms = ['Todas', 'Shopify', 'MercadoLibre', 'Falabella', 'Paris', 'WooCommerce', 'Jumpseller', 'Walmart'];

          rows.forEach((r) => {
            let platformVal = colPlatform ? r[colPlatform] : 'Todas';
            if (platformVal) {
              platformVal = platformVal.toString().trim();
              const matched = allowedPlatforms.find(ap => ap.toLowerCase() === platformVal.toLowerCase());
              platformVal = matched || 'Todas';
            } else {
              platformVal = 'Todas';
            }

            const platformSkuVal = r[colPlatformSku] ? r[colPlatformSku].toString().trim().replace(/\s+/g, '') : '';
            const masterSkuVal = r[colMasterSku] ? r[colMasterSku].toString().trim() : '';

            let status = 'Válido';
            let statusColor = '#10b981';
            let isValid = true;

            if (!platformSkuVal || !masterSkuVal) {
              status = 'Faltan datos (SKU)';
              statusColor = '#f59e0b';
              isValid = false;
            } else if (!validSkus.has(masterSkuVal)) {
              status = 'SKU Master no existe en Catálogo WMS';
              statusColor = '#ef4444';
              isValid = false;
            }

            previewData.push({
              platform: platformVal,
              platform_sku: platformSkuVal,
              master_sku: masterSkuVal,
              status,
              statusColor,
              isValid
            });
          });

          // Mostrar la modal de vista previa
          showImportPreviewModal(previewData);

        } catch (error) {
          console.error(error);
          alert('Error al leer el archivo Excel: ' + error.message);
        }
      };
      reader.readAsArrayBuffer(file);
    });
  }

  // 6.5. Trigger file input for initial stock import
  const btnTriggerImportStock = document.getElementById('btn-trigger-import-stock');
  if (btnTriggerImportStock) {
    btnTriggerImportStock.addEventListener('click', () => {
      const activeFileInput = document.getElementById('catalog-import-stock-excel');
      if (activeFileInput) activeFileInput.click();
    });
  }

  // Descargar plantilla de ejemplo para importación de stock inicial
  const btnDownloadStockTemplate = document.getElementById('btn-download-stock-template');
  if (btnDownloadStockTemplate) {
    btnDownloadStockTemplate.addEventListener('click', () => {
      const headers = [['SKU', 'Stock Inicial']];
      const sampleData = [
        ['PROD-001', '100'],
        ['PROD-002', '50'],
        ['PROD-003', '0']
      ];
      const wsData = headers.concat(sampleData);
      const wb = XLSX.utils.book_new();
      const ws = XLSX.utils.aoa_to_sheet(wsData);
      XLSX.utils.book_append_sheet(wb, ws, 'Stock Inicial');
      XLSX.writeFile(wb, 'plantilla_stock_inicial.xlsx');
    });
  }

  const fileImportStock = document.getElementById('catalog-import-stock-excel');
  if (fileImportStock) {
    const newFileInput = fileImportStock.cloneNode(true);
    fileImportStock.parentNode.replaceChild(newFileInput, fileImportStock);
    
    newFileInput.addEventListener('change', async (e) => {
      const file = e.target.files[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = async (evt) => {
        try {
          const data = new Uint8Array(evt.target.result);
          const workbook = XLSX.read(data, { type: 'array' });
          const worksheet = workbook.Sheets[workbook.SheetNames[0]];
          const excelRows = XLSX.utils.sheet_to_json(worksheet);

          if (excelRows.length === 0) {
            alert('El archivo Excel está vacío.');
            return;
          }

          // Identificar columnas
          const sample = excelRows[0];
          let colSku = '';
          let colStock = '';
          for (const key of Object.keys(sample)) {
            const lower = key.toLowerCase().trim();
            if (lower === 'sku' || lower === 'codigo' || lower === 'código') colSku = key;
            else if (lower === 'stock' || lower === 'stock_inicial' || lower === 'stock inicial' || lower === 'cantidad' || lower === 'initial_stock' || lower === 'cant') colStock = key;
          }

          if (!colSku || !colStock) {
            alert('Error: Columnas no encontradas. El archivo debe contener las columnas "SKU" y "Stock Inicial" (o "Stock").');
            return;
          }

          // Obtener la Bodega Central
          const { data: bodegaCentral } = await supabase
            .from('warehouses')
            .select('id')
            .ilike('name', '%Central%')
            .limit(1)
            .single();

          if (!bodegaCentral) {
            alert('Error: No se encontró la Bodega Central en el sistema.');
            return;
          }

          // Obtener todos los productos del comercio para mapeo y validación
          const { data: dbProducts } = await supabase
            .from('products')
            .select('id, sku, name')
            .eq('comercio', commerce);

          const productMap = {};
          if (dbProducts) {
            dbProducts.forEach(p => {
              productMap[p.sku.toLowerCase().trim()] = p;
            });
          }

          // Obtener todos los stocks iniciales anteriores
          const { data: dbMovements } = await supabase
            .from('movements')
            .select('product_id, quantity')
            .eq('reference_doc', 'Stock Inicial');

          const stockMap = {};
          if (dbMovements) {
            dbMovements.forEach(m => {
              stockMap[m.product_id] = m.quantity;
            });
          }

          // Construir filas para vista previa y validar
          const previewRows = [];
          for (const row of excelRows) {
            const skuVal = String(row[colSku] || '').trim();
            const stockValRaw = row[colStock];
            const stockVal = parseInt(stockValRaw, 10);

            const prod = productMap[skuVal.toLowerCase()];
            const oldStock = prod ? (stockMap[prod.id] || 0) : 0;

            let status = 'ok';
            let message = '';

            if (!skuVal) {
              status = 'error';
              message = 'Línea vacía o SKU ausente';
            } else if (!prod) {
              status = 'error';
              message = 'El SKU no existe en este comercio';
            } else if (isNaN(stockVal) || stockVal < 0 || stockVal !== Number(stockValRaw)) {
              status = 'error';
              message = 'Stock inválido (debe ser un número entero >= 0)';
            }

            previewRows.push({
              sku: skuVal || 'N/A',
              name: prod ? prod.name : null,
              oldValue: oldStock,
              newValue: isNaN(stockVal) ? (stockValRaw || '') : stockVal,
              status,
              message,
              prodId: prod ? prod.id : null,
              stockVal
            });
          }

          // Lanzar modal de vista previa
          window.showStockAndDimensionsPreviewModal({
            title: 'Vista Previa: Carga Masiva de Stock Inicial',
            headers: ['SKU', 'Nombre', 'S. Inicial Anterior', 'S. Inicial Nuevo', 'Estado', 'Detalle'],
            rows: previewRows,
            onConfirm: async (validRows) => {
              let updatedCount = 0;
              
              // Ejecutar en paralelo
              const updatePromises = validRows.map(async (r) => {
                const diff = r.stockVal - r.oldValue;

                // 1. inventory update/insert
                const { data: invRecord } = await supabase
                  .from('inventory')
                  .select('id, quantity')
                  .eq('product_id', r.prodId)
                  .eq('warehouse_id', bodegaCentral.id)
                  .maybeSingle();

                if (invRecord) {
                  const { error: invErr } = await supabase
                    .from('inventory')
                    .update({ quantity: Math.max(0, invRecord.quantity + diff) })
                    .eq('id', invRecord.id);
                  if (invErr) throw invErr;
                } else {
                  const { error: invErr } = await supabase
                    .from('inventory')
                    .insert([{
                      product_id: r.prodId,
                      warehouse_id: bodegaCentral.id,
                      quantity: r.stockVal
                    }]);
                  if (invErr) throw invErr;
                }

                // 2. movements update/insert
                const { data: movRecord } = await supabase
                  .from('movements')
                  .select('id')
                  .eq('product_id', r.prodId)
                  .eq('reference_doc', 'Stock Inicial')
                  .limit(1)
                  .maybeSingle();

                if (r.stockVal > 0) {
                  if (movRecord) {
                    const { error: movErr } = await supabase
                      .from('movements')
                      .update({ quantity: r.stockVal })
                      .eq('id', movRecord.id);
                    if (movErr) throw movErr;
                  } else {
                    const { error: movErr } = await supabase
                      .from('movements')
                      .insert([{
                        product_id: r.prodId,
                        warehouse_id: bodegaCentral.id,
                        type: 'in',
                        quantity: r.stockVal,
                        reference_doc: 'Stock Inicial'
                      }]);
                    if (movErr) throw movErr;
                  }
                } else {
                  if (movRecord) {
                    const { error: movErr } = await supabase
                      .from('movements')
                      .delete()
                      .eq('id', movRecord.id);
                    if (movErr) throw movErr;
                  }
                }

                updatedCount++;
              });

              await Promise.all(updatePromises);
              alert(`¡Éxito! Se actualizaron ${updatedCount} productos correctamente.`);
              renderCatalog();
            }
          });

        } catch (err) {
          console.error(err);
          alert('Error al importar la planilla: ' + err.message);
        }
      };
      reader.readAsArrayBuffer(file);
      e.target.value = '';
    });
  }

  // 6.7. Trigger file input for dimensions import
  const btnTriggerImportDimensions = document.getElementById('btn-trigger-import-dimensions');
  if (btnTriggerImportDimensions) {
    btnTriggerImportDimensions.addEventListener('click', () => {
      const activeFileInput = document.getElementById('catalog-import-dimensions-excel');
      if (activeFileInput) activeFileInput.click();
    });
  }

  // Descargar plantilla de ejemplo para importación de dimensiones
  const btnDownloadDimensionsTemplate = document.getElementById('btn-download-dimensions-template');
  if (btnDownloadDimensionsTemplate) {
    btnDownloadDimensionsTemplate.addEventListener('click', () => {
      const headers = [['SKU', 'Largo', 'Ancho', 'Alto']];
      const sampleData = [
        ['PROD-001', '30', '20', '15'],
        ['PROD-002', '12', '10', '8'],
        ['PROD-003', '50', '40', '30']
      ];
      const wsData = headers.concat(sampleData);
      const wb = XLSX.utils.book_new();
      const ws = XLSX.utils.aoa_to_sheet(wsData);
      XLSX.utils.book_append_sheet(wb, ws, 'Medidas');
      XLSX.writeFile(wb, 'plantilla_medidas.xlsx');
    });
  }

  const fileImportDimensions = document.getElementById('catalog-import-dimensions-excel');
  if (fileImportDimensions) {
    const newFileInput = fileImportDimensions.cloneNode(true);
    fileImportDimensions.parentNode.replaceChild(newFileInput, fileImportDimensions);
    
    newFileInput.addEventListener('change', async (e) => {
      const file = e.target.files[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = async (evt) => {
        try {
          const data = new Uint8Array(evt.target.result);
          const workbook = XLSX.read(data, { type: 'array' });
          const worksheet = workbook.Sheets[workbook.SheetNames[0]];
          const excelRows = XLSX.utils.sheet_to_json(worksheet);

          if (excelRows.length === 0) {
            alert('El archivo Excel está vacío.');
            return;
          }

          // Identificar columnas: sku, largo, ancho, alto
          const sample = excelRows[0];
          let colSku = '';
          let colLargo = '';
          let colAncho = '';
          let colAlto = '';

          for (const key of Object.keys(sample)) {
            const lower = key.toLowerCase().trim();
            if (lower === 'sku' || lower === 'codigo' || lower === 'código') colSku = key;
            else if (lower === 'largo' || lower === 'length' || lower === 'longitud') colLargo = key;
            else if (lower === 'ancho' || lower === 'width' || lower === 'anchura') colAncho = key;
            else if (lower === 'alto' || lower === 'height' || lower === 'altura') colAlto = key;
          }

          if (!colSku || !colLargo || !colAncho || !colAlto) {
            alert('Error: Columnas no encontradas. El archivo debe contener las columnas "SKU", "Largo", "Ancho" y "Alto".');
            return;
          }

          // Obtener todos los productos del comercio
          const { data: dbProducts } = await supabase
            .from('products')
            .select('id, sku, name, length, width, height')
            .eq('comercio', commerce);

          const productMap = {};
          if (dbProducts) {
            dbProducts.forEach(p => {
              productMap[p.sku.toLowerCase().trim()] = p;
            });
          }

          // Construir filas de vista previa
          const previewRows = [];
          for (const row of excelRows) {
            const skuVal = String(row[colSku] || '').trim();
            const largoRaw = row[colLargo];
            const anchoRaw = row[colAncho];
            const altoRaw = row[colAlto];

            const largoVal = parseInt(largoRaw, 10);
            const anchoVal = parseInt(anchoRaw, 10);
            const altoVal = parseInt(altoRaw, 10);

            const prod = productMap[skuVal.toLowerCase()];
            const oldDims = prod ? `${prod.length || 0}x${prod.width || 0}x${prod.height || 0} cm` : '0x0x0 cm';

            let status = 'ok';
            let message = '';

            if (!skuVal) {
              status = 'error';
              message = 'Línea vacía o SKU ausente';
            } else if (!prod) {
              status = 'error';
              message = 'El SKU no existe en este comercio';
            } else if (
              isNaN(largoVal) || largoVal <= 0 || largoVal !== Number(largoRaw) ||
              isNaN(anchoVal) || anchoVal <= 0 || anchoVal !== Number(anchoRaw) ||
              isNaN(altoVal) || altoVal <= 0 || altoVal !== Number(altoRaw)
            ) {
              status = 'error';
              message = 'Medidas inválidas (deben ser enteros mayores a 0, sin decimales)';
            }

            previewRows.push({
              sku: skuVal || 'N/A',
              name: prod ? prod.name : null,
              oldValue: oldDims,
              newValue: status === 'ok' ? `${largoVal}x${anchoVal}x${altoVal} cm` : `${largoRaw || ''}x${anchoRaw || ''}x${altoRaw || ''} cm`,
              status,
              message,
              prodId: prod ? prod.id : null,
              length: largoVal,
              width: anchoVal,
              height: altoVal
            });
          }

          // Lanzar modal
          window.showStockAndDimensionsPreviewModal({
            title: 'Vista Previa: Carga Masiva de Medidas (Largo, Ancho, Alto)',
            headers: ['SKU', 'Nombre', 'Medidas Actuales', 'Medidas Nuevas', 'Estado', 'Detalle'],
            rows: previewRows,
            onConfirm: async (validRows) => {
              let updatedCount = 0;
              const updatePromises = validRows.map(async (r) => {
                const calculatedVol = (r.length && r.width && r.height) ? window.roundUpVolume((r.length * r.width * r.height) / 1000000) : null;
                const { error } = await supabase
                  .from('products')
                  .update({
                    length: r.length,
                    width: r.width,
                    height: r.height,
                    largo: r.length,
                    ancho: r.width,
                    alto: r.height,
                    volumen: calculatedVol
                  })
                  .eq('id', r.prodId);

                if (error) throw error;
                updatedCount++;
              });

              await Promise.all(updatePromises);
              alert(`¡Éxito! Se actualizaron las dimensiones de ${updatedCount} productos correctamente.`);
              renderCatalog();
            }
          });

        } catch (err) {
          console.error(err);
          alert('Error al importar medidas: ' + err.message);
        }
      };
      reader.readAsArrayBuffer(file);
      e.target.value = '';
    });
  }

  // 6.7.2. Trigger file input for volumes import
  const btnTriggerImportVolumes = document.getElementById('btn-trigger-import-volumes');
  if (btnTriggerImportVolumes) {
    btnTriggerImportVolumes.addEventListener('click', () => {
      const activeFileInput = document.getElementById('catalog-import-volumes-excel');
      if (activeFileInput) activeFileInput.click();
    });
  }

  // Descargar plantilla de ejemplo para importación de volúmenes
  const btnDownloadVolumesTemplate = document.getElementById('btn-download-volumes-template');
  if (btnDownloadVolumesTemplate) {
    btnDownloadVolumesTemplate.addEventListener('click', () => {
      const headers = [['SKU', 'Volumen']];
      const sampleData = [
        ['PROD-001', '0.009'],
        ['PROD-002', '0.00096'],
        ['PROD-003', '0.06']
      ];
      const wsData = headers.concat(sampleData);
      const wb = XLSX.utils.book_new();
      const ws = XLSX.utils.aoa_to_sheet(wsData);
      XLSX.utils.book_append_sheet(wb, ws, 'Volumenes');
      XLSX.writeFile(wb, 'plantilla_volumenes.xlsx');
    });
  }

  const fileImportVolumes = document.getElementById('catalog-import-volumes-excel');
  if (fileImportVolumes) {
    const newFileInput = fileImportVolumes.cloneNode(true);
    fileImportVolumes.parentNode.replaceChild(newFileInput, fileImportVolumes);
    
    newFileInput.addEventListener('change', async (e) => {
      const file = e.target.files[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = async (evt) => {
        try {
          const data = new Uint8Array(evt.target.result);
          const workbook = XLSX.read(data, { type: 'array' });
          const worksheet = workbook.Sheets[workbook.SheetNames[0]];
          const excelRows = XLSX.utils.sheet_to_json(worksheet);

          if (excelRows.length === 0) {
            alert('El archivo Excel está vacío.');
            return;
          }

          // Identificar columnas: sku, volumen
          const sample = excelRows[0];
          let colSku = '';
          let colVolumen = '';

          for (const key of Object.keys(sample)) {
            const lower = key.toLowerCase().trim();
            if (lower === 'sku' || lower === 'codigo' || lower === 'código') colSku = key;
            else if (lower === 'volumen' || lower === 'volume' || lower === 'volumen_m3' || lower === 'vol' || lower === 'm3') colVolumen = key;
          }

          if (!colSku || !colVolumen) {
            alert('Error: Columnas no encontradas. El archivo debe contener las columnas "SKU" y "Volumen".');
            return;
          }

          // Obtener todos los productos del comercio
          const { data: dbProducts, error: dbErr } = await supabase
            .from('products')
            .select('id, sku, name, volumen')
            .eq('comercio', commerce);

          if (dbErr) {
            console.error('Error al consultar productos:', dbErr);
            alert(`Error de Base de Datos: ${dbErr.message}\n\nEs altamente probable que falte agregar la columna "volumen" a la tabla "products". Por favor ejecuta el script de migración SQL "supabase_schema_product_upload.sql" en el panel/SQL Editor de Supabase para agregar la columna y poder realizar esta carga.`);
            return;
          }

          const productMap = {};
          if (dbProducts) {
            dbProducts.forEach(p => {
              if (p.sku) {
                productMap[p.sku.toLowerCase().trim()] = p;
              }
            });
          }

          // Construir filas de vista previa
          const previewRows = [];
          for (const row of excelRows) {
            const skuVal = String(row[colSku] || '').trim();
            const volRaw = row[colVolumen];

            let volVal = parseFloat(String(volRaw || '').replace(',', '.'));

            const prod = productMap[skuVal.toLowerCase()];
            const oldVolText = prod ? `${(prod.volumen || 0).toFixed(5)} m³` : '0 m³';

            let status = 'ok';
            let message = '';

            if (!skuVal) {
              status = 'error';
              message = 'Línea vacía o SKU ausente';
            } else if (!prod) {
              status = 'error';
              message = 'El SKU no existe en este comercio';
            } else if (isNaN(volVal) || volVal <= 0) {
              status = 'error';
              message = 'Volumen inválido (debe ser un número mayor a 0)';
            }

            if (status === 'ok') {
              volVal = window.roundUpVolume(volVal);
            }

            previewRows.push({
              sku: skuVal || 'N/A',
              name: prod ? prod.name : null,
              oldValue: oldVolText,
              newValue: status === 'ok' ? `${volVal.toFixed(5)} m³` : `${volRaw || ''} m³`,
              status,
              message,
              prodId: prod ? prod.id : null,
              volumen: volVal
            });
          }

          // Lanzar modal
          window.showStockAndDimensionsPreviewModal({
            title: 'Vista Previa: Carga Masiva de Volúmenes (m³)',
            headers: ['SKU', 'Nombre', 'Volumen Actual', 'Volumen Nuevo', 'Estado', 'Detalle'],
            rows: previewRows,
            onConfirm: async (validRows) => {
              let updatedCount = 0;
              const updatePromises = validRows.map(async (r) => {
                const { error } = await supabase
                  .from('products')
                  .update({
                    volumen: r.volumen
                  })
                  .eq('id', r.prodId);

                if (error) throw error;
                updatedCount++;
              });

              try {
                await Promise.all(updatePromises);
                alert(`¡Éxito! Se actualizaron los volúmenes de ${updatedCount} productos correctamente.`);
                renderCatalog();
              } catch (err) {
                console.error(err);
                alert('Error al importar volúmenes: ' + err.message);
              }
            }
          });

        } catch (err) {
          console.error(err);
          alert('Error al importar volúmenes: ' + err.message);
        }
      };
      reader.readAsArrayBuffer(file);
      e.target.value = '';
    });
  }

  // 6.6. Toggle Quick Edit mode / Save Quick Changes
  const btnToggleQuickEdit = document.getElementById('btn-toggle-quick-edit');
  if (btnToggleQuickEdit) {
    btnToggleQuickEdit.addEventListener('click', async () => {
      if (!window.catalogQuickEditMode) {
        // Habilitar edición rápida
        window.catalogQuickEditMode = true;
        // Re-renderizar la vista para que muestre los inputs
        renderMasterCatalogRows(window.currentMasterProducts);
        
        btnToggleQuickEdit.style.backgroundColor = 'var(--color-success)';
        btnToggleQuickEdit.style.color = 'white';
        btnToggleQuickEdit.style.borderColor = 'var(--color-success)';
        btnToggleQuickEdit.innerHTML = `<i class="ri-save-line"></i> Guardar Cambios Rápidos`;
      } else {
        // Guardar cambios
        const stockInputs = document.querySelectorAll('.quick-edit-stock');
        const changes = [];

        stockInputs.forEach(input => {
          const prodId = input.getAttribute('data-id');
          const oldStock = parseInt(input.getAttribute('data-old') || '0', 10);
          const newStock = parseInt(input.value || '0', 10);

          const lenInput = document.querySelector(`.quick-edit-length[data-id="${prodId}"]`);
          const widInput = document.querySelector(`.quick-edit-width[data-id="${prodId}"]`);
          const heiInput = document.querySelector(`.quick-edit-height[data-id="${prodId}"]`);

          const oldLength = lenInput ? parseFloat(lenInput.getAttribute('data-old') || '0') : 0;
          const newLength = lenInput ? parseFloat(lenInput.value || '0') : 0;

          const oldWidth = widInput ? parseFloat(widInput.getAttribute('data-old') || '0') : 0;
          const newWidth = widInput ? parseFloat(widInput.value || '0') : 0;

          const oldHeight = heiInput ? parseFloat(heiInput.getAttribute('data-old') || '0') : 0;
          const newHeight = heiInput ? parseFloat(heiInput.value || '0') : 0;

          const volInput = document.querySelector(`.quick-edit-volumen[data-id="${prodId}"]`);
          const oldVol = volInput && volInput.getAttribute('data-old') ? window.roundUpVolume(parseFloat(volInput.getAttribute('data-old'))) : null;
          const newVol = volInput && volInput.value ? window.roundUpVolume(parseFloat(volInput.value)) : null;

          if (oldStock !== newStock || oldLength !== newLength || oldWidth !== newWidth || oldHeight !== newHeight || oldVol !== newVol) {
            changes.push({
              prodId,
              oldStock,
              newStock,
              oldLength,
              newLength,
              oldWidth,
              newWidth,
              oldHeight,
              newHeight,
              oldVol,
              newVol
            });
          }
        });

        if (changes.length === 0) {
          // No hay cambios, desactivar edición rápida
          window.catalogQuickEditMode = false;
          renderCatalog();
          return;
        }

        if (!confirm(`¿Estás seguro que deseas aplicar los cambios a los ${changes.length} productos modificados?`)) {
          return;
        }

        btnToggleQuickEdit.disabled = true;
        btnToggleQuickEdit.innerHTML = `<i class="ri-loader-4-line ri-spin"></i> Guardando...`;

        try {
          // Obtener la Bodega Central
          const { data: bodegaCentral } = await supabase
            .from('warehouses')
            .select('id')
            .ilike('name', '%Central%')
            .limit(1)
            .single();

          if (!bodegaCentral) {
            throw new Error('No se encontró la Bodega Central en el sistema.');
          }

          // Ejecutar actualizaciones en paralelo
          const updatePromises = changes.map(async (ch) => {
            // 1. Actualizar dimensiones y volumen en products
            const { error: prodErr } = await supabase
              .from('products')
              .update({
                length: ch.newLength || null,
                width: ch.newWidth || null,
                height: ch.newHeight || null,
                largo: ch.newLength || null,
                ancho: ch.newWidth || null,
                alto: ch.newHeight || null,
                volumen: ch.newVol !== null && ch.newVol !== undefined ? ch.newVol : null
              })
              .eq('id', ch.prodId);

            if (prodErr) throw prodErr;

            // 2. Si el stock inicial cambió, actualizar inventario y movimiento histórico
            if (ch.oldStock !== ch.newStock) {
              const diff = ch.newStock - ch.oldStock;

              // Actualizar o insertar inventario en Bodega Central
              const { data: invRecord } = await supabase
                .from('inventory')
                .select('id, quantity')
                .eq('product_id', ch.prodId)
                .eq('warehouse_id', bodegaCentral.id)
                .maybeSingle();

              if (invRecord) {
                const { error: invErr } = await supabase
                  .from('inventory')
                  .update({ quantity: Math.max(0, invRecord.quantity + diff) })
                  .eq('id', invRecord.id);
                if (invErr) throw invErr;
              } else {
                const { error: invErr } = await supabase
                  .from('inventory')
                  .insert([{
                    product_id: ch.prodId,
                    warehouse_id: bodegaCentral.id,
                    quantity: ch.newStock
                  }]);
                if (invErr) throw invErr;
              }

              // Actualizar o insertar movimiento de "Stock Inicial"
              const { data: movRecord } = await supabase
                .from('movements')
                .select('id')
                .eq('product_id', ch.prodId)
                .eq('reference_doc', 'Stock Inicial')
                .limit(1)
                .maybeSingle();

              if (ch.newStock > 0) {
                if (movRecord) {
                  const { error: movErr } = await supabase
                    .from('movements')
                    .update({ quantity: ch.newStock })
                    .eq('id', movRecord.id);
                  if (movErr) throw movErr;
                } else {
                  const { error: movErr } = await supabase
                    .from('movements')
                    .insert([{
                      product_id: ch.prodId,
                      warehouse_id: bodegaCentral.id,
                      type: 'in',
                      quantity: ch.newStock,
                      reference_doc: 'Stock Inicial'
                    }]);
                  if (movErr) throw movErr;
                }
              } else {
                if (movRecord) {
                  const { error: movErr } = await supabase
                    .from('movements')
                    .delete()
                    .eq('id', movRecord.id);
                  if (movErr) throw movErr;
                }
              }
            }
          });

          await Promise.all(updatePromises);
          alert('¡Cambios rápidos guardados exitosamente!');
        } catch (err) {
          console.error(err);
          alert('Error al guardar cambios rápidos: ' + err.message);
        } finally {
          window.catalogQuickEditMode = false;
          renderCatalog();
        }
      }
    });
  }

  // Real-time calculation and totals update for quick-edit mode
  const masterTbody = document.getElementById('catalog-master-tbody');
  if (masterTbody) {
    masterTbody.addEventListener('input', (e) => {
      if (e.target.classList.contains('quick-edit-length') || 
          e.target.classList.contains('quick-edit-width') || 
          e.target.classList.contains('quick-edit-height')) {
        const prodId = e.target.getAttribute('data-id');
        const lenVal = parseFloat(document.querySelector(`.quick-edit-length[data-id="${prodId}"]`)?.value) || 0;
        const widVal = parseFloat(document.querySelector(`.quick-edit-width[data-id="${prodId}"]`)?.value) || 0;
        const heiVal = parseFloat(document.querySelector(`.quick-edit-height[data-id="${prodId}"]`)?.value) || 0;
        const volInput = document.querySelector(`.quick-edit-volumen[data-id="${prodId}"]`);
        if (volInput) {
          if (lenVal > 0 && widVal > 0 && heiVal > 0) {
            const calculated = (lenVal * widVal * heiVal) / 1000000;
            volInput.value = window.roundUpVolume(calculated).toFixed(5);
          }
        }
        
        // Also update total volume display
        const stockVal = parseInt(document.querySelector(`.quick-edit-stock[data-id="${prodId}"]`)?.value) || 0;
        const volVal = parseFloat(volInput?.value) || 0;
        const totalDisplay = document.querySelector(`.quick-edit-total-vol-display[data-id="${prodId}"]`);
        if (totalDisplay) {
          totalDisplay.textContent = `Total: ${(volVal * stockVal).toFixed(5)} m³`;
        }
      }

      if (e.target.classList.contains('quick-edit-stock') || e.target.classList.contains('quick-edit-volumen')) {
        const prodId = e.target.getAttribute('data-id');
        const stockVal = parseInt(document.querySelector(`.quick-edit-stock[data-id="${prodId}"]`)?.value) || 0;
        const volVal = parseFloat(document.querySelector(`.quick-edit-volumen[data-id="${prodId}"]`)?.value) || 0;
        const totalDisplay = document.querySelector(`.quick-edit-total-vol-display[data-id="${prodId}"]`);
        if (totalDisplay) {
          totalDisplay.textContent = `Total: ${(volVal * stockVal).toFixed(5)} m³`;
        }
      }
    });
  }

  // Manejo de ordenación por cabeceras de tabla
  if (!window.catalogSortListenerAdded) {
    window.catalogSortListenerAdded = true;
    document.addEventListener('click', (e) => {
      const header = e.target.closest('.sortable-header');
      if (header) {
        const col = header.getAttribute('data-sort');
        if (window.catalogSortCol === col) {
          window.catalogSortAsc = !window.catalogSortAsc;
        } else {
          window.catalogSortCol = col;
          window.catalogSortAsc = true;
        }
        renderMasterCatalogRows(window.currentMasterProducts || []);
      }
    });
  }
}

function showImportPreviewModal(previewData) {
  let modal = document.getElementById('modal-eq-preview');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'modal-eq-preview';
    modal.className = 'modal-overlay';
    document.body.appendChild(modal);
  }

  modal.innerHTML = `
    <div class="modal-content" style="max-width: 850px; width: 95%; max-height: 90vh; display: flex; flex-direction: column; padding: 0; background: var(--color-surface); border-radius: var(--radius-lg); box-shadow: var(--shadow-xl);">
      <div class="modal-header" style="padding: 1.25rem 1.5rem; border-bottom: 1px solid var(--color-border); display: flex; justify-content: space-between; align-items: center; background-color: var(--color-bg); border-radius: var(--radius-lg) var(--radius-lg) 0 0;">
        <h3 style="margin: 0; font-size: 1.25rem; font-weight: 700; color: var(--color-text-main);">
          <i class="ri-file-excel-2-line" style="color: #10b981; margin-right: 0.5rem;"></i> Vista Previa de Importación
        </h3>
        <button class="modal-close" onclick="document.getElementById('modal-eq-preview').classList.remove('active')" style="background:none; border:none; font-size: 1.5rem; cursor:pointer; color: var(--color-text-muted);">&times;</button>
      </div>
      <div class="modal-body" style="flex: 1; padding: 1.5rem; overflow-y: auto;">
        <p style="margin-top: 0; margin-bottom: 1rem; font-size: 0.9rem; color: var(--color-text-muted);">
          Se procesaron <strong>${previewData.length}</strong> registros de tu planilla. Revisa el estado antes de confirmar.
        </p>
        <table class="data-table" style="width: 100%; border-collapse: collapse; text-align: left;">
          <thead>
            <tr style="border-bottom: 1px solid var(--color-border); background: var(--color-bg);">
              <th style="padding: 0.75rem; font-size: 0.85rem; color: var(--color-text-main);">Plataforma</th>
              <th style="padding: 0.75rem; font-size: 0.85rem; color: var(--color-text-main);">SKU Plataforma</th>
              <th style="padding: 0.75rem; font-size: 0.85rem; color: var(--color-text-main);">SKU Master</th>
              <th style="padding: 0.75rem; font-size: 0.85rem; color: var(--color-text-main);">Estado / Diagnóstico</th>
            </tr>
          </thead>
          <tbody>
            ${previewData.map(row => `
              <tr style="border-bottom: 1px solid var(--color-border);">
                <td style="padding: 0.75rem; font-size: 0.875rem;">${row.platform}</td>
                <td style="padding: 0.75rem; font-family: monospace; font-size: 0.875rem;">${row.platform_sku || 'N/A'}</td>
                <td style="padding: 0.75rem; font-family: monospace; font-size: 0.875rem; font-weight: 600; color: var(--color-primary);">${row.master_sku || 'N/A'}</td>
                <td style="padding: 0.75rem; font-size: 0.875rem; font-weight: 500; color: ${row.statusColor};">
                  ${row.status === 'Válido' ? '<i class="ri-checkbox-circle-line"></i> Válido' : `<i class="ri-error-warning-line"></i> ${row.status}`}
                </td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>
      <div class="modal-footer" style="padding: 1.25rem 1.5rem; border-top: 1px solid var(--color-border); display: flex; justify-content: flex-end; gap: 1rem; background-color: var(--color-bg); border-radius: 0 0 var(--radius-lg) var(--radius-lg);">
        <button class="btn btn-outline" onclick="document.getElementById('modal-eq-preview').classList.remove('active')" style="margin:0;">Cancelar</button>
        <button id="btn-confirm-eq-import" class="btn btn-primary" style="margin:0;" ${previewData.some(r => r.isValid) ? '' : 'disabled'}>
          Confirmar e Importar (${previewData.filter(r => r.isValid).length} válidos)
        </button>
      </div>
    </div>
  `;

  modal.classList.add('active');

  const btnConfirm = document.getElementById('btn-confirm-eq-import');
  if (btnConfirm) {
    btnConfirm.addEventListener('click', async () => {
      btnConfirm.disabled = true;
      btnConfirm.innerHTML = `<i class="ri-loader-4-line ri-spin"></i> Importando...`;

      const validRows = previewData.filter(r => r.isValid).map(r => ({
        comercio: window.activeIntegrationCommerce || (currentCompany ? currentCompany.split(',')[0].trim() : ''),
        platform: r.platform,
        platform_sku: r.platform_sku,
        master_sku: r.master_sku
      }));

      try {
        const { error } = await supabase
          .from('sku_equivalences')
          .upsert(validRows, { onConflict: 'comercio,platform,platform_sku' });

        if (error) throw error;

        alert(`Se han importado exitosamente ${validRows.length} equivalencias.`);
        modal.classList.remove('active');
        renderCatalog();
      } catch (err) {
        alert('Error al realizar la importación masiva: ' + err.message);
        btnConfirm.disabled = false;
        btnConfirm.innerHTML = `Confirmar e Importar`;
      }
    });
  }
}

window.getDeadlineBadgeHtml = function(fechaLimiteStr, pagoStatus) {
  if (!fechaLimiteStr) return '';
  if (pagoStatus === 'Recibido' || pagoStatus === 'aprobado' || pagoStatus === 'Sin movimientos') return '';
  
  const limitDate = new Date(fechaLimiteStr + 'T00:00:00');
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  limitDate.setHours(0, 0, 0, 0);
  
  const diffTime = limitDate.getTime() - today.getTime();
  const diffDays = Math.round(diffTime / (1000 * 60 * 60 * 24));
  
  if (diffDays < 0) {
    const days = Math.abs(diffDays);
    return `<div class="deadline-badge deadline-overdue" style="margin-top: 0.35rem; font-size: 0.7rem; font-weight: 700; color: var(--color-danger); display: inline-flex; align-items: center; gap: 0.25rem; background: rgba(239, 68, 68, 0.1); padding: 0.15rem 0.4rem; border-radius: 4px;">
      <i class="ri-error-warning-line"></i> Venció hace ${days} ${days === 1 ? 'día' : 'días'}
    </div>`;
  } else if (diffDays === 0) {
    return `<div class="deadline-badge deadline-today" style="margin-top: 0.35rem; font-size: 0.7rem; font-weight: 700; color: #d97706; display: inline-flex; align-items: center; gap: 0.25rem; background: rgba(217, 119, 6, 0.1); padding: 0.15rem 0.4rem; border-radius: 4px;">
      <i class="ri-time-line"></i> Vence hoy
    </div>`;
  } else {
    return `<div class="deadline-badge deadline-upcoming" style="margin-top: 0.35rem; font-size: 0.7rem; font-weight: 700; color: var(--color-primary); display: inline-flex; align-items: center; gap: 0.25rem; background: rgba(59, 130, 246, 0.1); padding: 0.15rem 0.4rem; border-radius: 4px;">
      <i class="ri-calendar-todo-line"></i> Vence en ${diffDays} ${diffDays === 1 ? 'día' : 'días'}
    </div>`;
  }
};

window.updateClientOrdersBulkSelection = function() {
  const checkboxes = document.querySelectorAll('.order-select-checkbox:checked');
  const bulkBar = document.getElementById('client-orders-bulk-actions');
  const countEl = document.getElementById('selected-orders-count');
  
  if (checkboxes.length > 0) {
    if (bulkBar) bulkBar.style.display = 'flex';
    if (countEl) countEl.textContent = checkboxes.length;
  } else {
    if (bulkBar) bulkBar.style.display = 'none';
  }
};

window.toggleSelectAllClientOrders = function(checked) {
  const checkboxes = document.querySelectorAll('.order-select-checkbox');
  checkboxes.forEach(cb => cb.checked = checked);
  window.updateClientOrdersBulkSelection();
};

window.exportShopifyOrdersCsv = function(selectedOrderIds) {
  const allOrders = window.clientLoadedOrders || [];
  const selectedOrders = allOrders.filter(o => selectedOrderIds.includes(o.id));
  
  if (selectedOrders.length === 0) {
    alert("No hay pedidos seleccionados.");
    return;
  }
  
  // Ordenar de forma cronológica ascendente (el más antiguo primero)
  selectedOrders.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));
  
  const shopifyHeaders = [
    "Name", "Email", "Financial Status", "Paid at", "Fulfillment Status", "Fulfilled at", 
    "Accepts Marketing", "Currency", "Subtotal", "Shipping", "Taxes", "Total", 
    "Discount Code", "Discount Amount", "Shipping Method", "Created at", 
    "Lineitem quantity", "Lineitem name", "Lineitem price", "Lineitem compare at price", 
    "Lineitem sku", "Lineitem requires shipping", "Lineitem taxable", "Lineitem fulfillment status", 
    "Billing Name", "Billing Street", "Billing Address1", "Billing Address2", "Billing Company", 
    "Billing City", "Billing Zip", "Billing Province", "Billing Country", "Billing Phone", 
    "Shipping Name", "Shipping Street", "Shipping Address1", "Shipping Address2", "Shipping Company", 
    "Shipping City", "Shipping Zip", "Shipping Province", "Shipping Country", "Shipping Phone", 
    "Notes", "Note Attributes", "Cancelled at", "Payment Method", "Payment Reference", 
    "Refunded Amount", "Vendor", "Outstanding Balance", "Employee", "Location", 
    "Device ID", "Id", "Tags", "Risk Level", "Source", "Lineitem discount", 
    "Tax 1 Name", "Tax 1 Value", "Tax 2 Name", "Tax 2 Value", "Tax 3 Name", "Tax 3 Value", 
    "Tax 4 Name", "Tax 4 Value", "Tax 5 Name", "Tax 5 Value", "Phone", "Receipt Number", 
    "Duties", "Billing Province Name", "Shipping Province Name", "Payment ID", 
    "Payment Terms Name", "Next Payment Due At", "Payment References"
  ];
  
  const csvRows = [];
  csvRows.push(shopifyHeaders.join(","));
  
  selectedOrders.forEach(order => {
    const raw = order.raw_shopify_data || {};
    
    // Determinar line items
    let lineItems = [];
    if (raw.line_items && raw.line_items.length > 0) {
      lineItems = raw.line_items;
    } else if (order.order_items && order.order_items.length > 0) {
      lineItems = order.order_items.map(oi => ({
        quantity: oi.quantity || 1,
        title: oi.products?.name || oi.item_name || "Producto sin nombre",
        price: order.total_value ? (Number(order.total_value) / order.order_items.length).toFixed(2) : "0.00",
        sku: oi.products?.sku || oi.sku || "",
        requires_shipping: true,
        taxable: true,
        fulfillment_status: order.estado_wms === 'Despachado' ? 'fulfilled' : null,
        vendor: "WMS STOCKA"
      }));
    } else {
      lineItems = [{
        quantity: order.cantidad || 1,
        title: order.item || "Producto sin nombre",
        price: order.total_value || "0.00",
        sku: order.sku || "",
        requires_shipping: true,
        taxable: true,
        fulfillment_status: order.estado_wms === 'Despachado' ? 'fulfilled' : null,
        vendor: "WMS STOCKA"
      }];
    }
    
    // Mapear shipping / billing details de raw o fallback de WMS
    const shippingName = raw.shipping_address ? `${raw.shipping_address.first_name || ''} ${raw.shipping_address.last_name || ''}`.trim() : (order.customer_name || "");
    const shippingAddr1 = raw.shipping_address?.address1 || (order.shipping_address || "");
    const shippingAddr2 = raw.shipping_address?.address2 || (order.shipping_complement || "");
    const shippingCompany = raw.shipping_address?.company || "";
    const shippingCity = raw.shipping_address?.city || (order.shipping_city || "");
    const shippingZip = raw.shipping_address?.zip || "";
    const shippingProvince = raw.shipping_address?.province_code || "";
    const shippingCountry = raw.shipping_address?.country_code || "";
    const shippingPhone = raw.shipping_address?.phone || (order.customer_phone || "");
    
    const billingName = raw.billing_address ? `${raw.billing_address.first_name || ''} ${raw.billing_address.last_name || ''}`.trim() : shippingName;
    const billingAddr1 = raw.billing_address?.address1 || shippingAddr1;
    const billingAddr2 = raw.billing_address?.address2 || shippingAddr2;
    const billingCompany = raw.billing_address?.company || shippingCompany;
    const billingCity = raw.billing_address?.city || shippingCity;
    const billingZip = raw.billing_address?.zip || shippingZip;
    const billingProvince = raw.billing_address?.province_code || shippingProvince;
    const billingCountry = raw.billing_address?.country_code || shippingCountry;
    const billingPhone = raw.billing_address?.phone || shippingPhone;
    
    const orderName = raw.name || order.external_order_number || `#${order.id.split('-')[0]}`;
    const email = raw.email || order.customer_email || "";
    const finStatus = raw.financial_status || (order.payment_status === 'PAID' ? 'paid' : 'pending');
    const fulfillStatus = raw.fulfillment_status || (order.estado_wms === 'Despachado' ? 'fulfilled' : '');
    const paidAt = raw.processed_at || order.created_at;
    const fulfilledAt = order.estado_wms === 'Despachado' ? order.created_at : '';
    const currency = raw.currency || "CLP";
    const subtotal = raw.subtotal_price || (Number(order.total_value) || 0).toFixed(2);
    const shipping = raw.total_shipping_price_set?.shop_money?.amount || "0.00";
    const taxes = raw.total_tax || "0.00";
    const total = raw.total_price || (Number(order.total_value) || 0).toFixed(2);
    const discountCode = raw.discount_codes?.map(dc => dc.code).join(", ") || "";
    const discountAmt = raw.total_discounts || "0.00";
    const shippingMethod = raw.shipping_lines?.map(sl => sl.title).join(", ") || order.shipping_method || "";
    const createdAt = raw.created_at || order.created_at;
    const note = raw.note || "";
    const tags = raw.tags || "";
    const paymentMethod = raw.gateway || "";
    
    lineItems.forEach((item, index) => {
      const rowData = {
        "Name": orderName,
        "Email": index === 0 ? email : "",
        "Financial Status": index === 0 ? finStatus : "",
        "Paid at": index === 0 ? paidAt : "",
        "Fulfillment Status": index === 0 ? fulfillStatus : "",
        "Fulfilled at": index === 0 ? fulfilledAt : "",
        "Accepts Marketing": index === 0 ? "yes" : "",
        "Currency": index === 0 ? currency : "",
        "Subtotal": index === 0 ? subtotal : "",
        "Shipping": index === 0 ? shipping : "",
        "Taxes": index === 0 ? taxes : "",
        "Total": index === 0 ? total : "",
        "Discount Code": index === 0 ? discountCode : "",
        "Discount Amount": index === 0 ? discountAmt : "",
        "Shipping Method": index === 0 ? shippingMethod : "",
        "Created at": index === 0 ? createdAt : "",
        "Lineitem quantity": item.quantity || 1,
        "Lineitem name": item.title || item.name || "",
        "Lineitem price": item.price || "0.00",
        "Lineitem compare at price": "",
        "Lineitem sku": item.sku || "",
        "Lineitem requires shipping": item.requires_shipping !== false ? "true" : "false",
        "Lineitem taxable": item.taxable !== false ? "true" : "false",
        "Lineitem fulfillment status": item.fulfillment_status || "",
        "Billing Name": index === 0 ? billingName : "",
        "Billing Street": index === 0 ? billingAddr1 : "",
        "Billing Address1": index === 0 ? billingAddr1 : "",
        "Billing Address2": index === 0 ? billingAddr2 : "",
        "Billing Company": index === 0 ? billingCompany : "",
        "Billing City": index === 0 ? billingCity : "",
        "Billing Zip": index === 0 ? billingZip : "",
        "Billing Province": index === 0 ? billingProvince : "",
        "Billing Country": index === 0 ? billingCountry : "",
        "Billing Phone": index === 0 ? billingPhone : "",
        "Shipping Name": index === 0 ? shippingName : "",
        "Shipping Street": index === 0 ? shippingAddr1 : "",
        "Shipping Address1": index === 0 ? shippingAddr1 : "",
        "Shipping Address2": index === 0 ? shippingAddr2 : "",
        "Shipping Company": index === 0 ? shippingCompany : "",
        "Shipping City": index === 0 ? shippingCity : "",
        "Shipping Zip": index === 0 ? shippingZip : "",
        "Shipping Province": index === 0 ? shippingProvince : "",
        "Shipping Country": index === 0 ? shippingCountry : "",
        "Shipping Phone": index === 0 ? shippingPhone : "",
        "Notes": index === 0 ? note : "",
        "Note Attributes": "",
        "Cancelled at": index === 0 ? (raw.cancelled_at || "") : "",
        "Payment Method": index === 0 ? paymentMethod : "",
        "Payment Reference": "",
        "Refunded Amount": "0.00",
        "Vendor": item.vendor || "",
        "Outstanding Balance": "0.00",
        "Employee": "",
        "Location": "",
        "Device ID": "",
        "Id": index === 0 ? (raw.id || "") : "",
        "Tags": index === 0 ? tags : "",
        "Risk Level": "low",
        "Source": index === 0 ? (raw.source_name || "web") : "",
        "Lineitem discount": "0.00",
        "Tax 1 Name": "",
        "Tax 1 Value": "",
        "Tax 2 Name": "",
        "Tax 2 Value": "",
        "Tax 3 Name": "",
        "Tax 3 Value": "",
        "Tax 4 Name": "",
        "Tax 4 Value": "",
        "Tax 5 Name": "",
        "Tax 5 Value": "",
        "Phone": index === 0 ? (raw.phone || "") : "",
        "Receipt Number": "",
        "Duties": "",
        "Billing Province Name": "",
        "Shipping Province Name": "",
        "Payment ID": "",
        "Payment Terms Name": "",
        "Next Payment Due At": "",
        "Payment References": ""
      };
      
      const csvRow = shopifyHeaders.map(h => {
        const val = rowData[h] !== undefined ? String(rowData[h]) : "";
        if (val.includes(",") || val.includes('"') || val.includes("\n")) {
          return `"${val.replace(/"/g, '""')}"`;
        }
        return val;
      }).join(",");
      csvRows.push(csvRow);
    });
  });
  
  const csvContent = "\ufeff" + csvRows.join("\n");
  const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `shopify_orders_export_${new Date().toISOString().slice(0,10)}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

window.markOrdersAsExported = async function(selectedOrderIds) {
  if (typeof userRole !== 'undefined' && userRole === 'observer') {
    alert('Acceso denegado: El rol de Observador no permite realizar esta acción.');
    return;
  }
  
  try {
    const { error } = await supabase
      .from('orders')
      .update({ shopify_exported: true })
      .in('id', selectedOrderIds);
      
    if (error) throw error;
    
    alert(`Se marcaron ${selectedOrderIds.length} pedidos como exportados.`);
    
    // Desmarcar cabecera general
    const selectAllCb = document.getElementById('select-all-client-orders');
    if (selectAllCb) selectAllCb.checked = false;
    
    renderOrders();
  } catch (err) {
    console.error(err);
    alert('Error al marcar pedidos como exportados: ' + err.message);
  }
};

window.loadClientExtraCharges = async function(periodId) {
  const tbody = document.getElementById('client-extra-charges-table-body');
  if (!tbody) return;

  try {
    const { data: { session } } = await supabase.auth.getSession();
    const userId = session?.user?.id;
    if (!userId) throw new Error("No hay sesión activa");

    const { data: profile } = await supabase
      .from('profiles')
      .select('comercio')
      .eq('id', userId)
      .single();

    let charges = [];
    if (profile && profile.comercio === 'all') {
      const { data, error: cErr } = await supabase
        .from('extra_billing_charges')
        .select('*')
        .order('fecha', { ascending: false });
      if (cErr) throw cErr;
      charges = data || [];
    } else {
      let companyList = [];
      if (profile && profile.comercio) {
        companyList = profile.comercio.split(',').map(c => c.trim()).filter(Boolean);
      }

      if (companyList.length === 0) {
        tbody.innerHTML = `
          <tr>
            <td colspan="6" class="text-center" style="padding: 2rem; color: var(--color-text-muted);">
              No tienes comercios asociados para ver cobros adicionales.
            </td>
          </tr>
        `;
        return;
      }

      const { data, error: cErr } = await supabase
        .from('extra_billing_charges')
        .select('*')
        .in('comercio', companyList)
        .order('fecha', { ascending: false });
      if (cErr) throw cErr;
      charges = data || [];
    }

    const { data: periods } = await supabase
      .from('billing_periods')
      .select('id, name');
    
    const periodsMap = {};
    if (periods) {
      periods.forEach(p => {
        periodsMap[p.id] = p.name;
      });
    }

    if (!charges || charges.length === 0) {
      tbody.innerHTML = `
        <tr>
          <td colspan="6" class="text-center" style="padding: 3rem; color: var(--color-text-muted);">
            No se registran cobros adicionales ni extraordinarios para tu comercio.
          </td>
        </tr>
      `;
      return;
    }

    tbody.innerHTML = charges.map(c => {
      const formattedDate = new Date(c.fecha + 'T00:00:00').toLocaleDateString();
      const statusClass = c.status === 'cobrado' ? 'status-active' : 'status-inactive';
      const statusText = c.status === 'cobrado' ? 'Cobrado' : 'Pendiente';
      const statusBadge = `<span class="client-badge ${statusClass}">${statusText}</span>`;
      const periodName = c.status === 'cobrado' ? (periodsMap[c.periodo_id] || 'No especificado') : '-';

      const ivaBadge = c.iva_tipo === 'iva_incluido'
        ? '<span style="font-size: 0.7rem; color: var(--color-success); font-weight: 600; display: block; opacity: 0.95; margin-top: 0.15rem;">IVA Incluido</span>'
        : '<span style="font-size: 0.7rem; color: var(--color-text-muted); font-weight: 600; display: block; margin-top: 0.15rem;">+ IVA (Neto)</span>';

      return `
        <tr>
          <td style="vertical-align: middle; color: var(--color-text-muted);">${formattedDate}</td>
          <td style="vertical-align: middle; font-weight: 600; color: var(--color-text-main);">${c.comercio}</td>
          <td style="vertical-align: middle;">${c.detalle}</td>
          <td style="vertical-align: middle; text-align: right; font-weight: 600; color: var(--color-text-main); line-height: 1.3;">
            <div>${window.formatCLP(c.monto)}</div>
            ${ivaBadge}
          </td>
          <td style="vertical-align: middle;">${statusBadge}</td>
          <td style="vertical-align: middle; color: var(--color-text-muted);">${periodName}</td>
        </tr>
      `;
    }).join('');

  } catch (err) {
    console.error('Error loading client extra charges:', err);
    tbody.innerHTML = `
      <tr>
        <td colspan="6" class="text-center" style="padding: 2rem; color: var(--color-danger);">
          Error al consultar cobros adicionales: ${err.message}
        </td>
      </tr>
    `;
  }
};

window.getClientObservationBtnHtml = function(r) {
  let colorStyle = 'color: var(--color-text-muted); border-color: var(--color-border);';
  let title = 'Solicitar Revisión / Apelación';
  let text = 'Solicitar Revisión';
  let icon = 'ri-chat-new-line';

  if (r.observation_status === 'pendiente') {
    colorStyle = 'color: #d97706; border-color: #d97706; background: rgba(217, 119, 6, 0.05);';
    title = 'Revisión Pendiente por Administración';
    text = 'Revisión Pendiente';
    icon = 'ri-discuss-line';
  } else if (r.observation_status === 'respondida') {
    colorStyle = 'color: var(--color-success); border-color: var(--color-success); background: rgba(16, 185, 129, 0.05);';
    title = 'Revisión Respondida por Administración';
    text = 'Revisión Respondida';
    icon = 'ri-chat-check-line';
  }

  return `
    <button class="btn btn-outline btn-sm" onclick="event.stopPropagation(); window.openClientBillingObservationModal('${r.id}')" style="padding: 0.25rem 0.5rem; font-size: 0.72rem; font-weight: 600; display: inline-flex; align-items: center; gap: 0.25rem; width: 100%; border-radius: 4px; ${colorStyle} height: auto; justify-content: center;" title="${title}">
      <i class="${icon}"></i> ${text}
    </button>
  `;
};

window.openClientBillingObservationModal = async function(recordId) {
  let modal = document.getElementById('modal-client-observation');
  if (modal) modal.remove();

  try {
    const { data: record, error } = await supabase
      .from('billing_records')
      .select('*')
      .eq('id', recordId)
      .single();

    if (error) throw error;
    if (!record) throw new Error("Registro no encontrado");

    const isPending = record.observation_status === 'pendiente';
    const hasResponse = record.admin_response && record.admin_response.trim() !== '';

    modal = document.createElement('div');
    modal.id = 'modal-client-observation';
    modal.className = 'modal-overlay active';
    modal.innerHTML = `
      <div class="modal-content" style="max-width: 500px; border-radius: 12px; overflow: hidden; box-shadow: var(--shadow-lg);">
        <div class="modal-header" style="background: var(--color-surface); padding: 1rem 1.5rem; border-bottom: 1px solid var(--color-border); display: flex; justify-content: space-between; align-items: center;">
          <h3 style="margin: 0; font-size: 1.1rem; color: var(--color-text-main); font-weight: 600; display: flex; align-items: center; gap: 0.5rem;">
            <i class="ri-chat-voice-line" style="color: var(--color-primary); font-size: 1.25rem;"></i>
            Revisión de Cobros - ${record.comercio}
          </h3>
          <button class="modal-close" onclick="document.getElementById('modal-client-observation').remove()" style="background: transparent; border: none; font-size: 1.25rem; color: var(--color-text-muted); cursor: pointer;">&times;</button>
        </div>
        
        <form id="form-client-observation">
          <div class="modal-body" style="padding: 1.5rem; background: var(--color-surface);">
            
            <div style="background: rgba(59, 130, 246, 0.05); border: 1px solid rgba(59, 130, 246, 0.2); padding: 0.85rem; border-radius: 8px; margin-bottom: 1.25rem; display: flex; gap: 0.5rem; align-items: flex-start;">
              <i class="ri-information-line" style="color: var(--color-primary); font-size: 1.2rem; margin-top: 0.1rem;"></i>
              <div style="font-size: 0.82rem; color: var(--color-text-muted); line-height: 1.4;">
                <strong>Nota aclaratoria:</strong> Las apelaciones o solicitudes de revisión serán evaluadas por administración. En caso de ser aprobadas, el ajuste correspondiente se verá reflejado en la facturación del **siguiente período**.
              </div>
            </div>

            <div class="form-group" style="margin-bottom: 1.25rem;">
              <label class="form-label" style="font-weight: 600; margin-bottom: 0.4rem; color: var(--color-text-main); font-size: 0.85rem;">Detalle de su apelación u observación:</label>
              <textarea id="obs-client-text" class="form-input" rows="4" placeholder="Indique claramente el cobro a revisar (Fulfillment o Envíame), el motivo de su discrepancia y cualquier detalle de respaldo..." required style="width: 100%; box-sizing: border-box; font-size: 0.85rem; padding: 0.5rem; line-height: 1.4; border-radius: 6px;" ${isPending ? 'disabled' : ''}>${record.client_observation || ''}</textarea>
            </div>

            ${hasResponse ? `
              <div class="form-group" style="margin-top: 1.25rem; padding-top: 1.25rem; border-top: 1px solid var(--color-border);">
                <label class="form-label" style="font-weight: 600; margin-bottom: 0.4rem; color: var(--color-success); font-size: 0.85rem; display: flex; align-items: center; gap: 0.25rem;">
                  <i class="ri-feedback-line"></i> Respuesta de Administración:
                </label>
                <div style="background: var(--color-bg); padding: 0.75rem 1rem; border-radius: 6px; border: 1px solid var(--color-border); font-size: 0.85rem; color: var(--color-text-main); line-height: 1.4; white-space: pre-wrap;">${record.admin_response}</div>
              </div>
            ` : ''}

            ${isPending ? `
              <div style="text-align: center; color: #d97706; font-size: 0.82rem; font-weight: 600; margin-top: 1rem; display: flex; align-items: center; justify-content: center; gap: 0.25rem;">
                <i class="ri-time-line"></i> Su solicitud está siendo evaluada por el equipo administrativo.
              </div>
            ` : ''}

          </div>
          <div class="modal-footer" style="padding: 1rem 1.5rem; border-top: 1px solid var(--color-border); background: var(--color-surface); display: flex; justify-content: flex-end; gap: 0.75rem;">
            <button type="button" class="btn btn-outline" onclick="document.getElementById('modal-client-observation').remove()" style="margin: 0; padding: 0.4rem 1rem; font-size: 0.85rem;">Cerrar</button>
            ${!isPending ? `
              <button type="submit" class="btn btn-primary" id="btn-submit-obs" style="margin: 0; padding: 0.4rem 1rem; font-size: 0.85rem;">
                <i class="ri-send-plane-line"></i> Enviar Solicitud
              </button>
            ` : ''}
          </div>
        </form>
      </div>
    `;

    document.body.appendChild(modal);

    const form = document.getElementById('form-client-observation');
    if (form) {
      form.addEventListener('submit', async (e) => {
        e.preventDefault();
        const btnSubmit = document.getElementById('btn-submit-obs');
        if (btnSubmit) {
          btnSubmit.disabled = true;
          btnSubmit.innerHTML = '<i class="ri-loader-4-line spin"></i> Enviando...';
        }

        const clientText = document.getElementById('obs-client-text').value.trim();

        try {
          const { error: updateErr } = await supabase
            .from('billing_records')
            .update({
              client_observation: clientText,
              observation_status: 'pendiente',
              observation_updated_at: new Date().toISOString()
            })
            .eq('id', recordId);

          if (updateErr) throw updateErr;

          modal.remove();
          alert('Su solicitud de revisión ha sido enviada exitosamente a administración.');
          
          if (typeof loadClientBillingData === 'function') {
            loadClientBillingData(window.currentClientSelectedPeriodId);
          }
        } catch (err) {
          console.error(err);
          alert('Error al enviar la observación: ' + err.message);
          if (btnSubmit) {
            btnSubmit.disabled = false;
            btnSubmit.innerHTML = '<i class="ri-send-plane-line"></i> Enviar Solicitud';
          }
        }
      });
    }

  } catch (err) {
    console.error(err);
    alert('Error al cargar la observación: ' + err.message);
  }
};

window.filterClientNewOrderProducts = function() {
  const searchInput = document.getElementById('order-product-search');
  const dropdownList = document.getElementById('order-product-dropdown-list');
  if (!dropdownList) return;

  const searchTerm = searchInput ? searchInput.value.toLowerCase().trim() : '';
  const products = window.tempClientProductsList || [];

  const filtered = products.filter(p => {
    const sku = (p.sku || '').toLowerCase();
    const name = (p.name || '').toLowerCase();
    return sku.includes(searchTerm) || name.includes(searchTerm);
  });

  if (filtered.length === 0) {
    dropdownList.innerHTML = `
      <div style="padding: 0.75rem; text-align: center; color: var(--color-text-muted); font-size: 0.85rem; font-style: italic;">
        No se encontraron productos
      </div>
    `;
    return;
  }

  let html = '';
  filtered.forEach(p => {
    const displayVal = `${p.sku} - ${p.name} (${window.formatCLP(p.price || 0)})`;
    html += `
      <div class="order-product-option" data-id="${p.id}" data-display="${displayVal}" style="padding: 0.5rem 0.75rem; cursor: pointer; font-size: 0.85rem; border-bottom: 1px solid var(--color-border); color: var(--color-text-main); transition: background-color 0.15s; display: flex; flex-direction: column; gap: 0.15rem;" onmouseover="this.style.backgroundColor='var(--color-bg)'" onmouseout="this.style.backgroundColor='transparent'">
        <span style="font-weight: 600; color: var(--color-primary);">${p.sku}</span>
        <span style="font-size: 0.8rem; color: var(--color-text-main); white-space: nowrap; overflow: hidden; text-overflow: ellipsis;">${p.name}</span>
        <span style="font-size: 0.75rem; color: var(--color-text-muted); font-weight: 500;">${window.formatCLP(p.price || 0)}</span>
      </div>
    `;
  });
  
  dropdownList.innerHTML = html;
};

window.addClientNewOrderItem = function() {
  const selectProd = document.getElementById('order-product'); // Hidden input
  const qtyInput = document.getElementById('order-qty');
  if (!selectProd || !qtyInput) return;

  const prodId = selectProd.value;
  const qty = parseInt(qtyInput.value, 10);

  if (!prodId) {
    alert('Por favor selecciona un producto escribiendo y eligiéndolo de la lista.');
    return;
  }
  if (isNaN(qty) || qty < 1) {
    alert('Cantidad inválida.');
    return;
  }

  const product = (window.tempClientProductsList || []).find(p => p.id === prodId);
  if (!product) {
    alert('Producto no encontrado.');
    return;
  }

  window.tempClientNewOrderItems = window.tempClientNewOrderItems || [];
  const existingIdx = window.tempClientNewOrderItems.findIndex(i => i.product_id === prodId);
  if (existingIdx !== -1) {
    window.tempClientNewOrderItems[existingIdx].quantity += qty;
  } else {
    window.tempClientNewOrderItems.push({
      product_id: prodId,
      sku: product.sku,
      name: product.name,
      price: product.price || 0,
      quantity: qty
    });
  }

  selectProd.value = '';
  const searchInput = document.getElementById('order-product-search');
  if (searchInput) searchInput.value = '';
  const dropdownList = document.getElementById('order-product-dropdown-list');
  if (dropdownList) dropdownList.style.display = 'none';
  qtyInput.value = '1';

  window.renderClientNewOrderItemsTable();
};

window.removeClientNewOrderItem = function(index) {
  if (window.tempClientNewOrderItems && window.tempClientNewOrderItems[index]) {
    window.tempClientNewOrderItems.splice(index, 1);
    window.renderClientNewOrderItemsTable();
  }
};

window.renderClientNewOrderItemsTable = function() {
  const tbody = document.getElementById('client-new-order-items-tbody');
  const totalQtyEl = document.getElementById('client-new-order-total-qty');
  const totalValEl = document.getElementById('client-new-order-total-val');
  if (!tbody || !totalQtyEl || !totalValEl) return;

  const items = window.tempClientNewOrderItems || [];
  if (items.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="6" style="text-align: center; color: var(--color-text-muted); padding: 1.5rem; font-style: italic;">
          No hay ítems agregados a este pedido. Selecciona un producto arriba y haz clic en "Añadir".
        </td>
      </tr>
    `;
    totalQtyEl.textContent = '0';
    totalValEl.textContent = window.formatCLP(0);
    return;
  }

  let html = '';
  let totalQty = 0;
  let totalVal = 0;

  items.forEach((item, idx) => {
    const subtotal = item.quantity * item.price;
    totalQty += item.quantity;
    totalVal += subtotal;

    html += `
      <tr style="border-bottom: 1px solid var(--color-border); background: var(--color-surface);">
        <td style="padding: 0.5rem 0.75rem; font-weight: 600; color: var(--color-text-main);">${item.sku}</td>
        <td style="padding: 0.5rem 0.75rem; color: var(--color-text-main);">${item.name}</td>
        <td style="padding: 0.5rem 0.75rem; text-align: center; font-weight: 600; color: var(--color-text-main);">${item.quantity}</td>
        <td style="padding: 0.5rem 0.75rem; text-align: right; color: var(--color-text-muted);">${window.formatCLP(item.price)}</td>
        <td style="padding: 0.5rem 0.75rem; text-align: right; font-weight: 600; color: var(--color-text-main);">${window.formatCLP(subtotal)}</td>
        <td style="padding: 0.5rem 0.75rem; text-align: center;">
          <button type="button" onclick="window.removeClientNewOrderItem(${idx})" class="btn btn-outline" style="padding: 0.25rem 0.4rem; border-color: var(--color-danger); color: var(--color-danger); cursor: pointer;"><i class="ri-delete-bin-line"></i></button>
        </td>
      </tr>
    `;
  });

  tbody.innerHTML = html;
  totalQtyEl.textContent = totalQty;
  totalValEl.textContent = window.formatCLP(totalVal);
};

window.exportDeclarationToPDF = async function(id) {
  try {
    // Buscar la declaración en base de datos
    const { data: dec, error } = await supabase
      .from('stock_declarations')
      .select('*, warehouses(name, address, comuna, operating_days)')
      .eq('id', id)
      .single();

    if (error) throw error;
    if (!dec) throw new Error('No se encontró la declaración.');

    let etaText = '';
    if (dec.estimated_arrival_type === 'exact') {
      const [y, m, d] = dec.estimated_arrival_date.split('-');
      etaText = `${d}/${m}/${y}`;
    } else {
      etaText = dec.estimated_arrival_period;
    }

    let products = [];
    if (dec.file_base64) {
      try {
        const binaryString = window.atob(dec.file_base64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) {
          bytes[i] = binaryString.charCodeAt(i);
        }
        const workbook = XLSX.read(bytes, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rows = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
        
        if (rows && rows.length > 1) {
          const headerRow = rows[0];
          const skuIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'sku');
          const nameIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'nombre producto');
          const qtyIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'cantidad declarada');
          const priceIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'valor');
          
          if (skuIdx !== -1 && nameIdx !== -1 && qtyIdx !== -1) {
            for (let i = 1; i < rows.length; i++) {
              const row = rows[i];
              if (!row || row.length === 0) continue;
              const isEmptyRow = row.every(val => val === null || val === undefined || val.toString().trim() === '');
              if (isEmptyRow) continue;
              
              const sku = row[skuIdx] ? row[skuIdx].toString().trim() : '';
              const name = row[nameIdx] ? row[nameIdx].toString().trim() : '';
              const qtyVal = row[qtyIdx];
              const priceVal = priceIdx !== -1 ? row[priceIdx] : '';
              
              const qty = parseInt(qtyVal, 10);
              let price = 0;
              if (priceVal !== '' && priceVal !== null && priceVal !== undefined) {
                price = parseFloat(priceVal);
                if (isNaN(price)) price = 0;
              }
              
              if (sku || name) {
                products.push({
                  sku,
                  name,
                  qty: isNaN(qty) ? 0 : qty,
                  price,
                  subtotal: (isNaN(qty) ? 0 : qty) * price
                });
              }
            }
          }
        }
      } catch (excelErr) {
        console.error('Error parsing excel for PDF:', excelErr);
      }
    }

    let productsHtml = '';
    if (products.length > 0) {
      products.forEach((p, idx) => {
        productsHtml += `
          <tr style="border-bottom: 1px solid #cbd5e1; page-break-inside: avoid; break-inside: avoid; vertical-align: top;">
            <td style="padding: 6px 8px; color: #475569; font-size: 9px;">${idx + 1}</td>
            <td style="padding: 6px 8px; color: #334155; font-weight: 600; font-size: 9px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;" title="${p.sku}">${p.sku}</td>
            <td style="padding: 6px 8px; color: #1e293b; font-size: 9px; vertical-align: top;">
              <div style="display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; text-overflow: ellipsis; line-height: 1.3; max-height: 2.6em; word-break: break-word;">
                ${p.name}
              </div>
            </td>
            <td style="padding: 6px 8px; color: #334155; text-align: right; font-weight: 600; font-size: 9px;">${p.qty}</td>
          </tr>
        `;
      });
    } else {
      productsHtml = `
        <tr>
          <td colspan="4" style="padding: 15px; text-align: center; color: #64748b; font-style: italic;">
            No se encontraron productos o el formato de planilla no pudo ser interpretado.
          </td>
        </tr>
      `;
    }

    // Crear contenedor temporal para el spinner de carga y el contenido a exportar
    const container = document.createElement('div');
    container.style.position = 'fixed';
    container.style.left = '0';
    container.style.top = '0';
    container.style.width = '100%';
    container.style.height = '100%';
    container.style.zIndex = '999999';
    container.style.background = 'rgba(255, 255, 255, 0.98)';
    container.style.overflowY = 'auto';

    container.innerHTML = `
      <div id="pdf-loading-overlay" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(255, 255, 255, 0.98); z-index: 1000000; display: flex; flex-direction: column; align-items: center; justify-content: center; font-family: sans-serif; color: #1e3a8a;">
        <div style="border: 4px solid #f3f3f3; border-top: 4px solid #2563eb; border-radius: 50%; width: 50px; height: 50px; animation: pdfSpin 1s linear infinite; margin-bottom: 20px;"></div>
        <style>
          @keyframes pdfSpin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        </style>
        <h2 style="margin: 0 0 8px 0; font-size: 18px; font-weight: bold;">Generando Comprobante PDF</h2>
        <p style="margin: 0; font-size: 14px; color: #475569;">Por favor, espera un momento...</p>
      </div>

      <div id="pdf-content-area" style="padding: 40px; font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; color: #1e293b; background: #ffffff; max-width: 800px; margin: 0 auto; box-sizing: border-box;">
        <div style="display: flex; justify-content: space-between; align-items: center; border-bottom: 2px solid #2563eb; padding-bottom: 15px; margin-bottom: 25px;">
          <div>
            <h1 style="margin: 0; font-size: 26px; color: #1e3a8a; font-weight: 800; letter-spacing: 0.5px;">WMS STOCKA</h1>
            <span style="font-size: 11px; color: #64748b; text-transform: uppercase; font-weight: 600; letter-spacing: 1px;">Comprobante de Ingreso de Stock</span>
          </div>
          <div style="text-align: right;">
            <h2 style="margin: 0; font-size: 14px; color: #2563eb; font-weight: 700;">DECLARACIÓN LOGÍSTICA</h2>
            <span style="font-size: 11px; color: #475569; font-weight: 600;">ID: ${dec.id.substring(0, 8).toUpperCase()}</span>
          </div>
        </div>

        <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 25px; background: #f8fafc; padding: 15px; border-radius: 8px; border: 1px solid #e2e8f0; font-size: 12px; line-height: 1.5;">
          <div>
            <h3 style="margin: 0 0 8px 0; font-size: 12px; color: #1e3a8a; font-weight: 700; border-bottom: 1px solid #cbd5e1; padding-bottom: 4px; text-transform: uppercase;">Información General</h3>
            <p style="margin: 4px 0;"><strong>Título/Descripción:</strong> ${dec.title}</p>
            <p style="margin: 4px 0;"><strong>Comercio:</strong> ${dec.comercio}</p>
            <p style="margin: 4px 0;"><strong>Estado Actual:</strong> <span style="background: #e2e8f0; padding: 2px 6px; border-radius: 4px; font-weight: 700; color: #1e293b;">${dec.status}</span></p>
            <p style="margin: 4px 0;"><strong>Fecha Registro:</strong> ${new Date(dec.created_at).toLocaleDateString('es-CL')} ${new Date(dec.created_at).toLocaleTimeString('es-CL', { hour: '2-digit', minute: '2-digit' })}</p>
            <p style="margin: 4px 0;"><strong>Llegada Estimada:</strong> ${etaText}</p>
          </div>
          <div>
            <h3 style="margin: 0 0 8px 0; font-size: 12px; color: #1e3a8a; font-weight: 700; border-bottom: 1px solid #cbd5e1; padding-bottom: 4px; text-transform: uppercase;">Detalles Logísticos</h3>
            <p style="margin: 4px 0;"><strong>Bodega Destino:</strong> ${dec.warehouses ? dec.warehouses.name : 'No asignada'}</p>
            <p style="margin: 4px 0;"><strong>Volumen Declarado:</strong> ${dec.volume_declared || 0} m³</p>
            <p style="margin: 4px 0;"><strong>Volumen Confirmado:</strong> ${dec.status !== 'Creada' && dec.status !== 'Bodega Asignada' ? (dec.volume_confirmed || 0) + ' m³' : '—'}</p>
            <p style="margin: 4px 0;"><strong>Bultos Totales:</strong> ${dec.package_count} (${dec.package_type})</p>
            <p style="margin: 4px 0; font-size: 11px; color: #64748b; margin-left: 10px;">• C: ${dec.container_count || 0} | P: ${dec.pallet_count || 0} | Cx: ${dec.box_count || 0}</p>
            <p style="margin: 4px 0;"><strong>Método de Envío:</strong> ${dec.delivery_method}</p>
            <p style="margin: 4px 0;"><strong>Servicio Descarga:</strong> ${dec.requires_unloading ? 'Sí, solicitado' : 'No solicitado'}</p>
          </div>
        </div>

        <div style="margin-bottom: 25px; background: #f0fdf4; padding: 15px; border-radius: 8px; border: 1px solid #bbf7d0; font-size: 12px; display: flex; justify-content: space-between; align-items: center; line-height: 1.4;">
          <div>
            <h3 style="margin: 0 0 2px 0; font-size: 13px; color: #166534; font-weight: 700;">Resumen Económico Estimado</h3>
            <span style="color: #475569; font-size: 10px;">* El costo definitivo se liquidará con el volumen físico confirmado en bodega.</span>
          </div>
          <div style="text-align: right;">
            <span style="font-size: 15px; font-weight: bold; color: #15803d; background: #dcfce7; padding: 6px 12px; border-radius: 6px; border: 1px solid #bbf7d0;">Total: ${(dec.estimated_cost || 0).toFixed(2)} UF</span>
          </div>
        </div>

        <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 30px; font-size: 11px; color: #475569; line-height: 1.5;">
          <div>
            <strong style="color: #1e293b;">Contacto Comercial & Transportista:</strong><br>
            Contacto: ${dec.contact_info || 'Sin registrar'}<br>
            Transportista: ${dec.carrier_info || 'Sin registrar'}
          </div>
          <div>
            <strong style="color: #1e293b;">Notas / Observaciones del Cliente:</strong><br>
            <span style="font-style: italic;">"${dec.notes || 'Sin comentarios'}"</span>
          </div>
        </div>

        <h3 style="font-size: 13px; color: #1e3a8a; border-bottom: 2px solid #cbd5e1; padding-bottom: 6px; margin-bottom: 12px; font-weight: 700; text-transform: uppercase;">Detalle de Productos Declarados en Planilla</h3>

        <table style="width: 100%; border-collapse: collapse; font-size: 9px; margin-bottom: 20px; text-align: left;">
          <tbody>
            ${productsHtml}
          </tbody>
        </table>

        <div style="margin-top: 50px; border-top: 1px solid #e2e8f0; padding-top: 15px; text-align: center; font-size: 9px; color: #94a3b8;">
          Comprobante oficial generado digitalmente por WMS STOCKA.
        </div>
      </div>
    `;

    document.body.appendChild(container);

    // Obtener el div específico que queremos exportar
    const contentArea = container.querySelector('#pdf-content-area');

    const opt = {
      margin:       10,
      filename:     `comprobante_ingreso_${dec.id.substring(0, 8).toUpperCase()}.pdf`,
      image:        { type: 'jpeg', quality: 0.98 },
      html2canvas:  { scale: 2, useCORS: true, scrollY: 0, scrollX: 0 },
      jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak:    { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // Usar html2pdf para guardar y usar promesas para garantizar la eliminación posterior
    html2pdf().from(contentArea).set(opt).save().then(() => {
      container.remove();
    }).catch(err => {
      console.error(err);
      container.remove();
    });
  } catch (err) {
    console.error('Error generating PDF:', err);
    alert('Error al generar el PDF: ' + err.message);
  }
};

window.viewDeclarationProducts = async function(id) {
  let modal = document.getElementById('modal-view-dec-products');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'modal-view-dec-products';
    modal.className = 'modal-overlay';
    modal.innerHTML = `
      <div class="modal-content" style="max-width: 700px; display: flex; flex-direction: column; max-height: 80vh; padding: 0;">
        <div class="modal-header" style="padding: 1.25rem; border-bottom: 1px solid var(--color-border); background: var(--color-surface); border-radius: var(--radius-lg) var(--radius-lg) 0 0;">
          <h3 style="margin: 0;" id="view-products-title">Productos del Ingreso</h3>
          <button type="button" class="modal-close" onclick="document.getElementById('modal-view-dec-products').classList.remove('active')">&times;</button>
        </div>
        <div class="modal-body" style="overflow-y: auto; flex: 1; padding: 1.25rem;" id="view-products-body">
          <p class="text-center" style="color: var(--color-text-muted);">Cargando productos...</p>
        </div>
        <div class="modal-footer" style="padding: 1.25rem; border-top: 1px solid var(--color-border); background: var(--color-surface); border-radius: 0 0 var(--radius-lg) var(--radius-lg); display: flex; justify-content: flex-end;">
          <button type="button" class="btn btn-outline" onclick="document.getElementById('modal-view-dec-products').classList.remove('active')">Cerrar</button>
        </div>
      </div>
    `;
    document.body.appendChild(modal);
  }

  modal.classList.add('active');
  const bodyEl = document.getElementById('view-products-body');
  const titleEl = document.getElementById('view-products-title');
  bodyEl.innerHTML = '<div style="text-align: center; padding: 2rem;"><i class="ri-loader-4-line animate-spin" style="font-size: 2rem; color: var(--color-primary); display: inline-block;"></i><p style="margin-top: 0.5rem; color: var(--color-text-muted);">Cargando y procesando la planilla...</p></div>';

  try {
    const { data: dec, error } = await supabase
      .from('stock_declarations')
      .select('title, file_base64')
      .eq('id', id)
      .single();

    if (error) throw error;
    if (!dec) throw new Error('No se encontró la declaración.');

    titleEl.textContent = `Productos: ${dec.title}`;

    let products = [];
    if (dec.file_base64) {
      const binaryString = window.atob(dec.file_base64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      const workbook = XLSX.read(bytes, { type: 'array' });
      const firstSheetName = workbook.SheetNames[0];
      const worksheet = workbook.Sheets[firstSheetName];
      const rows = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
      
      if (rows && rows.length > 1) {
        const headerRow = rows[0];
        const skuIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'sku');
        const nameIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'nombre producto');
        const qtyIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'cantidad declarada');
        
        if (skuIdx !== -1 && nameIdx !== -1 && qtyIdx !== -1) {
          for (let i = 1; i < rows.length; i++) {
            const row = rows[i];
            if (row && row[skuIdx] !== undefined) {
              products.push({
                sku: String(row[skuIdx] || '').trim(),
                name: String(row[nameIdx] || '').trim(),
                qty: parseInt(row[qtyIdx] || 0)
              });
            }
          }
        }
      }
    }

    if (products.length === 0) {
      bodyEl.innerHTML = '<p class="text-center" style="padding: 2rem; color: var(--color-text-muted); font-style: italic;">No se encontraron productos en la planilla.</p>';
      return;
    }

    let tableHtml = `
      <table class="data-table" style="width: 100%; border-collapse: collapse; font-size: 0.85rem;">
        <thead>
          <tr style="border-bottom: 2px solid var(--color-border); text-align: left;">
            <th style="padding: 8px;">#</th>
            <th style="padding: 8px;">SKU</th>
            <th style="padding: 8px;">Nombre Producto</th>
            <th style="padding: 8px; text-align: right;">Cant. Declarada</th>
          </tr>
        </thead>
        <tbody>
    `;

    products.forEach((p, idx) => {
      tableHtml += `
        <tr style="border-bottom: 1px solid var(--color-border);">
          <td style="padding: 8px; color: var(--color-text-muted);">${idx + 1}</td>
          <td style="padding: 8px; font-weight: 600;">${p.sku}</td>
          <td style="padding: 8px;">${p.name}</td>
          <td style="padding: 8px; text-align: right; font-weight: bold;">${p.qty.toLocaleString()}</td>
        </tr>
      `;
    });

    tableHtml += `
        </tbody>
      </table>
    `;

    bodyEl.innerHTML = tableHtml;

  } catch (err) {
    bodyEl.innerHTML = `<div style="padding: 2rem; text-align: center; color: var(--color-danger);"><i class="ri-error-warning-line" style="font-size: 2.5rem; display: block; margin-bottom: 1rem;"></i><h4>Error al procesar la planilla</h4><p>${err.message}</p></div>`;
  }
};

function loadChartJS() {
  return new Promise((resolve) => {
    if (window.Chart) {
      resolve();
      return;
    }
    const script = document.createElement('script');
    script.src = 'https://cdn.jsdelivr.net/npm/chart.js';
    script.onload = () => {
      resolve();
    };
    document.head.appendChild(script);
  });
}

window.renderVolumenDiario = async function() {
  const appContent = document.getElementById('app-content');
  if (!appContent) return;

  let clientComerces = [];
  if (currentCompany) {
    const list = currentCompany.split(',').map(c => c.trim()).filter(Boolean);
    if (list.some(c => c.toLowerCase() === 'all')) {
      try {
        const { data } = await supabase.from('v_comercios_config').select('nombre, sigla');
        clientComerces = data ? data.map(c => c.nombre) : [];
      } catch (e) {
        console.error(e);
      }
    } else {
      clientComerces = list;
    }
  }

  let activeComerces = [];
  try {
    const { data: activeConfigs } = await supabase
      .from('comercios_adicional_config')
      .select('comercio')
      .eq('inventario_seguimiento', true);
    
    const activeSet = new Set(activeConfigs ? activeConfigs.map(c => c.comercio.toLowerCase()) : []);
    activeComerces = clientComerces.filter(c => activeSet.has(c.toLowerCase()));
  } catch (e) {
    console.error('Error filtrando comercios por seguimiento:', e);
    activeComerces = clientComerces;
  }

  if (activeComerces.length === 0) {
    appContent.innerHTML = `
      <div style="padding: 3rem; text-align: center; color: var(--color-text-muted);">
        <i class="ri-information-line" style="font-size: 3rem; display: block; margin-bottom: 1rem;"></i>
        <h4>Seguimiento de stock inactivo</h4>
        <p>No tienes comercios asociados con el seguimiento de stock activo. Esta sección está disponible únicamente para comercios con control de inventario.</p>
      </div>
    `;
    return;
  }

  // Default date range (current month)
  const tzDate = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Santiago' }));
  const y = tzDate.getFullYear();
  const m = tzDate.getMonth();
  const firstDay = new Date(y, m, 1);
  const lastDay = new Date(y, m + 1, 0);

  function formatDate(d) {
    const yy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    return `${yy}-${mm}-${dd}`;
  }

  function addDays(dateStr, days) {
    const d = new Date(dateStr + 'T00:00:00');
    d.setDate(d.getDate() + days);
    const yy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    return `${yy}-${mm}-${dd}`;
  }

  let startDate = formatDate(firstDay);
  let endDate = formatDate(lastDay);
  let selectedCommerce = activeComerces.length === 1 ? activeComerces[0] : '';
  let currentPage = 1;
  const itemsPerPage = 15;
  let allHistories = [];
  let volumeChartInstance = null;

  appContent.innerHTML = `
    <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 1.5rem; flex-wrap: wrap; gap: 1rem;">
      <div>
        <h3 style="margin: 0; font-size: 1.25rem; color: var(--color-text-main);">Evolución de Volumen Diario</h3>
        <p style="margin: 0.25rem 0 0 0; font-size: 0.85rem; color: var(--color-text-muted);">Monitorea el histórico diario y el consumo en tiempo real de volumen total por metro cúbico</p>
      </div>
      <div>
        <button class="btn btn-outline" id="btn-refresh-volume"><i class="ri-refresh-line"></i> Actualizar</button>
      </div>
    </div>

    <!-- Filters & Stats Card -->
    <div class="card" style="margin-bottom: 1.5rem; background: var(--color-surface); border: 1px solid var(--color-border); border-radius: var(--radius-md);">
      <div class="card-body" style="padding: 1.25rem 1.5rem;">
        <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1.25rem; align-items: end;">
          <div class="form-group" style="margin: 0; ${activeComerces.length <= 1 ? 'display: none;' : ''}">
            <label class="form-label" style="font-weight: 600; margin-bottom: 0.5rem; display: block;">Comercio</label>
            <select id="volume-merchant-select" class="form-input" style="width: 100%; margin: 0; height: 38px;">
              <option value="">-- Todos los comercios --</option>
              ${activeComerces.map(c => `<option value="${c}">${c}</option>`).join('')}
            </select>
          </div>

          <div class="form-group" style="margin: 0;">
            <label class="form-label" style="font-weight: 600; margin-bottom: 0.5rem; display: block;">Fecha Inicio</label>
            <input type="date" id="volume-start-date" class="form-input" style="width: 100%; margin: 0; height: 38px;">
          </div>

          <div class="form-group" style="margin: 0;">
            <label class="form-label" style="font-weight: 600; margin-bottom: 0.5rem; display: block;">Fecha Fin</label>
            <input type="date" id="volume-end-date" class="form-input" style="width: 100%; margin: 0; height: 38px;">
          </div>
          
          <div style="background: var(--color-bg); padding: 0.5rem 0.75rem; border-radius: var(--radius-sm); border: 1px solid var(--color-border); display: flex; flex-direction: column; height: 50px; justify-content: center;">
            <span style="font-size: 0.65rem; color: var(--color-text-muted); font-weight: 500; text-transform: uppercase; line-height: 1.2;">Volumen Actual</span>
            <span id="volume-current-value" style="font-size: 1.05rem; font-weight: 700; color: var(--color-primary); margin-top: 0.15rem; line-height: 1.2;">-- m³</span>
          </div>

          <div style="background: var(--color-bg); padding: 0.5rem 0.75rem; border-radius: var(--radius-sm); border: 1px solid var(--color-border); display: flex; flex-direction: column; height: 50px; justify-content: center;">
            <span style="font-size: 0.65rem; color: var(--color-text-muted); font-weight: 500; text-transform: uppercase; line-height: 1.2;">Tendencia Periodo</span>
            <span id="volume-trend-value" style="font-size: 1.05rem; font-weight: 700; color: var(--color-text-main); margin-top: 0.15rem; line-height: 1.2; display: flex; align-items: center;">--</span>
          </div>
        </div>
      </div>
    </div>

    <!-- Chart Card -->
    <div class="card" style="margin-bottom: 1.5rem; background: var(--color-surface); border: 1px solid var(--color-border); border-radius: var(--radius-md);">
      <div class="card-header" style="padding: 1rem 1.25rem; border-bottom: 1px solid var(--color-border); display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 1rem;">
        <h4 style="margin: 0; font-size: 0.95rem; color: var(--color-text-main); font-weight: 600;">Evolución de Volumen (m³)</h4>
        <div style="display: flex; align-items: center; gap: 0.75rem; font-size: 0.75rem;">
          <span style="display: inline-flex; align-items: center; gap: 0.25rem; color: var(--color-text-muted);">
            <span style="width: 8px; height: 8px; border-radius: 50%; background-color: #2563eb; display: inline-block;"></span> Rango Filtrado
          </span>
          <span style="display: inline-flex; align-items: center; gap: 0.25rem; color: var(--color-text-muted);">
            <span style="width: 8px; height: 8px; border-radius: 50%; background-color: #cbd5e1; display: inline-block;"></span> Contexto Extra (Gris)
          </span>
          <span style="display: inline-flex; align-items: center; gap: 0.25rem; color: var(--color-text-muted);">
            <span style="width: 8px; height: 8px; border-radius: 50%; background-color: #f43f5e; display: inline-block;"></span> Volumen Actual (Tiempo Real)
          </span>
        </div>
      </div>
      <div class="card-body" style="padding: 1.25rem;">
        <div style="position: relative; height: 320px; width: 100%;">
          <canvas id="volume-chart-canvas"></canvas>
        </div>
      </div>
    </div>

    <!-- Table Card -->
    <div class="card" style="background: var(--color-surface); border: 1px solid var(--color-border); border-radius: var(--radius-md);">
      <div class="card-header" style="padding: 1rem 1.25rem; border-bottom: 1px solid var(--color-border); display: flex; justify-content: space-between; align-items: center;">
        <h4 style="margin: 0; font-size: 0.95rem; color: var(--color-text-main); font-weight: 600;">Detalle de Mediciones Diarias</h4>
      </div>
      <div class="card-body" style="padding: 0;">
        <div class="table-responsive" style="overflow-x: auto;">
          <table class="table" style="width: 100%; border-collapse: collapse; margin: 0; font-size: 0.85rem;">
            <thead>
              <tr style="border-bottom: 2px solid var(--color-border); background: var(--color-bg); text-align: left;">
                <th style="padding: 0.75rem 1.5rem; font-size: 0.8rem; color: var(--color-text-muted); text-transform: uppercase;">Fecha</th>
                <th style="padding: 0.75rem 1.5rem; font-size: 0.8rem; color: var(--color-text-muted); text-transform: uppercase;">Comercio</th>
                <th style="padding: 0.75rem 1.5rem; font-size: 0.8rem; color: var(--color-text-muted); text-transform: uppercase; text-align: right;">Nivel de Volumen (m³)</th>
              </tr>
            </thead>
            <tbody id="volume-history-tbody">
              <tr>
                <td colspan="3" class="text-center" style="padding: 3rem; color: var(--color-text-muted);">
                  <i class="ri-loader-4-line spin" style="font-size: 1.5rem; display: block; margin-bottom: 0.5rem;"></i>
                  Cargando historial de volumen...
                </td>
              </tr>
            </tbody>
          </table>
        </div>
        <div id="volume-pagination" style="padding: 1rem 1.5rem; display: flex; justify-content: space-between; align-items: center; border-top: 1px solid var(--color-border); font-size: 0.85rem;">
          <span style="color: var(--color-text-muted);" id="volume-page-info">Mostrando registros</span>
          <div style="display: flex; gap: 0.5rem;">
            <button class="btn btn-outline" id="btn-volume-prev" style="padding: 0.25rem 0.75rem; font-size: 0.8rem;" disabled>Anterior</button>
            <button class="btn btn-outline" id="btn-volume-next" style="padding: 0.25rem 0.75rem; font-size: 0.8rem;" disabled>Siguiente</button>
          </div>
        </div>
      </div>
    </div>
  `;

  // Set default values in inputs
  document.getElementById('volume-start-date').value = startDate;
  document.getElementById('volume-end-date').value = endDate;

  // DOM Elements
  const merchantSelect = document.getElementById('volume-merchant-select');
  const startDateInput = document.getElementById('volume-start-date');
  const endDateInput = document.getElementById('volume-end-date');
  const currentValSpan = document.getElementById('volume-current-value');
  const trendValSpan = document.getElementById('volume-trend-value');
  const tbody = document.getElementById('volume-history-tbody');
  const btnRefresh = document.getElementById('btn-refresh-volume');
  const btnPrev = document.getElementById('btn-volume-prev');
  const btnNext = document.getElementById('btn-volume-next');
  const pageInfo = document.getElementById('volume-page-info');

  // Load Current Volume in Real Time
  async function updateVolumeStats() {
    currentValSpan.textContent = '-- m³';

    try {
      let rtQuery = supabase.from('v_comercios_volumen_actual').select('volumen_actual');
      if (selectedCommerce) {
        rtQuery = rtQuery.eq('comercio', selectedCommerce);
      } else {
        rtQuery = rtQuery.in('comercio', activeComerces);
      }
      const { data: realTimeData, error: rtErr } = await rtQuery;

      if (rtErr) throw rtErr;
      const volReal = realTimeData ? realTimeData.reduce((sum, item) => sum + parseFloat(item.volumen_actual || 0), 0) : 0;
      currentValSpan.textContent = `${volReal.toFixed(5)} m³`;
    } catch (e) {
      console.error('Error al cargar estadísticas de volumen:', e);
    }
  }

  // Update Trend Indicator
  function updateTrendIndicator(filteredDates, filteredValues, totalLiveVolume, isTodayInRange) {
    if (!trendValSpan) return;

    const dates = [...filteredDates];
    const values = [...filteredValues];

    if (isTodayInRange) {
      dates.push('Actual');
      values.push(totalLiveVolume);
    }

    if (values.length < 2) {
      trendValSpan.innerHTML = '<span style="color: var(--color-text-muted); font-size: 0.85rem;">Sin datos suf.</span>';
      return;
    }

    const vStart = values[0];
    const vEnd = values[values.length - 1];

    let pctChange = 0;
    if (vStart > 0) {
      pctChange = ((vEnd - vStart) / vStart) * 100;
    } else if (vEnd > 0) {
      pctChange = 100;
    }

    const absPct = Math.abs(pctChange).toFixed(2);
    if (pctChange > 0.0001) {
      trendValSpan.innerHTML = `<span style="color: #10b981; display: flex; align-items: center; font-weight: 700;"><i class="ri-trending-up-line" style="margin-right: 0.25rem;"></i> +${absPct}%</span>`;
    } else if (pctChange < -0.0001) {
      trendValSpan.innerHTML = `<span style="color: #ef4444; display: flex; align-items: center; font-weight: 700;"><i class="ri-trending-down-line" style="margin-right: 0.25rem;"></i> -${absPct}%</span>`;
    } else {
      trendValSpan.innerHTML = `<span style="color: var(--color-text-muted); display: flex; align-items: center; font-weight: 700;"><i class="ri-subtract-line" style="margin-right: 0.25rem;"></i> 0.00%</span>`;
    }
  }

  // Update Chart
  async function updateChart() {
    let liveVolumeMap = {};
    try {
      let rtQuery = supabase.from('v_comercios_volumen_actual').select('comercio, volumen_actual');
      if (selectedCommerce) {
        rtQuery = rtQuery.eq('comercio', selectedCommerce);
      } else {
        rtQuery = rtQuery.in('comercio', activeComerces);
      }
      const { data: rtData, error: rtErr } = await rtQuery;
      if (rtErr) throw rtErr;
      if (rtData) {
        rtData.forEach(item => {
          liveVolumeMap[item.comercio] = parseFloat(item.volumen_actual || 0);
        });
      }
    } catch (e) {
      console.error('Error al obtener volumen en tiempo real para gráfico:', e);
    }

    const tzToday = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Santiago' }));
    const yy = tzToday.getFullYear();
    const mm = String(tzToday.getMonth() + 1).padStart(2, '0');
    const dd = String(tzToday.getDate()).padStart(2, '0');
    const chileTodayStr = `${yy}-${mm}-${dd}`;

    const isTodayInRange = (chileTodayStr >= startDate && chileTodayStr <= endDate);

    // Get unique list of dates (sorted ascending)
    const datesSet = new Set();
    allHistories.forEach(item => datesSet.add(item.fecha));
    const dates = Array.from(datesSet).sort();

    const chartDates = [...dates];
    if (isTodayInRange) {
      chartDates.push('Actual');
    }

    const labels = dates.map(d => {
      const parts = d.split('-');
      return `${parts[2]}/${parts[1]}`;
    });
    if (isTodayInRange) {
      labels.push('Actual');
    }

    const ctx = document.getElementById('volume-chart-canvas');
    if (!ctx) return;

    await loadChartJS();

    if (volumeChartInstance) {
      volumeChartInstance.destroy();
    }

    const isStackedBar = !selectedCommerce;

    // Get list of comercios to show
    let comercios = [];
    if (isStackedBar) {
      comercios = [...activeComerces].sort();
    } else {
      comercios = [selectedCommerce];
    }

    const CHART_PALETTE = [
      '#3b82f6', // blue
      '#10b981', // emerald
      '#f59e0b', // amber
      '#8b5cf6', // violet
      '#ec4899', // pink
      '#06b6d4', // cyan
      '#f97316', // orange
      '#14b8a6', // teal
      '#a855f7', // purple
      '#6366f1'  // indigo
    ];
    const CHART_BORDER_PALETTE = [
      '#1d4ed8',
      '#047857',
      '#b45309',
      '#6d28d9',
      '#be185d',
      '#0e7490',
      '#c2410c',
      '#0f766e',
      '#7e22ce',
      '#4338ca'
    ];

    const datasets = comercios.map((commerceName, idx) => {
      const values = chartDates.map(d => {
        if (d === 'Actual') {
          return liveVolumeMap[commerceName] || 0;
        }
        const match = allHistories.find(item => item.comercio === commerceName && item.fecha === d);
        return match ? parseFloat(match.volumen || 0) : 0;
      });

      if (isStackedBar) {
        // Multi-merchant stacked bar details
        const bgColors = chartDates.map(d => {
          const isExtra = (d < startDate || d > endDate);
          return isExtra ? 'rgba(148, 163, 184, 0.25)' : CHART_PALETTE[idx % CHART_PALETTE.length];
        });
        const borderColors = chartDates.map(d => {
          const isExtra = (d < startDate || d > endDate);
          return isExtra ? 'rgba(148, 163, 184, 0.4)' : CHART_BORDER_PALETTE[idx % CHART_BORDER_PALETTE.length];
        });

        return {
          type: 'bar',
          label: commerceName,
          data: values,
          backgroundColor: bgColors,
          borderColor: borderColors,
          borderWidth: 1,
          barPercentage: 0.45,
          categoryPercentage: 0.8,
          stack: 'volume_stack'
        };
      } else {
        // Single merchant line curve
        const pointBgColor = chartDates.map(d => {
          if (d === 'Actual') return '#f43f5e';
          const isExtra = (d < startDate || d > endDate);
          return isExtra ? '#cbd5e1' : '#2563eb';
        });
        const pointBdColor = chartDates.map(d => {
          if (d === 'Actual') return '#fda4af';
          const isExtra = (d < startDate || d > endDate);
          return isExtra ? '#cbd5e1' : '#3b82f6';
        });
        const pointRad = chartDates.map(d => d === 'Actual' ? 7 : 4);
        const pointHoverRad = chartDates.map(d => d === 'Actual' ? 9 : 6);

        return {
          type: 'line',
          label: commerceName,
          data: values,
          borderColor: '#2563eb',
          borderWidth: 2.5,
          tension: 0.35,
          pointBackgroundColor: pointBgColor,
          pointBorderColor: pointBdColor,
          pointBorderWidth: 2,
          pointRadius: pointRad,
          pointHoverRadius: pointHoverRad,
          segment: {
            borderColor: ctx => {
              const p0 = ctx.p0DataIndex;
              const p1 = ctx.p1DataIndex;
              const d0 = chartDates[p0];
              const d1 = chartDates[p1];
              const isExtra = (d0 < startDate || d0 > endDate || d1 < startDate || d1 > endDate);
              return isExtra ? 'rgba(148, 163, 184, 0.4)' : '#2563eb';
            },
            borderDash: ctx => {
              const p0 = ctx.p0DataIndex;
              const p1 = ctx.p1DataIndex;
              const d0 = chartDates[p0];
              const d1 = chartDates[p1];
              const isExtra = (d0 < startDate || d0 > endDate || d1 < startDate || d1 > endDate);
              return isExtra ? [4, 4] : undefined;
            }
          }
        };
      }
    });

    // Overlay the Total Volume Curve only if we are showing multiple comerces (consolidated)
    if (isStackedBar) {
      const totalValues = chartDates.map((_, i) => {
        // datasets contains individual commerce volumes
        return datasets.reduce((sum, ds) => sum + (ds.data[i] || 0), 0);
      });

      datasets.push({
        type: 'line',
        label: 'Curva Total',
        data: totalValues,
        borderColor: '#2563eb',
        borderWidth: 2.2,
        tension: 0.35,
        fill: false,
        pointBackgroundColor: chartDates.map(d => {
          if (d === 'Actual') return '#f43f5e';
          const isExtra = (d < startDate || d > endDate);
          return isExtra ? '#cbd5e1' : '#2563eb';
        }),
        pointBorderColor: chartDates.map(d => {
          if (d === 'Actual') return '#fda4af';
          const isExtra = (d < startDate || d > endDate);
          return isExtra ? '#cbd5e1' : '#3b82f6';
        }),
        pointRadius: chartDates.map(d => d === 'Actual' ? 6 : 3.5),
        pointHoverRadius: chartDates.map(d => d === 'Actual' ? 8 : 5.5),
        segment: {
          borderColor: ctx => {
            const p0 = ctx.p0DataIndex;
            const p1 = ctx.p1DataIndex;
            const d0 = chartDates[p0];
            const d1 = chartDates[p1];
            const isExtra = (d0 < startDate || d0 > endDate || d1 < startDate || d1 > endDate);
            return isExtra ? 'rgba(148, 163, 184, 0.4)' : '#2563eb';
          },
          borderDash: ctx => {
            const p0 = ctx.p0DataIndex;
            const p1 = ctx.p1DataIndex;
            const d0 = chartDates[p0];
            const d1 = chartDates[p1];
            const isExtra = (d0 < startDate || d0 > endDate || d1 < startDate || d1 > endDate);
            return isExtra ? [4, 4] : undefined;
          }
        }
      });
    }

    // Calculate trend over user selected range
    const filteredDates = dates.filter(d => d >= startDate && d <= endDate);
    const filteredValues = filteredDates.map(d => {
      const matches = allHistories.filter(item => item.fecha === d);
      return matches.reduce((sum, item) => sum + parseFloat(item.volumen || 0), 0);
    });

    let totalLiveVolume = 0;
    if (selectedCommerce) {
      totalLiveVolume = liveVolumeMap[selectedCommerce] || 0;
    } else {
      totalLiveVolume = Object.values(liveVolumeMap).reduce((sum, v) => sum + v, 0);
    }
    updateTrendIndicator(filteredDates, filteredValues, totalLiveVolume, isTodayInRange);

    volumeChartInstance = new Chart(ctx, {
      data: {
        labels: labels,
        datasets: datasets
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: {
            display: isStackedBar,
            position: 'top',
            labels: {
              color: '#94a3b8',
              font: {
                size: 11
              },
              boxWidth: 12
            }
          },
          tooltip: {
            backgroundColor: 'rgba(15, 23, 42, 0.9)',
            titleColor: '#fff',
            bodyColor: '#fff',
            borderColor: '#334155',
            borderWidth: 1,
            padding: 10,
            callbacks: {
              title: function(context) {
                const item = context[0];
                if (item.label === 'Actual') {
                  return `Hoy: ${dd}/${mm}/${yy} (Tiempo Real)`;
                }
                const foundDate = chartDates[item.dataIndex];
                if (foundDate) {
                  const parts = foundDate.split('-');
                  return `Fecha: ${parts[2]}/${parts[1]}/${parts[0]}`;
                }
                return `Fecha: ${item.label}`;
              },
              label: function(context) {
                const dataIndex = context.dataIndex;
                const chart = context.chart;
                let dayTotal = 0;
                chart.data.datasets.forEach(dataset => {
                  if (dataset.type === 'bar') {
                    dayTotal += parseFloat(dataset.data[dataIndex] || 0);
                  }
                });

                const value = context.parsed.y;
                const pct = dayTotal > 0 ? ((value / dayTotal) * 100).toFixed(1) : '0.0';
                
                if (context.dataset.label === 'Curva Total') {
                  return ` Volumen Total: ${value.toFixed(5)} m³`;
                }

                if (isStackedBar) {
                  return ` ${context.dataset.label}: ${value.toFixed(5)} m³ (${pct}%)`;
                } else {
                  return ` Volumen: ${value.toFixed(5)} m³`;
                }
              },
              footer: function(context) {
                if (isStackedBar) {
                  const dataIndex = context[0].dataIndex;
                  const chart = context[0].chart;
                  let dayTotal = 0;
                  chart.data.datasets.forEach(dataset => {
                    if (dataset.type === 'bar') {
                      dayTotal += parseFloat(dataset.data[dataIndex] || 0);
                    }
                  });
                  return `Total diario: ${dayTotal.toFixed(5)} m³`;
                }
                return null;
              }
            }
          }
        },
        scales: {
          x: {
            stacked: isStackedBar,
            grid: {
              display: false
            },
            ticks: {
              color: '#94a3b8',
              font: {
                size: 11
              }
            }
          },
          y: {
            stacked: isStackedBar,
            grid: {
              color: 'rgba(148, 163, 184, 0.08)',
              drawBorder: false
            },
            ticks: {
              color: '#94a3b8',
              font: {
                size: 11
              },
              callback: function(value) {
                return value.toFixed(3) + ' m³';
              }
            }
          }
        }
      }
    });
  }

  // Load Histories
  async function loadHistories() {
    tbody.innerHTML = `
      <tr>
        <td colspan="3" class="text-center" style="padding: 3rem; color: var(--color-text-muted);">
          <i class="ri-loader-4-line spin" style="font-size: 1.5rem; display: block; margin-bottom: 0.5rem;"></i>
          Cargando historial de volumen...
        </td>
      </tr>
    `;

    try {
      const startD = new Date(startDate + 'T00:00:00');
      const endD = new Date(endDate + 'T00:00:00');
      const diffDays = Math.ceil(Math.abs(endD - startD) / (1000 * 60 * 60 * 24)) + 1;

      const expandedStart = addDays(startDate, -diffDays);
      const expandedEnd = addDays(endDate, diffDays);

      let query = supabase.from('comercios_volumen_diario').select('*');

      if (selectedCommerce) {
        query = query.eq('comercio', selectedCommerce);
      } else {
        query = query.in('comercio', activeComerces);
      }
      
      query = query.gte('fecha', expandedStart).lte('fecha', expandedEnd);

      const { data, error } = await query.order('fecha', { ascending: true }); // Ascending for the chart

      if (error) throw error;

      allHistories = data || [];
      currentPage = 1;
      await updateChart();
      renderTableData();
    } catch (e) {
      console.error('Error al cargar historial de volumen:', e);
      tbody.innerHTML = `
        <tr>
          <td colspan="3" class="text-center" style="padding: 2rem; color: var(--color-danger);">
            <i class="ri-error-warning-line" style="font-size: 2rem; display: block; margin-bottom: 0.5rem;"></i>
            Error al obtener el historial de volumen: ${e.message}
          </td>
        </tr>
      `;
    }
  }

  // Render Table Data with Pagination
  function renderTableData() {
    // Reverse historical data to show most recent first in table (only within user selected filtered range)
    const tableHistories = allHistories
      .filter(item => item.fecha >= startDate && item.fecha <= endDate)
      .reverse();

    if (tableHistories.length === 0) {
      tbody.innerHTML = `
        <tr>
          <td colspan="3" class="text-center" style="padding: 3rem; color: var(--color-text-muted);">
            <i class="ri-information-line" style="font-size: 1.5rem; display: block; margin-bottom: 0.5rem;"></i>
            No se encontraron registros de volumen para los filtros seleccionados
          </td>
        </tr>
      `;
      btnPrev.disabled = true;
      btnNext.disabled = true;
      pageInfo.textContent = 'Mostrando 0 de 0 registros';
      return;
    }

    const totalItems = tableHistories.length;
    const totalPages = Math.ceil(totalItems / itemsPerPage);
    const startIdx = (currentPage - 1) * itemsPerPage;
    const endIdx = Math.min(startIdx + itemsPerPage, totalItems);
    const pageItems = tableHistories.slice(startIdx, endIdx);

    tbody.innerHTML = pageItems.map(item => {
      const d = new Date(item.fecha + 'T00:00:00');
      const formattedDate = d.toLocaleDateString('es-CL', { day: '2-digit', month: '2-digit', year: 'numeric', weekday: 'short' });

      return `
        <tr style="border-bottom: 1px solid var(--color-border); transition: var(--transition-theme);">
          <td style="padding: 0.75rem 1.5rem; font-weight: 500; text-transform: capitalize;">${formattedDate}</td>
          <td style="padding: 0.75rem 1.5rem; font-weight: 600;">${item.comercio}</td>
          <td style="padding: 0.75rem 1.5rem; text-align: right; font-weight: 700; color: var(--color-primary);">${parseFloat(item.volumen).toFixed(5)} m³</td>
        </tr>
      `;
    }).join('');

    btnPrev.disabled = currentPage === 1;
    btnNext.disabled = currentPage === totalPages;
    pageInfo.textContent = `Mostrando ${startIdx + 1}-${endIdx} de ${totalItems} registros`;
  }

  // Event Listeners
  if (merchantSelect) {
    merchantSelect.addEventListener('change', (e) => {
      selectedCommerce = e.target.value;
      updateVolumeStats();
      loadHistories();
    });
  }

  startDateInput.addEventListener('change', (e) => {
    startDate = e.target.value;
    loadHistories();
  });

  endDateInput.addEventListener('change', (e) => {
    endDate = e.target.value;
    loadHistories();
  });

  btnRefresh.addEventListener('click', () => {
    updateVolumeStats();
    loadHistories();
  });

  btnPrev.addEventListener('click', () => {
    if (currentPage > 1) {
      currentPage--;
      renderTableData();
    }
  });

  btnNext.addEventListener('click', () => {
    if (currentPage * itemsPerPage < allHistories.length) {
      currentPage++;
      renderTableData();
    }
  });

  await updateVolumeStats();
  await loadHistories();
};

function openNewsModal(newsItem) {
  let overlay = document.getElementById('news-detail-modal-overlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'news-detail-modal-overlay';
    overlay.className = 'modal-overlay';
    document.body.appendChild(overlay);
  }
  
  overlay.innerHTML = `
    <div class="modal-content" style="max-width: 600px; width: 90%;">
      <div class="modal-header" style="display: flex; justify-content: space-between; align-items: center; padding: 1.25rem 1.5rem; border-bottom: 1px solid var(--color-border);">
        <h3 style="margin: 0; font-size: 1.25rem; color: var(--color-text-main); font-weight: 700;">${newsItem.title}</h3>
        <button class="modal-close" id="close-news-modal-btn" style="background: none; border: none; color: var(--color-text-muted); cursor: pointer; font-size: 1.25rem;"><i class="ri-close-line"></i></button>
      </div>
      <div class="modal-body" style="padding: 1.5rem; overflow-y: auto; max-height: 60vh;">
        ${newsItem.subtitle ? `<h4 style="margin: 0 0 1rem 0; font-weight: 600; color: var(--color-primary); font-size: 1rem;">${newsItem.subtitle}</h4>` : ''}
        <span style="font-size: 0.75rem; color: var(--color-text-muted); display: block; margin-bottom: 1rem;">
          <i class="ri-calendar-line" style="margin-right: 0.25rem;"></i>${new Date(newsItem.created_at).toLocaleString()}
        </span>
        <div style="font-size: 0.9rem; color: var(--color-text-main); line-height: 1.6; white-space: pre-wrap;">${newsItem.body}</div>
      </div>
      <div class="modal-footer" style="padding: 1rem 1.5rem; border-top: 1px solid var(--color-border); display: flex; justify-content: flex-end;">
        <button class="btn btn-outline" id="close-news-modal-footer-btn" style="padding: 0.5rem 1rem;">Cerrar</button>
      </div>
    </div>
  `;
  
  overlay.classList.add('active');
  
  const close = () => {
    overlay.classList.remove('active');
  };
  
  document.getElementById('close-news-modal-btn').addEventListener('click', close);
  document.getElementById('close-news-modal-footer-btn').addEventListener('click', close);
  overlay.addEventListener('click', (e) => {
    if (e.target === overlay) {
      close();
    }
  });
}

function getDeclarationProducts(dec) {
  if (dec.products_list && Array.isArray(dec.products_list) && dec.products_list.length > 0) {
    return dec.products_list;
  }
  if (dec.file_base64) {
    try {
      const binaryString = window.atob(dec.file_base64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      const workbook = XLSX.read(bytes, { type: 'array' });
      const firstSheetName = workbook.SheetNames[0];
      const worksheet = workbook.Sheets[firstSheetName];
      const rows = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
      
      const parsed = [];
      if (rows && rows.length > 1) {
        const headerRow = rows[0];
        const skuIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'sku');
        const nameIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'nombre producto');
        const qtyIdx = headerRow.findIndex(h => h && h.toString().trim().toLowerCase() === 'cantidad declarada');
        
        if (skuIdx !== -1 && nameIdx !== -1 && qtyIdx !== -1) {
          for (let i = 1; i < rows.length; i++) {
            const row = rows[i];
            if (row && row[skuIdx] !== undefined) {
              parsed.push({
                sku: String(row[skuIdx] || '').trim(),
                name: String(row[nameIdx] || '').trim(),
                qty: parseInt(row[qtyIdx] || 0)
              });
            }
          }
        }
      }
      return parsed;
    } catch (e) {
      console.error('Error fallback parsing Excel:', e);
    }
  }
  return [];
}

async function openPendingDetailModal(sku, name) {
  const modalId = 'modal-pending-detail';
  let modal = document.getElementById(modalId);
  if (modal) modal.remove();

  modal = document.createElement('div');
  modal.id = modalId;
  modal.className = 'modal-overlay active';
  
  modal.innerHTML = `
    <div class="modal-content" style="max-width: 800px; width: 90%; background: var(--color-surface); border: 1px solid var(--color-border); border-radius: var(--radius-lg); overflow: hidden; box-shadow: var(--shadow-xl);">
      <div class="modal-header" style="padding: 1.25rem 1.5rem; border-bottom: 1px solid var(--color-border); display: flex; justify-content: space-between; align-items: center; background: rgba(0,0,0,0.05);">
        <div>
          <h3 style="margin: 0; font-size: 1.2rem; font-weight: 700; color: var(--color-text-main); display: flex; align-items: center; gap: 0.5rem;">
            <i class="ri-loader-4-line" style="color: var(--color-primary);"></i> Detalle de Stock Pendiente de Ingreso
          </h3>
          <p style="margin: 0.15rem 0 0 0; font-size: 0.8rem; color: var(--color-text-muted); font-weight: 500;">
            ${name} <span style="margin: 0 0.25rem; opacity: 0.5;">|</span> SKU: <strong>${sku}</strong>
          </p>
        </div>
        <button class="modal-close" onclick="document.getElementById('${modalId}').remove()" style="font-size: 1.5rem; cursor: pointer; background: transparent; border: none; color: var(--color-text-muted);">&times;</button>
      </div>
      <div class="modal-body" style="padding: 1.5rem; max-height: 400px; overflow-y: auto;" id="pending-detail-modal-body">
        <div class="text-center" style="color: var(--color-text-muted); padding: 3rem;">
          <i class="ri-loader-4-line spin" style="font-size: 2rem; display: inline-block; animation: spin 1s linear infinite; margin-bottom: 0.75rem; color: var(--color-primary);"></i>
          <p style="margin: 0; font-size: 0.9rem;">Buscando ingresos activos con este producto...</p>
        </div>
      </div>
      <div class="modal-footer" style="padding: 1rem 1.5rem; border-top: 1px solid var(--color-border); display: flex; justify-content: flex-end; background: rgba(0,0,0,0.05);">
        <button type="button" class="btn btn-outline" onclick="document.getElementById('${modalId}').remove()" style="border-radius: var(--radius-md); font-weight: 500;">Cerrar</button>
      </div>
    </div>
  `;

  document.body.appendChild(modal);

  try {
    const activeStatuses = ['Creada', 'Bodega Asignada', 'En Recepción - Pendiente Conteo', 'En proceso de conteo/clasificación'];
    const commerce = window.activeIntegrationCommerce || (currentCompany ? currentCompany.split(',')[0].trim() : '');
    
    let query = supabase
      .from('stock_declarations')
      .select('id, title, status, estimated_arrival_type, estimated_arrival_date, estimated_arrival_period, products_list, file_base64')
      .in('status', activeStatuses);
      
    if (commerce) {
      query = query.eq('comercio', commerce);
    }

    const { data: declarations, error } = await query.order('created_at', { ascending: false });

    if (error) throw error;

    const modalBody = document.getElementById('pending-detail-modal-body');
    if (!modalBody) return;

    // Filtrar declaraciones que contienen el SKU del producto
    const matchingDecs = [];
    if (declarations) {
      declarations.forEach(dec => {
        const products = getDeclarationProducts(dec);
        const match = products.find(p => p.sku && p.sku.trim().toLowerCase() === sku.trim().toLowerCase());
        if (match) {
          matchingDecs.push({
            id: dec.id,
            title: dec.title,
            status: dec.status,
            eta: dec.estimated_arrival_type === 'exact' 
              ? `${dec.estimated_arrival_date.split('-')[2]}/${dec.estimated_arrival_date.split('-')[1]}/${dec.estimated_arrival_date.split('-')[0]}`
              : dec.estimated_arrival_period,
            qty: match.qty
          });
        }
      });
    }

    if (matchingDecs.length === 0) {
      modalBody.innerHTML = `
        <div class="text-center" style="padding: 4rem 2rem; color: var(--color-text-muted);">
          <i class="ri-checkbox-circle-line" style="font-size: 3rem; color: var(--color-success); margin-bottom: 1rem; display: block; opacity: 0.5;"></i>
          <p style="margin: 0; font-size: 0.95rem; font-weight: 500;">No hay ingresos de stock activos con este producto en camino.</p>
        </div>
      `;
      return;
    }

    let rowsHtml = matchingDecs.map(item => {
      return `
        <tr style="border-bottom: 1px solid var(--color-border); font-size: 0.85rem;">
          <td style="padding: 0.75rem 1rem;"><strong>${item.title}</strong></td>
          <td style="padding: 0.75rem 1rem; color: var(--color-text-muted);">${item.eta}</td>
          <td style="padding: 0.75rem 1rem;">
            <span class="badge" style="background-color: var(--badge-neutral-bg); color: var(--badge-neutral-text); font-size: 0.75rem;">${item.status}</span>
          </td>
          <td style="padding: 0.75rem 1rem; text-align: right; font-weight: 600; color: var(--color-primary);">${item.qty.toLocaleString()}</td>
        </tr>
      `;
    }).join('');

    modalBody.innerHTML = `
      <table class="data-table" style="width: 100%; border-collapse: collapse;">
        <thead>
          <tr style="border-bottom: 2px solid var(--color-border); text-align: left; font-size: 0.75rem; text-transform: uppercase; color: var(--color-text-muted);">
            <th style="padding: 0.5rem 1rem;">Ingreso / Declaración</th>
            <th style="padding: 0.5rem 1rem;">ETA / Llegada</th>
            <th style="padding: 0.5rem 1rem;">Estado</th>
            <th style="padding: 0.5rem 1rem; text-align: right;">Cantidad Pendiente</th>
          </tr>
        </thead>
        <tbody>
          ${rowsHtml}
        </tbody>
      </table>
    `;

  } catch (err) {
    console.error('Error fetching pending details:', err);
    const modalBody = document.getElementById('pending-detail-modal-body');
    if (modalBody) {
      modalBody.innerHTML = `<p style="color: var(--color-danger); text-align: center; padding: 2rem;">Error al buscar detalles: ${err.message}</p>`;
    }
  }
}

function setProductSource(source) {
  const btnExcel = document.getElementById('btn-source-excel');
  const btnCatalog = document.getElementById('btn-source-catalog');
  const excelCont = document.getElementById('dec-excel-container');
  const catalogCont = document.getElementById('dec-catalog-container');
  const fileInput = document.getElementById('dec-file-input');
  
  if (source === 'excel') {
    if (btnExcel) {
      btnExcel.style.background = 'var(--color-primary)';
      btnExcel.style.color = 'white';
      btnExcel.classList.add('active');
    }
    if (btnCatalog) {
      btnCatalog.style.background = 'transparent';
      btnCatalog.style.color = 'var(--color-text-muted)';
      btnCatalog.classList.remove('active');
    }
    if (excelCont) excelCont.style.display = 'block';
    if (catalogCont) catalogCont.style.display = 'none';
    if (fileInput) fileInput.setAttribute('required', 'required');
  } else {
    if (btnExcel) {
      btnExcel.style.background = 'transparent';
      btnExcel.style.color = 'var(--color-text-muted)';
      btnExcel.classList.remove('active');
    }
    if (btnCatalog) {
      btnCatalog.style.background = 'var(--color-primary)';
      btnCatalog.style.color = 'white';
      btnCatalog.classList.add('active');
    }
    if (excelCont) excelCont.style.display = 'none';
    if (catalogCont) catalogCont.style.display = 'block';
    if (fileInput) fileInput.removeAttribute('required');
  }
}

async function checkSelectedCommerceTracking() {
  const selectComm = document.getElementById('dec-comercio');
  const commerce = selectComm ? selectComm.value : (currentCompany ? currentCompany.split(',')[0].trim() : 'STOCKA');
  
  const sourceGroup = document.getElementById('dec-product-source-group');
  if (!sourceGroup) return;
  
  try {
    const { data: config } = await supabase
      .from('comercios_adicional_config')
      .select('inventario_seguimiento')
      .eq('comercio', commerce)
      .maybeSingle();
      
    if (config && config.inventario_seguimiento) {
      sourceGroup.style.display = 'block';
      // Pre-cargar productos del catálogo
      await loadCatalogProductsForDeclaration(commerce);
      if (!editingDeclarationId) {
        setProductSource('catalog');
      }
    } else {
      sourceGroup.style.display = 'none';
      setProductSource('excel');
    }
  } catch (e) {
    console.error('Error checking commerce tracking config:', e);
    sourceGroup.style.display = 'none';
    setProductSource('excel');
  }
}

async function loadCatalogProductsForDeclaration(commerce) {
  try {
    const { data: prods, error } = await supabase
      .from('products')
      .select('sku, name, volumen, price')
      .eq('comercio', commerce)
      .order('name');
      
    if (error) throw error;
    
    window.decCatalogProductsCache = prods || [];
    
    const selectProd = document.getElementById('dec-catalog-product-select');
    if (selectProd) {
      if (!prods || prods.length === 0) {
        selectProd.innerHTML = '<option value="">-- No hay productos en catálogo --</option>';
        return;
      }
      let html = '<option value="">-- Selecciona un Producto --</option>';
      prods.forEach(p => {
        html += `<option value="${p.sku}" data-name="${p.name.replace(/"/g, '&quot;')}" data-vol="${p.volumen || 0}">${p.name} (${p.sku})</option>`;
      });
      selectProd.innerHTML = html;
    }
  } catch (e) {
    console.error('Error preloading catalog products:', e);
    const selectProd = document.getElementById('dec-catalog-product-select');
    if (selectProd) selectProd.innerHTML = '<option value="">Error al cargar productos</option>';
  }
}

function addCatalogProductToDeclarationList(sku, name, vol, price = 0) {
  const container = document.getElementById('dec-selected-products-list');
  if (!container) return;

  const emptyMsg = container.querySelector('p');
  if (emptyMsg && emptyMsg.textContent.includes('Ningún producto')) {
    emptyMsg.remove();
  }

  const existingRow = container.querySelector(`.selected-product-row[data-sku="${sku}"]`);
  if (existingRow) {
    const qtyInput = existingRow.querySelector('.dec-catalog-qty-input');
    qtyInput.value = parseInt(qtyInput.value, 10) + 1;
    qtyInput.dispatchEvent(new Event('change'));
    return;
  }

  const row = document.createElement('div');
  row.className = 'selected-product-row';
  row.setAttribute('data-sku', sku);
  row.style.cssText = 'display: flex; justify-content: space-between; align-items: center; padding: 0.5rem; background: var(--color-bg); border: 1px solid var(--color-border); border-radius: 4px; gap: 0.5rem; margin-bottom: 0.5rem;';
  row.innerHTML = `
    <div style="flex: 1; min-width: 0;">
      <div style="font-size: 0.85rem; font-weight: 600; text-overflow: ellipsis; overflow: hidden; white-space: nowrap;">${name}</div>
      <div style="font-size: 0.72rem; color: var(--color-text-muted);">SKU: ${sku} | Vol: ${vol.toFixed(4)} m³</div>
    </div>
    <div style="display: flex; align-items: center; gap: 0.5rem;">
      <input type="number" class="dec-catalog-qty-input" data-sku="${sku}" data-name="${name.replace(/"/g, '&quot;')}" data-vol="${vol}" data-price="${price}" min="1" value="1" style="width: 70px; padding: 0.25rem 0.5rem; border-radius: 4px; border: 1px solid var(--color-border); text-align: center; font-size: 0.8rem; background: var(--color-surface); color: var(--color-text-main);">
      <button type="button" class="btn-remove-selected-prod" style="background: none; border: none; color: var(--color-danger); cursor: pointer; padding: 0.25rem;"><i class="ri-delete-bin-line"></i></button>
    </div>
  `;

  const qtyInput = row.querySelector('.dec-catalog-qty-input');
  qtyInput.addEventListener('change', recalculateCatalogTotals);
  qtyInput.addEventListener('input', recalculateCatalogTotals);

  row.querySelector('.btn-remove-selected-prod').addEventListener('click', () => {
    row.remove();
    if (container.children.length === 0) {
      container.innerHTML = '<p class="text-center" style="color: var(--color-text-muted); font-size: 0.8rem; margin: 1rem 0;">Ningún producto seleccionado</p>';
    }
    recalculateCatalogTotals();
  });

  container.appendChild(row);
  recalculateCatalogTotals();
}

function recalculateCatalogTotals() {
  let totalQty = 0;
  let totalVolume = 0;

  const rows = document.querySelectorAll('#dec-selected-products-list .selected-product-row');
  rows.forEach(row => {
    const qtyInput = row.querySelector('.dec-catalog-qty-input');
    const vol = parseFloat(qtyInput.getAttribute('data-vol') || '0');
    const qty = parseInt(qtyInput.value, 10) || 0;
    
    totalQty += qty;
    totalVolume += (qty * vol);
  });

  const qtyEl = document.getElementById('dec-qty-declared');
  if (qtyEl) {
    qtyEl.value = totalQty > 0 ? totalQty : '';
  }

  const volEl = document.getElementById('dec-volume-declared');
  if (volEl) {
    volEl.value = totalVolume > 0 ? totalVolume.toFixed(3) : '';
  }
}

async function updateClientBadges(userId, userComercio) {
  try {
    const badgeEl = document.getElementById('badge-incidencias');
    if (!badgeEl) return;

    let query = supabase
      .from('incidencias')
      .select('*', { count: 'exact', head: true })
      .eq('status', 'pendiente');

    if (userComercio !== 'all') {
      const commerceList = userComercio.split(',').map(s => s.trim()).filter(Boolean);
      if (commerceList.length > 0) {
        query = query.in('comercio', commerceList);
      } else {
        query = query.eq('comercio', 'no asignado');
      }
    }

    const { count, error } = await query;
    if (error) {
      if (error.code === '42P01' || error.message.includes('does not exist')) {
        badgeEl.style.display = 'none';
        return;
      }
      throw error;
    }

    if (count !== null && count > 0) {
      badgeEl.textContent = count;
      badgeEl.style.display = 'inline-flex';
    } else {
      badgeEl.style.display = 'none';
    }
  } catch (err) {
    console.error('Error al actualizar globo de incidencias del cliente:', err);
  }
}
window.updateClientBadges = updateClientBadges;

