async function renderCampaignsTab(commerce) {
  // Bind "Nueva Campaña" button click listener first so it always works
  const btnNewCampaign = document.getElementById('btn-new-campaign');
  if (btnNewCampaign) {
    const newBtn = btnNewCampaign.cloneNode(true);
    btnNewCampaign.parentNode.replaceChild(newBtn, btnNewCampaign);
    newBtn.addEventListener('click', () => {
      openCampaignModal(commerce);
    });
  }

  const tbody = document.getElementById('catalog-campaigns-tbody');
  if (!tbody) return;

  tbody.innerHTML = `
    <tr>
      <td colspan="6" class="text-center" style="padding: 2rem; color: var(--color-text-muted);">
        <i class="ri-loader-4-line ri-spin" style="font-size: 1.5rem; display: block; margin: 0 auto 0.5rem;"></i>
        Cargando campañas...
      </td>
    </tr>
  `;

  try {
    const { data: campaigns, error } = await supabase
      .from('campaigns')
      .select('*')
      .eq('comercio', commerce)
      .order('created_at', { ascending: false });

    if (error) throw error;

    const isObserver = userRole === 'observer';

    if (!campaigns || campaigns.length === 0) {
      tbody.innerHTML = `
        <tr>
          <td colspan="6" class="text-center" style="padding: 2rem; color: var(--color-text-muted);">
            No tienes ninguna campaña de regalo configurada.
          </td>
        </tr>
      `;
    } else {
      tbody.innerHTML = campaigns.map(c => {
        // Formatear vigencia
        let datesText = 'Indefinida';
        if (c.start_date || c.end_date) {
          const start = c.start_date ? new Date(c.start_date).toLocaleDateString('es-CL') : '...';
          const end = c.end_date ? new Date(c.end_date).toLocaleDateString('es-CL') : '...';
          datesText = `${start} al ${end}`;
        }

        // Formatear condiciones
        const conds = [];
        if (c.trigger_skus && c.trigger_skus.length > 0) {
          conds.push(`Contiene SKUs: <strong>${c.trigger_skus.join(', ')}</strong>`);
        }
        if (c.min_total_quantity && c.min_total_quantity > 0) {
          conds.push(`Cant. total de ítems >= <strong>${c.min_total_quantity}</strong>`);
        }
        if (c.min_distinct_skus && c.min_distinct_skus > 0) {
          conds.push(`SKUs distintos >= <strong>${c.min_distinct_skus}</strong>`);
        }
        const conditionsHtml = conds.length > 0 ? conds.join('<br>') : '<span style="color: var(--color-text-muted); font-style: italic;">Sin condiciones</span>';

        // Botón de activación
        const statusText = c.active ? 'Activa' : 'Inactiva';
        const toggleBtnText = c.active ? 'Desactivar' : 'Activar';
        const toggleBtnColor = c.active ? 'var(--color-text-muted)' : 'var(--color-success)';

        const statusBadgeHtml = `
          <span class="badge" style="background-color: ${c.active ? 'rgba(16, 185, 129, 0.1)' : 'rgba(107, 114, 128, 0.1)'}; color: ${c.active ? '#10b981' : '#6b7280'}; border: 1px solid ${c.active ? 'rgba(16, 185, 129, 0.2)' : 'rgba(107, 114, 128, 0.2)'}; padding: 0.25rem 0.5rem; border-radius: 4px; font-size: 0.75rem; font-weight: 600;">
            ${statusText}
          </span>
        `;

        const deleteBtn = isObserver 
          ? '' 
          : `<button class="btn btn-outline btn-delete-campaign" data-id="${c.id}" style="padding: 0.35rem 0.75rem; font-size: 0.85rem; border-color: var(--color-danger); color: var(--color-danger); margin-left: 0.5rem;"><i class="ri-delete-bin-line"></i></button>`;
        
        const actionBtn = isObserver 
          ? '' 
          : `<button class="btn btn-outline btn-edit-campaign" data-id="${c.id}" style="padding: 0.35rem 0.75rem; font-size: 0.85rem; border-color: var(--color-border); color: var(--color-text);"><i class="ri-edit-line"></i></button>` +
            `<button class="btn btn-outline btn-toggle-campaign" data-id="${c.id}" data-active="${c.active}" style="padding: 0.35rem 0.75rem; font-size: 0.85rem; border-color: ${toggleBtnColor}; color: ${toggleBtnColor}; margin-left: 0.5rem;">${toggleBtnText}</button>` + deleteBtn;

        return `
          <tr data-campaign-id="${c.id}">
            <td style="padding: 0.75rem 2rem;"><strong>${c.name}</strong></td>
            <td style="padding: 0.75rem 2rem;"><strong>${c.gift_sku}</strong> <span style="color: var(--color-primary); font-weight: bold;">(x${c.gift_quantity})</span></td>
            <td style="padding: 0.75rem 2rem; font-size: 0.85rem; line-height: 1.4;">${conditionsHtml}</td>
            <td style="padding: 0.75rem 2rem; font-size: 0.85rem;">${datesText}</td>
            <td style="padding: 0.75rem 2rem;">${statusBadgeHtml}</td>
            <td style="padding: 0.75rem 2rem;">${actionBtn}</td>
          </tr>
        `;
      }).join('');

      // Bind toggle active listener
      tbody.querySelectorAll('.btn-toggle-campaign').forEach(btn => {
        btn.addEventListener('click', async (e) => {
          const id = e.currentTarget.getAttribute('data-id');
          const currentActive = e.currentTarget.getAttribute('data-active') === 'true';
          const newActive = !currentActive;

          try {
            e.currentTarget.disabled = true;
            const { error: updateErr } = await supabase
              .from('campaigns')
              .update({ active: newActive })
              .eq('id', id);

            if (updateErr) throw updateErr;
            renderCampaignsTab(commerce);
          } catch (err) {
            alert('Error al cambiar estado de la campaña: ' + err.message);
            e.currentTarget.disabled = false;
          }
        });
      });

      // Bind delete listener
      tbody.querySelectorAll('.btn-delete-campaign').forEach(btn => {
        btn.addEventListener('click', async (e) => {
          const id = e.currentTarget.getAttribute('data-id');
          if (confirm('¿Estás seguro de que deseas eliminar esta campaña?')) {
            try {
              const { error: delErr } = await supabase
                .from('campaigns')
                .delete()
                .eq('id', id);

              if (delErr) throw delErr;
              renderCampaignsTab(commerce);
            } catch (err) {
              alert('Error al eliminar campaña: ' + err.message);
            }
          }
        });
      });

      // Bind edit listener
      tbody.querySelectorAll('.btn-edit-campaign').forEach(btn => {
        btn.addEventListener('click', async (e) => {
          const id = e.currentTarget.getAttribute('data-id');
          const campaign = campaigns.find(item => item.id === id);
          if (campaign) {
            openCampaignModal(commerce, campaign);
          }
        });
      });
    }

  } catch (err) {
    console.error("Error loading campaigns:", err);
    tbody.innerHTML = `
      <tr>
        <td colspan="6" class="text-center" style="padding: 2rem; color: var(--color-danger);">
          Error al cargar campañas: ${err.message}
        </td>
      </tr>
    `;
  }
}

function openCampaignModal(commerce, campaign = null) {
  const existing = document.getElementById('modal-campaign');
  if (existing) existing.remove();

  const isEdit = !!campaign;
  const modalTitle = isEdit ? 'Editar Campaña' : 'Nueva Campaña de Regalo';

  let startVal = '';
  let endVal = '';
  if (isEdit) {
    if (campaign.start_date) {
      startVal = campaign.start_date.split('T')[0];
    }
    if (campaign.end_date) {
      endVal = campaign.end_date.split('T')[0];
    }
  }

  const triggerSkusVal = isEdit && campaign.trigger_skus ? campaign.trigger_skus.join(', ') : '';
  const giftSkuVal = isEdit ? campaign.gift_sku : '';
  const giftQtyVal = isEdit ? campaign.gift_quantity : 1;
  const minQtyVal = isEdit && campaign.min_total_quantity !== null ? campaign.min_total_quantity : '';
  const minSkusVal = isEdit && campaign.min_distinct_skus !== null ? campaign.min_distinct_skus : '';
  const nameVal = isEdit ? campaign.name : '';
  const activeChecked = isEdit ? (campaign.active ? 'checked' : '') : 'checked';

  const modal = document.createElement('div');
  modal.className = 'modal-overlay active';
  modal.id = 'modal-campaign';
  modal.style.zIndex = '1500';
  modal.innerHTML = `
    <div class="modal-content" style="max-width: 600px; width: 95%; background: var(--color-surface); color: var(--color-text-main); border-radius: var(--radius-lg); box-shadow: var(--shadow-xl); overflow: hidden; display: flex; flex-direction: column;">
      <div class="modal-header" style="padding: 1.25rem 1.5rem; border-bottom: 1px solid var(--color-border); display: flex; justify-content: space-between; align-items: center;">
        <h3 style="margin: 0; font-size: 1.15rem; font-weight: 600; color: var(--color-text-main);">${modalTitle}</h3>
        <button class="modal-close" style="background: transparent; border: none; font-size: 1.5rem; cursor: pointer; color: var(--color-text-muted);" onclick="this.closest('.modal-overlay').remove()">&times;</button>
      </div>
      <form id="form-campaign">
        <div class="modal-body" style="padding: 1.5rem; display: flex; flex-direction: column; gap: 1.25rem; max-height: 70vh; overflow-y: auto;">
          
          <div>
            <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.4rem;">Nombre de la Campaña *</label>
            <input type="text" id="campaign-name" class="form-input" placeholder="Ej. Regalo Taza Día del Padre" value="${nameVal}" required style="width: 100%;">
          </div>

          <div style="display: flex; align-items: center; gap: 0.5rem;">
            <input type="checkbox" id="campaign-active" ${activeChecked} style="width: 16px; height: 16px; cursor: pointer;">
            <label for="campaign-active" style="font-weight: 600; cursor: pointer; user-select: none;">Campaña Activa</label>
          </div>

          <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 1rem;">
            <div>
              <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.4rem;">Fecha Inicio</label>
              <input type="date" id="campaign-start" class="form-input" value="${startVal}" style="width: 100%;">
            </div>
            <div>
              <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.4rem;">Fecha Término</label>
              <input type="date" id="campaign-end" class="form-input" value="${endVal}" style="width: 100%;">
            </div>
          </div>

          <hr style="border: 0; border-top: 1px solid var(--color-border); margin: 0.5rem 0;">
          <h4 style="margin: 0; font-size: 0.95rem; font-weight: 600; color: var(--color-primary);">Condiciones (Se deben cumplir todas)</h4>

          <div>
            <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.2rem;">SKUs Específicos Disparadores</label>
            <p style="margin: 0 0 0.4rem 0; font-size: 0.75rem; color: var(--color-text-muted);">Separados por comas. El pedido debe contener al menos uno de estos SKUs.</p>
            <input type="text" id="campaign-trigger-skus" class="form-input" placeholder="Ej. SKU-A, SKU-B" value="${triggerSkusVal}" style="width: 100%;">
          </div>

          <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 1rem;">
            <div>
              <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.4rem;">Cantidad Mín. de Artículos</label>
              <input type="number" id="campaign-min-total-qty" class="form-input" placeholder="Ej. 3" min="1" value="${minQtyVal}" style="width: 100%;">
            </div>
            <div>
              <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.4rem;">SKUs Distintos Mínimos</label>
              <input type="number" id="campaign-min-distinct-skus" class="form-input" placeholder="Ej. 2" min="1" value="${minSkusVal}" style="width: 100%;">
            </div>
          </div>

          <hr style="border: 0; border-top: 1px solid var(--color-border); margin: 0.5rem 0;">
          <h4 style="margin: 0; font-size: 0.95rem; font-weight: 600; color: var(--color-success);">Premio / Regalo a Añadir</h4>

          <div style="display: grid; grid-template-columns: 2fr 1fr; gap: 1rem;">
            <div>
              <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.4rem;">SKU de Regalo *</label>
              <input type="text" id="campaign-gift-sku" list="master-skus-list" class="form-input" placeholder="Busca o ingresa SKU..." value="${giftSkuVal}" required style="width: 100%;">
            </div>
            <div>
              <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.4rem;">Cantidad *</label>
              <input type="number" id="campaign-gift-qty" class="form-input" min="1" value="${giftQtyVal}" required style="width: 100%;">
            </div>
          </div>

        </div>
        <div class="modal-footer" style="padding: 1rem 1.5rem; border-top: 1px solid var(--color-border); display: flex; justify-content: flex-end; gap: 0.75rem;">
          <button type="button" class="btn btn-outline" onclick="this.closest('.modal-overlay').remove()">Cancelar</button>
          <button type="submit" class="btn btn-primary" id="btn-save-campaign-submit" style="background-color: var(--color-primary); color: var(--color-dark); font-weight: 600;">
            ${isEdit ? 'Guardar Cambios' : 'Crear Campaña'}
          </button>
        </div>
      </form>
    </div>
  `;

  document.body.appendChild(modal);

  const form = document.getElementById('form-campaign');
  form.addEventListener('submit', async (e) => {
    e.preventDefault();

    const name = document.getElementById('campaign-name').value.trim();
    const active = document.getElementById('campaign-active').checked;
    const startVal = document.getElementById('campaign-start').value;
    const endVal = document.getElementById('campaign-end').value;
    const triggerSkusRaw = document.getElementById('campaign-trigger-skus').value.trim();
    const minTotalQtyRaw = document.getElementById('campaign-min-total-qty').value;
    const minDistinctSkusRaw = document.getElementById('campaign-min-distinct-skus').value;
    const giftSku = document.getElementById('campaign-gift-sku').value.trim();
    const giftQty = parseInt(document.getElementById('campaign-gift-qty').value) || 1;

    if (!name || !giftSku) {
      alert('Nombre y SKU de Regalo son requeridos.');
      return;
    }

    const masterProducts = window.currentMasterProducts || [];
    const giftExists = masterProducts.some(p => p.sku.toLowerCase().trim() === giftSku.toLowerCase().trim());
    if (!giftExists) {
      alert(`El SKU de Regalo "${giftSku}" no existe en tu catálogo master. Por favor selecciona uno válido.`);
      return;
    }

    let trigger_skus = null;
    if (triggerSkusRaw) {
      trigger_skus = triggerSkusRaw.split(',').map(s => s.trim()).filter(Boolean);
    }

    const min_total_quantity = minTotalQtyRaw ? parseInt(minTotalQtyRaw) : null;
    const min_distinct_skus = minDistinctSkusRaw ? parseInt(minDistinctSkusRaw) : null;

    const start_date = startVal ? new Date(startVal + 'T00:00:00').toISOString() : null;
    const end_date = endVal ? new Date(endVal + 'T23:59:59').toISOString() : null;

    const payload = {
      comercio: commerce,
      name,
      active,
      start_date,
      end_date,
      trigger_skus,
      min_total_quantity,
      min_distinct_skus,
      gift_sku: giftSku,
      gift_quantity: giftQty
    };

    const submitBtn = document.getElementById('btn-save-campaign-submit');
    submitBtn.disabled = true;
    submitBtn.innerHTML = '<i class="ri-loader-4-line ri-spin"></i> Guardando...';

    try {
      let response;
      if (isEdit) {
        response = await supabase
          .from('campaigns')
          .update(payload)
          .eq('id', campaign.id);
      } else {
        response = await supabase
          .from('campaigns')
          .insert(payload);
      }

      if (response.error) throw response.error;

      alert(isEdit ? 'Campaña actualizada correctamente.' : 'Campaña creada correctamente.');
      modal.remove();
      renderCampaignsTab(commerce);
    } catch (err) {
      alert('Error al guardar campaña: ' + err.message);
      submitBtn.disabled = false;
      submitBtn.innerHTML = isEdit ? 'Guardar Cambios' : 'Crear Campaña';
    }
  });
}

window.showStockAndDimensionsPreviewModal = function({ title, headers, rows, onConfirm }) {
  const oldModal = document.getElementById('modal-import-preview');
  if (oldModal) oldModal.remove();

  const modal = document.createElement('div');
  modal.id = 'modal-import-preview';
  modal.className = 'modal-overlay active';
  modal.style.zIndex = '9999';

  const trs = rows.map(r => {
    const badgeColor = r.status === 'ok' ? 'var(--color-success)' : 'var(--color-danger)';
    const badgeText = r.status === 'ok' ? 'Listo' : 'Error';
    const rowStyle = r.status === 'error' ? 'background-color: rgba(239, 68, 68, 0.05);' : '';
    return `
      <tr style="${rowStyle} border-bottom: 1px solid var(--color-border);">
        <td style="padding: 0.75rem; font-weight: 600;">${r.sku}</td>
        <td style="padding: 0.75rem; max-width: 250px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${r.name || '<span style="color:var(--color-text-muted);">No encontrado</span>'}</td>
        <td style="padding: 0.75rem; text-align: center;">${r.oldValue}</td>
        <td style="padding: 0.75rem; text-align: center; font-weight: 600;">${r.newValue}</td>
        <td style="padding: 0.75rem; text-align: center;">
          <span class="badge" style="background-color: ${badgeColor}20; color: ${badgeColor}; padding: 0.25rem 0.5rem; border-radius: var(--radius-sm); font-size: 0.75rem; font-weight: 600;">
            ${badgeText}
          </span>
        </td>
        <td style="padding: 0.75rem; color: ${r.status === 'ok' ? 'var(--color-text-muted)' : 'var(--color-danger)'}; font-size: 0.8rem;">
          ${r.message || ''}
        </td>
      </tr>
    `;
  }).join('');

  const totalRows = rows.length;
  const okRows = rows.filter(r => r.status === 'ok').length;
  const errorRows = rows.filter(r => r.status === 'error').length;

  const alertBanner = errorRows > 0
    ? `<div style="background-color: rgba(239, 68, 68, 0.1); border: 1px solid var(--color-danger); color: var(--color-danger); padding: 0.75rem 1rem; border-radius: var(--radius-md); margin-bottom: 1rem; font-size: 0.85rem; display: flex; align-items: center; gap: 0.5rem;">
         <i class="ri-error-warning-line" style="font-size: 1.1rem;"></i>
         <span>Se detectaron <strong>${errorRows} filas con errores</strong>. Solo se procesarán las <strong>${okRows} filas válidas</strong>.</span>
       </div>`
    : `<div style="background-color: rgba(16, 124, 65, 0.1); border: 1px solid var(--color-success); color: var(--color-success); padding: 0.75rem 1rem; border-radius: var(--radius-md); margin-bottom: 1rem; font-size: 0.85rem; display: flex; align-items: center; gap: 0.5rem;">
         <i class="ri-checkbox-circle-line" style="font-size: 1.1rem;"></i>
         <span>¡Todo correcto! Las <strong>${okRows} filas</strong> son completamente válidas y están listas para importar.</span>
       </div>`;

  modal.innerHTML = `
    <div class="modal-content" style="max-width: 850px; width: 95%; max-height: 90vh; display: flex; flex-direction: column;">
      <div class="modal-header">
        <h3><i class="ri-table-line" style="color: var(--color-primary); margin-right: 0.5rem;"></i> ${title}</h3>
        <button class="modal-close" onclick="this.closest('.modal-overlay').remove()">&times;</button>
      </div>
      <div class="modal-body" style="padding: 1.25rem; overflow-y: auto; flex: 1;">
        ${alertBanner}
        <div style="max-height: 350px; overflow-y: auto; border: 1px solid var(--color-border); border-radius: var(--radius-md); margin-bottom: 1.25rem;">
          <table style="width: 100%; border-collapse: collapse; text-align: left; font-size: 0.85rem;">
            <thead>
              <tr style="background-color: var(--color-bg); border-bottom: 2px solid var(--color-border); color: var(--color-text-muted); text-transform: uppercase; font-size: 0.75rem; letter-spacing: 0.05em; position: sticky; top: 0; z-index: 1;">
                <th style="padding: 0.75rem;">SKU</th>
                <th style="padding: 0.75rem;">Nombre</th>
                <th style="padding: 0.75rem; text-align: center;">Stock Anterior</th>
                <th style="padding: 0.75rem; text-align: center;">Stock Nuevo</th>
                <th style="padding: 0.75rem; text-align: center;">Estado</th>
                <th style="padding: 0.75rem;">Detalle</th>
              </tr>
            </thead>
            <tbody>
              ${trs}
            </tbody>
          </table>
        </div>
        
        <div style="display: flex; justify-content: space-between; align-items: center; background: var(--color-bg); padding: 0.75rem 1rem; border-radius: var(--radius-md); border: 1px solid var(--color-border);">
          <div style="display: flex; gap: 1.5rem; font-size: 0.85rem; color: var(--color-text-main);">
            <div>Total registros: <strong>${totalRows}</strong></div>
            <div style="color: var(--color-success);">Válidos: <strong>${okRows}</strong></div>
            <div style="color: var(--color-danger);">Errores: <strong>${errorRows}</strong></div>
          </div>
        </div>
      </div>
      <div class="modal-footer" style="border-top: 1px solid var(--color-border); padding: 1rem 1.25rem;">
        <button type="button" class="btn btn-outline" onclick="this.closest('.modal-overlay').remove()">Cancelar</button>
        <button type="button" class="btn btn-primary" id="btn-confirm-import" ${okRows === 0 ? 'disabled' : ''} style="background-color: var(--color-success); border-color: var(--color-success); color: white;">
          <i class="ri-checkbox-circle-line"></i> Confirmar y Cargar
        </button>
      </div>
    </div>
  `;

  document.body.appendChild(modal);

  const confirmBtn = document.getElementById('btn-confirm-import');
  if (confirmBtn) {
    confirmBtn.addEventListener('click', async () => {
      confirmBtn.disabled = true;
      confirmBtn.innerHTML = '<i class="ri-loader-4-line spin"></i> Procesando...';
      try {
        const validRows = rows.filter(r => r.status === 'ok');
        await onConfirm(validRows);
        modal.remove();
      } catch (err) {
        console.error(err);
        alert('Error durante la importación: ' + err.message);
        confirmBtn.disabled = false;
        confirmBtn.innerHTML = '<i class="ri-checkbox-circle-line"></i> Confirmar y Cargar';
      }
    });
  }
};

function openBulkStockAssignModal(commerce, onComplete) {
  let modal = document.getElementById('modal-bulk-stock-assign');
  if (modal) modal.remove();

  modal = document.createElement('div');
  modal.id = 'modal-bulk-stock-assign';
  modal.className = 'modal-overlay active';
  modal.style.zIndex = '9998';
  modal.innerHTML = `
    <div class="modal-content" style="max-width: 500px; padding: 0; display: flex; flex-direction: column; background: var(--color-surface); border: 1px solid var(--color-border); border-radius: var(--radius-lg);">
      <div class="modal-header" style="padding: 1.25rem; border-bottom: 1px solid var(--color-border); background: var(--color-surface); border-radius: var(--radius-lg) var(--radius-lg) 0 0; display: flex; justify-content: space-between; align-items: center;">
        <h3 style="margin: 0; display: flex; align-items: center; gap: 0.5rem; color: var(--color-text-main);"><i class="ri-upload-2-line" style="color: var(--color-primary);"></i> Carga Masiva de Stock</h3>
        <button type="button" class="modal-close" onclick="document.getElementById('modal-bulk-stock-assign').remove()">&times;</button>
      </div>
      <div class="modal-body" style="padding: 1.5rem; overflow-y: auto; flex: 1; display: flex; flex-direction: column; gap: 1.25rem;">
        <div class="form-group" style="margin-bottom: 0;">
          <label class="form-label" style="font-weight: 600; margin-bottom: 0.5rem; display: block; color: var(--color-text-main);">1. Seleccionar Bodega Destino</label>
          <select id="bulk-stock-warehouse-select" class="form-input" style="width: 100%; height: 38px; border: 1px solid var(--color-border); background: var(--color-bg); color: var(--color-text-main); border-radius: var(--radius-md); padding: 0.35rem 0.5rem;">
            <option value="">-- Cargando bodegas --</option>
          </select>
        </div>
        <div class="form-group" style="margin-bottom: 0;">
          <label class="form-label" style="font-weight: 600; margin-bottom: 0.5rem; display: block; color: var(--color-text-main);">2. Descargar Plantilla</label>
          <button type="button" id="btn-download-bulk-stock-template" class="btn btn-outline" style="width: 100%; display: flex; align-items: center; justify-content: center; gap: 0.5rem; font-size: 0.85rem; height: 38px; border-color: var(--color-border);">
            <i class="ri-file-excel-2-line" style="color: var(--color-success);"></i> Descargar Plantilla Excel
          </button>
        </div>
        <div class="form-group" style="margin-bottom: 0;">
          <label class="form-label" style="font-weight: 600; margin-bottom: 0.5rem; display: block; color: var(--color-text-main);">3. Subir Planilla Excel</label>
          <div style="border: 2px dashed var(--color-border); padding: 1.5rem; border-radius: var(--radius-md); text-align: center; cursor: pointer; transition: all 0.2s; background: var(--color-bg);" id="drop-zone-bulk-stock">
            <i class="ri-upload-cloud-2-line" style="font-size: 2.5rem; color: var(--color-primary); display: block; margin-bottom: 0.5rem;"></i>
            <span style="font-size: 0.85rem; color: var(--color-text-muted);" id="bulk-stock-file-label">Selecciona o arrastra el archivo Excel aquí</span>
            <input type="file" id="bulk-stock-excel-file" accept=".xlsx, .xls, .csv" style="display: none;">
          </div>
        </div>
      </div>
      <div class="modal-footer" style="padding: 1.25rem; border-top: 1px solid var(--color-border); background: var(--color-surface); border-radius: 0 0 var(--radius-lg) var(--radius-lg); display: flex; justify-content: flex-end; gap: 0.75rem;">
        <button type="button" class="btn btn-outline" onclick="document.getElementById('modal-bulk-stock-assign').remove()">Cerrar</button>
      </div>
    </div>
  `;

  document.body.appendChild(modal);

  // Cargar bodegas
  supabase
    .from('warehouses')
    .select('id, name, address, comuna')
    .order('name')
    .then(({ data: warehouses, error }) => {
      const selectEl = document.getElementById('bulk-stock-warehouse-select');
      if (selectEl) {
        selectEl.innerHTML = '<option value="">-- Selecciona una Bodega --</option>';
        if (warehouses) {
          warehouses.forEach(w => {
            selectEl.innerHTML += `<option value="${w.id}">${w.name} (${w.comuna})</option>`;
          });
        }
      }
    });

  // Template download listener
  document.getElementById('btn-download-bulk-stock-template').addEventListener('click', () => {
    const headers = [['SKU', 'Stock']];
    const sampleData = [
      ['PROD-001', '10'],
      ['PROD-002', '5'],
      ['PROD-003', '0']
    ];
    const wsData = headers.concat(sampleData);
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet(wsData);
    XLSX.utils.book_append_sheet(wb, ws, 'Stock Asignado');
    XLSX.writeFile(wb, 'plantilla_carga_masiva_stock.xlsx');
  });

  const dropZone = document.getElementById('drop-zone-bulk-stock');
  const fileInput = document.getElementById('bulk-stock-excel-file');

  dropZone.addEventListener('click', () => fileInput.click());
  
  dropZone.addEventListener('dragover', (e) => {
    e.preventDefault();
    dropZone.style.borderColor = 'var(--color-primary)';
  });

  dropZone.addEventListener('dragleave', () => {
    dropZone.style.borderColor = 'var(--color-border)';
  });

  dropZone.addEventListener('drop', (e) => {
    e.preventDefault();
    dropZone.style.borderColor = 'var(--color-border)';
    const files = e.dataTransfer.files;
    if (files.length > 0) {
      fileInput.files = files;
      handleFileSelected(files[0]);
    }
  });

  fileInput.addEventListener('change', (e) => {
    const file = e.target.files[0];
    if (file) {
      handleFileSelected(file);
    }
  });

  async function handleFileSelected(file) {
    const warehouseSelect = document.getElementById('bulk-stock-warehouse-select');
    const selectedWarehouseId = warehouseSelect.value;
    if (!selectedWarehouseId) {
      alert('Por favor, selecciona una bodega destino primero.');
      fileInput.value = '';
      return;
    }
    const selectedWarehouseName = warehouseSelect.options[warehouseSelect.selectedIndex].text;

    document.getElementById('bulk-stock-file-label').textContent = file.name;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const data = new Uint8Array(evt.target.result);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const excelRows = XLSX.utils.sheet_to_json(worksheet);

        if (excelRows.length === 0) {
          alert('El archivo Excel está vacío.');
          return;
        }

        // Identificar columnas
        const sample = excelRows[0];
        let colSku = '';
        let colStock = '';
        for (const key of Object.keys(sample)) {
          const lower = key.toLowerCase().trim();
          if (lower === 'sku' || lower === 'codigo' || lower === 'código') colSku = key;
          else if (lower === 'stock' || lower === 'cantidad' || lower === 'cant' || lower === 'unidades') colStock = key;
        }

        if (!colSku || !colStock) {
          alert('Error: Columnas no encontradas. El archivo debe contener las columnas "SKU" y "Stock" (o "Cantidad").');
          return;
        }

        // Fetch products of commerce
        const { data: dbProducts } = await supabase
          .from('products')
          .select('id, sku, name')
          .eq('comercio', commerce);

        const productMap = {};
        if (dbProducts) {
          dbProducts.forEach(p => {
            if (p.sku) {
              productMap[p.sku.toLowerCase().trim()] = p;
            }
          });
        }

        // Fetch inventory levels for selected warehouse
        const { data: dbInventory } = await supabase
          .from('inventory')
          .select('product_id, quantity')
          .eq('warehouse_id', selectedWarehouseId);

        const inventoryMap = {};
        if (dbInventory) {
          dbInventory.forEach(inv => {
            inventoryMap[inv.product_id] = inv.quantity || 0;
          });
        }

        // Build preview rows
        const previewRows = [];
        for (const row of excelRows) {
          const skuVal = String(row[colSku] || '').trim();
          const stockValRaw = row[colStock];
          const stockVal = parseInt(stockValRaw, 10);

          const prod = productMap[skuVal.toLowerCase()];
          const oldStock = prod ? (inventoryMap[prod.id] || 0) : 0;

          let status = 'ok';
          let message = '';

          if (!skuVal) {
            status = 'error';
            message = 'Línea vacía o SKU ausente';
          } else if (!prod) {
            status = 'error';
            message = 'El SKU no existe en este comercio';
          } else if (isNaN(stockVal) || stockVal < 0) {
            status = 'error';
            message = 'Stock inválido (debe ser un número entero >= 0)';
          }

          previewRows.push({
            sku: skuVal || 'N/A',
            name: prod ? prod.name : null,
            oldValue: oldStock,
            newValue: isNaN(stockVal) ? (stockValRaw || '') : stockVal,
            status,
            message,
            prodId: prod ? prod.id : null,
            stockVal
          });
        }

        // Close bulk upload modal first
        document.getElementById('modal-bulk-stock-assign').remove();

        // Launch generic preview modal
        window.showStockAndDimensionsPreviewModal({
          title: `Carga Masiva de Stock - Bodega: ${selectedWarehouseName}`,
          headers: ['SKU', 'Nombre', 'Stock Anterior', 'Stock Nuevo', 'Estado', 'Detalle'],
          rows: previewRows,
          onConfirm: async (validRows) => {
            let updatedCount = 0;
            const updatePromises = validRows.map(async (r) => {
              const diff = r.stockVal - r.oldValue;
              if (diff !== 0) {
                // Find or insert in inventory
                const { data: invRecord } = await supabase
                  .from('inventory')
                  .select('id, quantity')
                  .eq('product_id', r.prodId)
                  .eq('warehouse_id', selectedWarehouseId)
                  .maybeSingle();

                if (invRecord) {
                  const { error: invErr } = await supabase
                    .from('inventory')
                    .update({ quantity: r.stockVal })
                    .eq('id', invRecord.id);
                  if (invErr) throw invErr;
                } else {
                  const { error: invErr } = await supabase
                    .from('inventory')
                    .insert([{
                      product_id: r.prodId,
                      warehouse_id: selectedWarehouseId,
                      quantity: r.stockVal,
                      committed_quantity: 0
                    }]);
                  if (invErr) throw invErr;
                }

                // Register movement
                const type = diff > 0 ? 'in' : 'out';
                const qty = Math.abs(diff);
                await supabase
                  .from('movements')
                  .insert([{
                    product_id: r.prodId,
                    warehouse_id: selectedWarehouseId,
                    type: type,
                    quantity: qty,
                    reference_doc: 'Carga Masiva Stock'
                  }]);
              }
              updatedCount++;
            });

            await Promise.all(updatePromises);
            alert(`¡Éxito! Se actualizaron ${updatedCount} productos correctamente.`);
            if (onComplete) onComplete();
          }
        });
      } catch (err) {
        console.error(err);
        alert('Error al leer el archivo Excel: ' + err.message);
      }
    };
    reader.readAsArrayBuffer(file);
  }
}

function openDirectBulkWarehouseAssignModal(commerce, selectedProducts, onComplete) {
  let modal = document.getElementById('modal-direct-warehouse-assign');
  if (modal) modal.remove();

  modal = document.createElement('div');
  modal.id = 'modal-direct-warehouse-assign';
  modal.className = 'modal-overlay active';
  modal.style.zIndex = '9998';
  
  const trs = selectedProducts.map(p => `
    <tr style="border-bottom: 1px solid var(--color-border);" data-prod-id="${p.id}">
      <td style="padding: 0.75rem; font-weight: 600;">${p.sku}</td>
      <td style="padding: 0.75rem; max-width: 250px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${p.name}</td>
      <td style="padding: 0.75rem; text-align: center;" class="direct-current-stock-label" data-prod-id="${p.id}">0</td>
      <td style="padding: 0.75rem; text-align: center;">
        <input type="number" class="direct-stock-input form-input" data-prod-id="${p.id}" min="0" value="0" style="width: 100px; text-align: center; height: 32px; padding: 0.25rem; font-weight: 600; border: 1px solid var(--color-border); border-radius: var(--radius-sm); background: var(--color-bg); color: var(--color-text-main);">
      </td>
    </tr>
  `).join('');

  modal.innerHTML = `
    <div class="modal-content" style="max-width: 650px; padding: 0; display: flex; flex-direction: column; background: var(--color-surface); border: 1px solid var(--color-border); border-radius: var(--radius-lg);">
      <div class="modal-header" style="padding: 1.25rem; border-bottom: 1px solid var(--color-border); background: var(--color-surface); border-radius: var(--radius-lg) var(--radius-lg) 0 0; display: flex; justify-content: space-between; align-items: center;">
        <h3 style="margin: 0; display: flex; align-items: center; gap: 0.5rem; color: var(--color-text-main);"><i class="ri-git-repository-line" style="color: var(--color-accent);"></i> Asignar Bodega y Stock</h3>
        <button type="button" class="modal-close" onclick="document.getElementById('modal-direct-warehouse-assign').remove()">&times;</button>
      </div>
      <div class="modal-body" style="padding: 1.5rem; overflow-y: auto; flex: 1; display: flex; flex-direction: column; gap: 1.25rem;">
        <div class="form-group" style="margin-bottom: 0;">
          <label class="form-label" style="font-weight: 600; margin-bottom: 0.5rem; display: block; color: var(--color-text-main);">1. Seleccionar Bodega Destino</label>
          <select id="direct-warehouse-select" class="form-input" style="width: 100%; height: 38px; border: 1px solid var(--color-border); background: var(--color-bg); color: var(--color-text-main); border-radius: var(--radius-md); padding: 0.35rem 0.5rem;">
            <option value="">-- Selecciona una Bodega --</option>
          </select>
        </div>
        <div class="form-group" style="margin-bottom: 0;">
          <label class="form-label" style="font-weight: 600; margin-bottom: 0.5rem; display: block; color: var(--color-text-main);">2. Definir Stock para los Productos Seleccionados</label>
          <div style="max-height: 250px; overflow-y: auto; border: 1px solid var(--color-border); border-radius: var(--radius-md);">
            <table style="width: 100%; border-collapse: collapse; text-align: left; font-size: 0.85rem;">
              <thead>
                <tr style="background-color: var(--color-bg); border-bottom: 2px solid var(--color-border); color: var(--color-text-muted); text-transform: uppercase; font-size: 0.75rem; letter-spacing: 0.05em; position: sticky; top: 0; z-index: 1;">
                  <th style="padding: 0.75rem;">SKU</th>
                  <th style="padding: 0.75rem;">Nombre</th>
                  <th style="padding: 0.75rem; text-align: center;">Stock Actual</th>
                  <th style="padding: 0.75rem; text-align: center;">Nuevo Stock</th>
                </tr>
              </thead>
              <tbody>
                ${trs}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      <div class="modal-footer" style="padding: 1.25rem; border-top: 1px solid var(--color-border); background: var(--color-surface); border-radius: 0 0 var(--radius-lg) var(--radius-lg); display: flex; justify-content: flex-end; gap: 0.75rem;">
        <button type="button" class="btn btn-outline" onclick="document.getElementById('modal-direct-warehouse-assign').remove()">Cancelar</button>
        <button type="button" class="btn btn-primary" id="btn-confirm-direct-assign" style="background-color: var(--color-accent); border-color: var(--color-accent); color: white;">
          <i class="ri-checkbox-circle-line"></i> Confirmar y Guardar
        </button>
      </div>
    </div>
  `;

  document.body.appendChild(modal);

  // Load warehouses
  supabase
    .from('warehouses')
    .select('id, name, address, comuna')
    .order('name')
    .then(({ data: warehouses, error }) => {
      const selectEl = document.getElementById('direct-warehouse-select');
      if (selectEl) {
        selectEl.innerHTML = '<option value="">-- Selecciona una Bodega --</option>';
        if (warehouses) {
          warehouses.forEach(w => {
            selectEl.innerHTML += `<option value="${w.id}">${w.name} (${w.comuna})</option>`;
          });
        }
      }
    });

  const selectEl = document.getElementById('direct-warehouse-select');
  selectEl.addEventListener('change', async () => {
    const warehouseId = selectEl.value;
    if (!warehouseId) {
      document.querySelectorAll('.direct-current-stock-label').forEach(lbl => lbl.textContent = '0');
      document.querySelectorAll('.direct-stock-input').forEach(inp => inp.value = '0');
      return;
    }

    // Fetch current stocks for selected products in this warehouse
    const productIds = selectedProducts.map(p => p.id);
    const { data: dbInvs } = await supabase
      .from('inventory')
      .select('product_id, quantity')
      .eq('warehouse_id', warehouseId)
      .in('product_id', productIds);

    const stockMap = {};
    if (dbInvs) {
      dbInvs.forEach(inv => {
        stockMap[inv.product_id] = inv.quantity || 0;
      });
    }

    selectedProducts.forEach(p => {
      const currentStock = stockMap[p.id] || 0;
      const label = document.querySelector(`.direct-current-stock-label[data-prod-id="${p.id}"]`);
      if (label) label.textContent = currentStock;

      const input = document.querySelector(`.direct-stock-input[data-prod-id="${p.id}"]`);
      if (input) input.value = currentStock;
    });
  });

  const confirmBtn = document.getElementById('btn-confirm-direct-assign');
  confirmBtn.addEventListener('click', async () => {
    const warehouseId = selectEl.value;
    if (!warehouseId) {
      alert('Por favor, selecciona una bodega destino.');
      return;
    }

    confirmBtn.disabled = true;
    confirmBtn.innerHTML = '<i class="ri-loader-4-line ri-spin"></i> Guardando...';

    try {
      let updatedCount = 0;
      for (const p of selectedProducts) {
        const label = document.querySelector(`.direct-current-stock-label[data-prod-id="${p.id}"]`);
        const oldValue = parseInt(label.textContent || '0', 10);
        
        const input = document.querySelector(`.direct-stock-input[data-prod-id="${p.id}"]`);
        const newValue = parseInt(input.value || '0', 10);

        const diff = newValue - oldValue;
        if (diff !== 0) {
          // Update/Insert inventory
          const { data: invRecord } = await supabase
            .from('inventory')
            .select('id, quantity')
            .eq('product_id', p.id)
            .eq('warehouse_id', warehouseId)
            .maybeSingle();

          if (invRecord) {
            const { error: invErr } = await supabase
              .from('inventory')
              .update({ quantity: newValue })
              .eq('id', invRecord.id);
            if (invErr) throw invErr;
          } else {
            const { error: invErr } = await supabase
              .from('inventory')
              .insert([{
                product_id: p.id,
                warehouse_id: warehouseId,
                quantity: newValue,
                committed_quantity: 0
              }]);
            if (invErr) throw invErr;
          }

          // Register movement
          const type = diff > 0 ? 'in' : 'out';
          const qty = Math.abs(diff);
          await supabase
            .from('movements')
            .insert([{
              product_id: p.id,
              warehouse_id: warehouseId,
              type: type,
              quantity: qty,
              reference_doc: 'Ajuste Manual Bodega'
            }]);
          
          updatedCount++;
        }
      }

      alert(`¡Éxito! Se actualizó el stock de ${updatedCount} productos en la bodega.`);
      modal.remove();
      if (onComplete) onComplete();
    } catch (err) {
      console.error(err);
      alert('Error al asignar bodega: ' + err.message);
      confirmBtn.disabled = false;
      confirmBtn.innerHTML = '<i class="ri-checkbox-circle-line"></i> Confirmar y Guardar';
    }
  });
}
